# v200: Moro 3–4 part 2 pages 14–23 local handlers.
# Synthetic thematic variants only; no verbatim textbook task bank is embedded.
def _v200_relaxed_text(raw_text: str) -> str:
    lower = _normalize(raw_text).lower().replace('ё', 'е').replace('—', '-').replace('−', '-')
    lower = lower.replace('м²', 'м2')
    lower = re.sub(r'\s*([.,!?;:])\s*', ' ', lower)
    return re.sub(r'\s+', ' ', lower).strip()


def _build_v200_container_sum_division(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'разложили' not in lower or 'сколько всего' not in lower or 'потребовалось' not in lower:
        return None
    m = re.search(r'по\s+(\d+)\s*кг\b.*?разложили\s+(\d+)\s*кг\b.*?и\s+(\d+)\s*кг\b.*?сколько\s+всего', lower)
    if not m:
        return None
    cap, first, second = map(int, m.groups())
    total = first + second
    if cap == 0 or total % cap:
        return None
    answer = total // cap
    return _make_payload(raw_text, [
        'Решение.',
        f'1) Всего разложили: {first} + {second} = {total} кг.',
        f'2) Количество ёмкостей: {total} : {cap} = {answer}.',
        f'Ответ: {answer}.',
    ])


def _build_v200_number_machine(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'вычислительная машина' not in lower or 'если число делится' not in lower:
        return None
    m = re.search(
        r'если\s+число\s+делится\s+на\s+(\d+)\b.*?делит\s+его\s+на\s+(\d+)\b.*?прибавляет\s+(\d+)\b.*?если\s+не\s+делится\b.*?умножает\s+на\s+(\d+)\b.*?вычитает\s+(\d+)\b.*?для\s+числа\s+(\d+)\b',
        lower,
    )
    if not m:
        return None
    div_cond, div_action, addend, multiplier, subtrahend, value = map(int, m.groups())
    if div_cond == 0 or div_action == 0 or div_cond != div_action:
        return None
    if value % div_cond == 0:
        answer = value // div_action + addend
        step = f'{value} делится на {div_cond}, поэтому {value} : {div_action} + {addend} = {answer}.'
    else:
        answer = value * multiplier - subtrahend
        step = f'{value} не делится на {div_cond}, поэтому {value} × {multiplier} − {subtrahend} = {answer}.'
    return _make_payload(raw_text, ['Решение.', step, f'Ответ: {answer}.'])


def _build_v200_greenhouse_yield(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'теплиц' not in lower or 'квадратного метра' not in lower or 'площади' not in lower:
        return None
    m = re.search(r'по\s+(\d+)\s*кг\b.*?площади\s+(\d+)\s*м2\b.*?по\s+(\d+)\s*кг\b.*?площади\s+(\d+)\s*м2\b', lower)
    if not m:
        return None
    p1, a1, p2, a2 = map(int, m.groups())
    first = p1 * a1
    second = p2 * a2
    answer = first + second
    return _make_payload(raw_text, [
        'Решение.',
        f'1) В первой теплице: {p1} × {a1} = {first} кг.',
        f'2) Во второй теплице: {p2} × {a2} = {second} кг.',
        f'3) Всего: {first} + {second} = {answer} кг.',
        f'Ответ: {answer} кг.',
    ])


def _v200_verbal_value(phrase: str) -> Optional[int]:
    p = _v200_relaxed_text(phrase)
    m = re.fullmatch(r'(?:число\s+)?(\d+)', p)
    if m:
        return int(m.group(1))
    m = re.search(r'сумм\w*\s+чисел\s+(\d+)\s+и\s+(\d+)', p)
    if m:
        a, b = map(int, m.groups())
        return a + b
    m = re.search(r'разност\w*\s+чисел\s+(\d+)\s+и\s+(\d+)', p)
    if m:
        a, b = map(int, m.groups())
        return a - b
    m = re.search(r'произведени\w*\s+чисел\s+(\d+)\s+и\s+(\d+)', p)
    if m:
        a, b = map(int, m.groups())
        return a * b
    m = re.search(r'частн\w*\s+от\s+деления\s+чисел\s+(\d+)\s+и\s+(\d+)', p)
    if m:
        a, b = map(int, m.groups())
        if b == 0 or a % b:
            return None
        return a // b
    return None


def _build_v200_verbal_comparison(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if not lower.startswith('сравни'):
        return None
    m = re.search(r'сравни\s+(.*?)\s+с\s+(.+?)\.?$', lower)
    if not m:
        return None
    left_phrase, right_phrase = m.groups()
    left = _v200_verbal_value(left_phrase)
    right = _v200_verbal_value(right_phrase)
    if left is None or right is None:
        return None
    sign = '>' if left > right else '<' if left < right else '='
    return _make_payload(raw_text, [
        'Решение.',
        f'1) Левая часть равна {left}.',
        f'2) Правая часть равна {right}.',
        f'3) Сравниваем: {left} {sign} {right}.',
        f'Ответ: {sign}.',
    ])


def _build_v200_books_exhibition(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'книжной выставке' not in lower or 'для учителей' not in lower:
        return None
    m = re.search(r'представлено\s+(\d+)\s+книг\b.*?младших\s+школьников\s+(\d+)\b.*?в\s+(\d+)\s+раз\w*\s+меньше\b.*?старших\s+школьников\b.*?студентов\s+столько\s+сколько\s+для\s+младших\s+и\s+старших', lower)
    if not m:
        return None
    total, junior, factor = map(int, m.groups())
    senior = junior * factor
    students = junior + senior
    teachers = total - junior - senior - students
    if teachers < 0:
        return None
    return _make_payload(raw_text, [
        'Решение.',
        f'1) Для старших школьников: {junior} × {factor} = {senior} книг.',
        f'2) Для студентов: {junior} + {senior} = {students} книг.',
        f'3) Для учителей: {total} − {junior} − {senior} − {students} = {teachers} книг.',
        f'Ответ: {teachers} книг.',
    ])


def _build_v200_rectangle_scaled_length(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'площадь прямоугольника' not in lower or 'длину увеличить' not in lower:
        return None
    m = re.search(r'длина\s+прямоугольника\s+(\d+)\s*м\b.*?ширина\s+(\d+)\s*м\b.*?длину\s+увеличить\s+в\s+(\d+)\s+раз', lower)
    if not m:
        return None
    length, width, factor = map(int, m.groups())
    new_length = length * factor
    answer = new_length * width
    return _make_payload(raw_text, [
        'Решение.',
        f'1) Новая длина: {length} × {factor} = {new_length} м.',
        f'2) Новая площадь: {new_length} × {width} = {answer} м².',
        f'Ответ: {answer} м².',
    ])


_PRE_V200_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION = build_open_source_curriculum_explanation


def build_open_source_curriculum_explanation(raw_text: str) -> Optional[str]:
    return (
        _build_v200_container_sum_division(raw_text)
        or _build_v200_number_machine(raw_text)
        or _build_v200_greenhouse_yield(raw_text)
        or _build_v200_verbal_comparison(raw_text)
        or _build_v200_books_exhibition(raw_text)
        or _build_v200_rectangle_scaled_length(raw_text)
        or _PRE_V200_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION(raw_text)
    )


# --- v201 Moro 3–4 part 2 pages 24–33 local handlers ---

def _build_v201_remainder_division(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'остат' not in lower:
        return None
    numbers = [int(x) for x in re.findall(r'\d+', lower)]
    if len(numbers) < 2:
        return None
    dividend, divisor = numbers[-2], numbers[-1]
    if divisor == 0:
        return None
    q, r = divmod(dividend, divisor)
    return _make_payload(raw_text, [
        'Решение.',
        f'1) Делим {dividend} на {divisor}: неполное частное {q}.',
        f'2) Проверяем остаток: {dividend} − {divisor} × {q} = {r}.',
        f'3) Остаток {r} меньше делителя {divisor}.',
        f'Ответ: {q} (ост. {r}).',
    ])


def _build_v201_packing_remainder(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'упаковать' not in lower or 'короб' not in lower or 'остан' not in lower:
        return None
    m = re.search(r'упаковать\s+(\d+)\s+кубик\w*.*?по\s+(\d+)\s+штук', lower)
    if not m:
        return None
    total, per_box = map(int, m.groups())
    if per_box <= 0:
        return None
    boxes, leftover = divmod(total, per_box)
    return _make_payload(raw_text, [
        'Решение.',
        f'1) Делим кубики на полные коробки: {total} : {per_box} = {boxes} (ост. {leftover}).',
        f'Ответ: {boxes} коробок, {leftover} кубиков останется.',
    ])


def _build_v201_notebooks_from_sheets(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'тетрад' not in lower or 'лист' not in lower:
        return None
    m = re.search(r'в\s+(\d+)\s+одинаков\w*\s+тетрад\w*\s+(\d+)\s+лист\w*.*?из\s+(\d+)\s+лист', lower)
    if not m:
        return None
    notebooks, total_sheets, target_sheets = map(int, m.groups())
    if notebooks <= 0 or total_sheets % notebooks:
        return None
    per_notebook = total_sheets // notebooks
    if per_notebook <= 0:
        return None
    answer = target_sheets // per_notebook
    return _make_payload(raw_text, [
        'Решение.',
        f'1) В одной тетради: {total_sheets} : {notebooks} = {per_notebook} листов.',
        f'2) Из {target_sheets} листов получится: {target_sheets} : {per_notebook} = {answer} тетрадей.',
        f'Ответ: {answer} тетрадей.',
    ])


def _build_v201_fraction_part_area(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'прямоугольник' not in lower or 'равных частей' not in lower or 'площадь одной' not in lower:
        return None
    m = re.search(r'разрезали\s+на\s+(\d+)\s+равных\s+част\w*.*?площадь\s+одной\s+част\w*\s+равна\s+(\d+)\s*см', lower)
    if not m:
        return None
    parts, part_area = map(int, m.groups())
    total_area = parts * part_area
    return _make_payload(raw_text, [
        'Решение.',
        f'1) Всего {parts} равных частей, каждая по {part_area} см².',
        f'2) Площадь всего прямоугольника: {part_area} × {parts} = {total_area} см².',
        f'Ответ: {total_area} см².',
    ])


def _build_v201_birdhouse_boards(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'скворечник' not in lower or 'дощеч' not in lower:
        return None
    m = re.search(r'для\s+изготовления\s+(\d+)\s+одинаков\w*\s+скворечник\w*.*?(\d+)\s+прямоугольн\w*\s+и\s+(\d+)\s+квадратн\w*\s+дощеч', lower)
    if not m:
        return None
    houses, rect, square = map(int, m.groups())
    if houses <= 0:
        return None
    total = rect + square
    answer = total // houses
    return _make_payload(raw_text, [
        'Решение.',
        f'1) Всего дощечек: {rect} + {square} = {total}.',
        f'2) На один скворечник: {total} : {houses} = {answer}.',
        f'Ответ: {answer} дощечек.',
    ])


def _build_v201_ratio_difference_words(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'во сколько раз' not in lower or 'на сколько' not in lower or 'слов' not in lower:
        return None
    m = re.search(r'маша\s+составила\s+(\d+)\s+слов.*?слава\s+(\d+)\s+других\s+слов', lower)
    if not m:
        return None
    masha, slava = map(int, m.groups())
    if masha <= 0:
        return None
    ratio = slava // masha
    diff = slava - masha
    return _make_payload(raw_text, [
        'Решение.',
        f'1) Во сколько раз больше: {slava} : {masha} = {ratio}.',
        f'2) На сколько больше: {slava} − {masha} = {diff}.',
        f'Ответ: в {ratio} раза, на {diff} слов.',
    ])


def _build_v201_variable_product(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'значение выражения' not in lower or ('a' not in lower and 'а' not in lower) or 'd' not in lower:
        return None
    m = re.search(r'(?:a|а)\s*[=*]\s*(\d+).*?d\s*[=*]\s*(\d+)', lower)
    if not m:
        return None
    a, d = map(int, m.groups())
    answer = a * d
    return _make_payload(raw_text, [
        'Решение.',
        f'1) Подставляем значения: a · d = {a} · {d}.',
        f'2) {a} · {d} = {answer}.',
        f'Ответ: {answer}.',
    ])


def _build_v201_hidden_number(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'задумал' not in lower or 'увелич' not in lower or 'уменьш' not in lower:
        return None
    m = re.search(r'увелич\w*\s+его\s+в\s+(\d+)\s+раз.*?уменьш\w*\s+на\s+(\d+).*?получил\w*\s+(\d+)', lower)
    if not m:
        return None
    factor, sub, result = map(int, m.groups())
    if factor <= 0 or (result + sub) % factor:
        return None
    answer = (result + sub) // factor
    return _make_payload(raw_text, [
        'Решение.',
        f'1) После увеличения получилось: {result} + {sub} = {result + sub}.',
        f'2) Задуманное число: {result + sub} : {factor} = {answer}.',
        f'Ответ: {answer}.',
    ])


def _build_v201_three_baskets(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if '3 корзин' not in lower or 'первой и второй' not in lower or 'второй и третьей' not in lower:
        return None
    m = re.search(r'всего\s+в\s+них\s+(\d+)\s+кг.*?первой\s+и\s+второй\s+корзинах\s+вместе\s+(\d+)\s+кг.*?второй\s+и\s+третьей\s+вместе\s+(\d+)\s+кг', lower)
    if not m:
        return None
    total, sum12, sum23 = map(int, m.groups())
    first = total - sum23
    third = total - sum12
    second = sum12 - first
    if min(first, second, third) < 0:
        return None
    return _make_payload(raw_text, [
        'Решение.',
        f'1) В первой корзине: {total} − {sum23} = {first} кг.',
        f'2) В третьей корзине: {total} − {sum12} = {third} кг.',
        f'3) Во второй корзине: {sum12} − {first} = {second} кг.',
        f'Ответ: первая — {first} кг, вторая — {second} кг, третья — {third} кг.',
    ])


def _build_v201_unit_price_compare(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'табурет' not in lower or 'стул' not in lower:
        return None
    m = re.search(r'за\s+(\d+)\s+табурет\w*\s+заплатили\s+(\d+)\s*р.*?за\s+(\d+)\s+стул\w*\s+[—-]?\s*(\d+)\s*р', lower)
    if not m:
        return None
    stools_n, stools_sum, chairs_n, chairs_sum = map(int, m.groups())
    if stools_n <= 0 or chairs_n <= 0:
        return None
    stool_price = stools_sum // stools_n
    chair_price = chairs_sum // chairs_n
    if 'во сколько раз' in lower:
        if stool_price == 0 or chair_price % stool_price:
            return None
        answer = chair_price // stool_price
        return _make_payload(raw_text, [
            'Решение.',
            f'1) Цена табуретки: {stools_sum} : {stools_n} = {stool_price} р.',
            f'2) Цена стула: {chairs_sum} : {chairs_n} = {chair_price} р.',
            f'3) Во сколько раз дороже: {chair_price} : {stool_price} = {answer}.',
            f'Ответ: в {answer} раза.',
        ])
    if 'на сколько' in lower:
        answer = chair_price - stool_price
        return _make_payload(raw_text, [
            'Решение.',
            f'1) Цена табуретки: {stools_sum} : {stools_n} = {stool_price} р.',
            f'2) Цена стула: {chairs_sum} : {chairs_n} = {chair_price} р.',
            f'3) Разница: {chair_price} − {stool_price} = {answer} р.',
            f'Ответ: {answer} р.',
        ])
    return None


