# --- v204 Moro 3–4 part 2 pages 54–63 local handlers ---

def _v204_eval_int_expr(expr: str) -> Optional[int]:
    return _v202_eval_arith(str(expr or '').replace('∙', '*').replace('·', '*').replace('×', '*'))


def _build_v204_mass_weights(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'подбери гири' not in lower:
        return None
    m = re.search(r'получить\s+(\d+)\s*г', lower)
    if not m:
        return None
    mass = int(m.group(1))
    rem = mass
    parts = []
    for w in [500, 200, 100, 50, 20, 10, 5, 2, 1]:
        while rem >= w:
            parts.append(w)
            rem -= w
    text = ' + '.join(f'{p} г' for p in parts)
    return _make_payload(raw_text, ['Решение.', f'{mass} г = {text}.', f'Ответ: {text}.'])


def _build_v204_mass_purchase(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'пачки печенья' not in lower or 'пачки чая' not in lower:
        return None
    m = re.search(r'купили\s+(\d+)\s+пачк\w*\s+печенья\s+по\s+(\d+)\s*г\s+и\s+(\d+)\s+пачк\w*\s+чая\s+по\s+(\d+)\s*г', lower)
    if not m:
        return None
    c1,m1,c2,m2=map(int,m.groups())
    total=c1*m1+c2*m2
    return _make_payload(raw_text, ['Решение.', f'1) Печенье: {m1} × {c1} = {c1*m1} г.', f'2) Чай: {m2} × {c2} = {c2*m2} г.', f'3) Всего: {c1*m1} + {c2*m2} = {total} г.', f'Ответ: {total} г.'])


def _build_v204_kg_g_to_grams(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    m = re.search(r'вырази\s+(\d+)\s*кг\s+(\d+)\s*г\s+в\s+граммах', lower)
    if not m:
        return None
    kg,g=map(int,m.groups())
    total=kg*1000+g
    return _make_payload(raw_text, ['Решение.', f'{kg} кг = {kg*1000} г; {kg*1000} + {g} = {total} г.', f'Ответ: {total} г.'])


def _build_v204_simple_equation(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text).replace('х','x').replace('×','*').replace('·','*').replace('∙','*')
    if 'реши уравнение' not in lower:
        return None
    m = re.search(r'x\s*\+\s*(\d+)\s*=\s*([0-9+\-*/:()\s]+)', lower)
    if m:
        a=int(m.group(1)); rhs=_v204_eval_int_expr(m.group(2));
        if rhs is None: return None
        ans=rhs-a
        return _make_payload(raw_text, ['Решение.', f'x = {rhs} − {a} = {ans}.', f'Ответ: {ans}.'])
    m = re.search(r'x\s*\*\s*(\d+)\s*=\s*([0-9+\-*/:()\s]+)', lower)
    if m:
        a=int(m.group(1)); rhs=_v204_eval_int_expr(m.group(2));
        if rhs is None: return None
        ans=rhs//a
        return _make_payload(raw_text, ['Решение.', f'x = {rhs} : {a} = {ans}.', f'Ответ: {ans}.'])
    m = re.search(r'(\d+)\s*-\s*x\s*=\s*([0-9+\-*/:()\s]+)', lower)
    if m:
        a=int(m.group(1)); rhs=_v204_eval_int_expr(m.group(2));
        if rhs is None: return None
        ans=a-rhs
        return _make_payload(raw_text, ['Решение.', f'x = {a} − {rhs} = {ans}.', f'Ответ: {ans}.'])
    m = re.search(r'x\s*:\s*(\d+)\s*=\s*([0-9+\-*/:()\s]+)', lower)
    if m:
        a=int(m.group(1)); rhs=_v204_eval_int_expr(m.group(2));
        if rhs is None: return None
        ans=rhs*a
        return _make_payload(raw_text, ['Решение.', f'x = {rhs} × {a} = {ans}.', f'Ответ: {ans}.'])
    m = re.search(r'(\d+)\s*:\s*x\s*=\s*([0-9+\-*/:()\s]+)', lower)
    if m:
        a=int(m.group(1)); rhs=_v204_eval_int_expr(m.group(2));
        if rhs is None or rhs == 0: return None
        ans=a//rhs
        return _make_payload(raw_text, ['Решение.', f'x = {a} : {rhs} = {ans}.', f'Ответ: {ans}.'])
    m = re.search(r'x\s*-\s*(\d+)\s*=\s*([0-9+\-*/:()\s]+)', lower)
    if m:
        a=int(m.group(1)); rhs=_v204_eval_int_expr(m.group(2));
        if rhs is None: return None
        ans=rhs+a
        return _make_payload(raw_text, ['Решение.', f'x = {rhs} + {a} = {ans}.', f'Ответ: {ans}.'])
    return None


def _build_v204_canvas_fit(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'клетка на канве' not in lower or 'хватит ли' not in lower:
        return None
    m = re.search(r'рисунок\s+имеет\s+(\d+)\s*мм.*?(\d+)\s*мм.*?в\s+(\d+)\s+раза?\s+больше.*?куска\s+канвы\s+(\d+)\s*см\s+на\s+(\d+)\s*см', lower)
    if not m:
        return None
    w,h,k,cm1,cm2=map(int,m.groups())
    sw,sh=w*k,h*k
    fits=(sw <= cm1*10 and sh <= cm2*10) or (sw <= cm2*10 and sh <= cm1*10)
    verdict='хватит' if fits else 'не хватит'
    return _make_payload(raw_text, ['Решение.', f'Размер на канве: {w} × {k} = {sw} мм, {h} × {k} = {sh} мм.', f'Кусок канвы: {cm1*10} мм на {cm2*10} мм.', f'Ответ: {verdict}, размер рисунка {sw} мм на {sh} мм.'])


def _build_v204_fabric_enough(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'обивку' not in lower or 'хватит ли' not in lower:
        return None
    m = re.search(r'одного\s+дивана\s+нужно\s+(\d+)\s*м.*?пару\s+кресел\s+[—-]\s+(\d+)\s*м.*?есть\s+(\d+)\s*м.*?на\s+(\d+)\s+диван\w*\s+и\s+(\d+)\s+пар', lower)
    if not m:
        return None
    sofa,chair,total,sc,pc=map(int,m.groups())
    used=sofa*sc+chair*pc
    verdict='хватит' if used<=total else 'не хватит'
    extra=total-used
    return _make_payload(raw_text, ['Решение.', f'Понадобится: {sofa}×{sc} + {chair}×{pc} = {used} м.', f'Есть {total} м.', f'Ответ: {verdict}; нужно {used} м, остаток/нехватка {abs(extra)} м.'])


def _build_v204_time_seconds(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    m = re.search(r'сколько\s+секунд\s+в\s+(\d+)\s*мин\s+(\d+)\s*с', lower)
    if not m:
        return None
    minutes,sec=map(int,m.groups())
    total=minutes*60+sec
    return _make_payload(raw_text, ['Решение.', f'{minutes} мин = {minutes*60} с; {minutes*60} + {sec} = {total} с.', f'Ответ: {total} с.'])


def _build_v204_robot_cleaning(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'робот' not in lower or 'комнат' not in lower or 'раза меньше' not in lower:
        return None
    m = re.search(r'первой\s+комнаты.*?(\d+)\s*мин.*?вторую\s+[—-]\s+в\s+(\d+)\s+раза?\s+меньше', lower)
    if not m:
        return None
    first,k=map(int,m.groups())
    second=first//k; total=first+second
    return _make_payload(raw_text, ['Решение.', f'Вторая комната: {first} : {k} = {second} мин.', f'Всего: {first} + {second} = {total} мин.', f'Ответ: {total} мин.'])


def _build_v204_camera_rate(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'кинокамера' not in lower or 'сним' not in lower:
        return None
    m = re.search(r'делает\s+(\d+)\s+сним\w*\s+за\s+(\d+)\s*с.*?за\s+(\d+)\s*с', lower)
    if not m:
        return None
    shots,sec,target=map(int,m.groups())
    per=shots//sec; ans=per*target
    return _make_payload(raw_text, ['Решение.', f'За 1 с: {shots} : {sec} = {per} сним.', f'За {target} с: {per} × {target} = {ans} сним.', f'Ответ: {ans} снимков.'])


def _build_v204_spring_water(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'родник' not in lower or 'литров' not in lower:
        return None
    m = re.search(r'банку\s+(\d+)\s*л\s+за\s+(\d+)\s*с.*?за\s+(\d+)\s*мин', lower)
    if not m:
        return None
    liters,sec,minutes=map(int,m.groups())
    sec_per_l=sec//liters
    per_min=60//sec_per_l
    ans=per_min*minutes
    return _make_payload(raw_text, ['Решение.', f'1 л получается за {sec} : {liters} = {sec_per_l} с.', f'За 1 мин: 60 : {sec_per_l} = {per_min} л.', f'За {minutes} мин: {per_min} × {minutes} = {ans} л.', f'Ответ: {ans} л.'])


def _build_v204_digit_permutations(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'трехзначные числа' not in lower and 'трёхзначные числа' not in lower:
        return None
    if 'без повторения' not in lower:
        return None
    m = re.search(r'цифры\s+(\d)\s*,\s*(\d)\s*,\s*(\d)', lower)
    if not m:
        return None
    digs = list(map(int,m.groups()))
    nums = [''.join(map(str,p)) for p in __import__('itertools').permutations(digs,3)]
    return _make_payload(raw_text, ['Решение.', 'Переставляем три цифры без повторений.', f'Ответ: {len(nums)} чисел: {", ".join(nums)}.'])


def _build_v204_bicycles(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'велосипед' not in lower or 'детск' not in lower:
        return None
    m = re.search(r'на\s+складе\s+(\d+)\s+велосипед\w*.*?женск\w*\s+велосипед\w*\s+(\d+).*?мужск\w*\s+[—-]\s+в\s+(\d+)\s+раз', lower)
    if not m:
        return None
    total,female,k=map(int,m.groups())
    male=female*k; child=total-female-male
    return _make_payload(raw_text, ['Решение.', f'Мужских: {female} × {k} = {male}.', f'Женских и мужских: {female} + {male} = {female+male}.', f'Детских: {total} − {female+male} = {child}.', f'Ответ: {child}.'])


def _build_v204_grain_packages(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'круп' not in lower or 'пакет' not in lower or 'больше' not in lower:
        return None
    m = re.search(r'расфасовали\s+(\d+)\s*кг\s+крупы\s+поровну\s+в\s+(\d+)\s+пакет\w*.*?для\s+(\d+)\s*кг.*?на\s+(\d+)\s*кг\s+больше', lower)
    if not m:
        return None
    mass,bags,new_mass,inc=map(int,m.groups())
    old_one=mass//bags; new_one=old_one+inc; ans=new_mass//new_one
    return _make_payload(raw_text, ['Решение.', f'В старом пакете: {mass} : {bags} = {old_one} кг.', f'В новом пакете: {old_one} + {inc} = {new_one} кг.', f'Пакетов: {new_mass} : {new_one} = {ans}.', f'Ответ: {ans} пакетов.'])


def _build_v204_equality_check(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'проверь равенство' not in lower:
        return None
    expr = lower.split(':',1)[1].strip().rstrip('.') if ':' in lower else ''
    if '=' not in expr:
        return None
    left,right = expr.split('=',1)
    lv=_v204_eval_int_expr(left); rv=_v204_eval_int_expr(right)
    if lv is None or rv is None:
        return None
    verdict='верно' if lv==rv else 'неверно'
    return _make_payload(raw_text, ['Решение.', f'Левая часть = {lv}, правая часть = {rv}.', f'Ответ: {verdict}.'])


def _build_v204_variable_values(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text).replace('х','x')
    m = re.search(r'a\s*\+\s*b\s+и\s+a\s*-\s*b.*?a\s*=\s*(\d+)\s*,\s*b\s*=\s*(\d+)', lower)
    if m:
        a,b=map(int,m.groups())
        return _make_payload(raw_text, ['Решение.', f'a + b = {a} + {b} = {a+b}.', f'a − b = {a} − {b} = {a-b}.', f'Ответ: {a+b}, {a-b}.'])
    m = re.search(r'c\s*\*\s*d\s+и\s+c\s*:\s*d.*?c\s*=\s*(\d+)\s*,\s*d\s*=\s*(\d+)', lower)
    if m:
        c,d=map(int,m.groups())
        return _make_payload(raw_text, ['Решение.', f'c × d = {c} × {d} = {c*d}.', f'c : d = {c} : {d} = {c//d}.', f'Ответ: {c*d}, {c//d}.'])
    return None


def _build_v204_convenient(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'вычисли удобным способом' not in lower:
        return None
    expr = lower.split(':',1)[1].strip().rstrip('.') if ':' in lower else ''
    ans=_v204_eval_int_expr(expr)
    if ans is None:
        return None
    return _make_payload(raw_text, ['Решение.', f'Используем общий множитель/удобную группировку.', f'{expr} = {ans}.', f'Ответ: {ans}.'])


def _build_v204_quotient_remainder(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'частное и остаток' not in lower:
        return None
    m = re.search(r'(\d+)\s*:\s*(\d+)', lower)
    if not m:
        return None
    a,b=map(int,m.groups())
    q,r=divmod(a,b)
    return _make_payload(raw_text, ['Решение.', f'{a} = {b} × {q} + {r}; остаток меньше делителя.', f'Ответ: {q} (ост. {r}).'])


def _build_v204_race_finish(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'автопробег' not in lower or 'спортсмен' not in lower:
        return None
    m = re.search(r'участвовало\s+(\d+)\s+машин.*?по\s+(\d+)\s+спортсмен\w*.*?не\s+дошли\s+(\d+)\s+машин', lower)
    if not m:
        return None
    cars,team,not_finished=map(int,m.groups())
    fin=cars-not_finished; athletes=fin*team
    return _make_payload(raw_text, ['Решение.', f'Машин финишировало: {cars} − {not_finished} = {fin}.', f'Спортсменов: {fin} × {team} = {athletes}.', f'Ответ: {fin} машин и {athletes} спортсменов.'])


def _build_v204_curtains(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'штор' not in lower or 'куск' not in lower:
        return None
    m = re.search(r'первом\s+куске\s+было\s+(\d+)\s*м.*?втором\s+[—-]\s+(\d+)\s*м.*?на\s+(\d+)\s+штор', lower)
    if not m:
        return None
    first,second,extra=map(int,m.groups())
    per=(second-first)//extra; a=first//per; b=second//per
    return _make_payload(raw_text, ['Решение.', f'Разница ткани: {second} − {first} = {second-first} м.', f'На одну штору: {second-first} : {extra} = {per} м.', f'Первый кусок: {first} : {per} = {a}; второй: {second} : {per} = {b}.', f'Ответ: {a} и {b} штор.'])


def _build_v204_stamps_pages(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'марок' not in lower or 'страниц' not in lower:
        return None
    m = re.search(r'было\s+(\d+)\s+иностранных\s+марок\s+и\s+(\d+)\s+российских.*?на\s+(\d+)\s+страниц', lower)
    if not m:
        return None
    foreign,russian,extra=map(int,m.groups())
    per=(russian-foreign)//extra; pages=russian//per
    return _make_payload(raw_text, ['Решение.', f'Разница марок: {russian} − {foreign} = {russian-foreign}.', f'На странице: {russian-foreign} : {extra} = {per} марок.', f'Российские заняли: {russian} : {per} = {pages} стр.', f'Ответ: {pages} страниц.'])


def _build_v204_opposite_initial(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'противоположных направлениях' not in lower or 'расстояние между которыми' not in lower:
        return None
    m = re.search(r'расстояние\s+между\s+которыми\s+(\d+)\s*км.*?скоростями\s+(\d+)\s*км/ч\s+и\s+(\d+)\s*км/ч.*?через\s+(\d+)\s*ч', lower)
    if not m:
        return None
    initial,v1,v2,t=map(int,m.groups())
    moved=(v1+v2)*t; ans=initial+moved
    return _make_payload(raw_text, ['Решение.', f'Скорость удаления: {v1} + {v2} = {v1+v2} км/ч.', f'За {t} ч удалятся на {(v1+v2)} × {t} = {moved} км.', f'Всего: {initial} + {moved} = {ans} км.', f'Ответ: {ans} км.'])


def _build_v204_exact_division(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'выполни деление' not in lower:
        return None
    m = re.search(r'(\d+)\s*:\s*(\d+)', lower)
    if not m:
        return None
    a,b=map(int,m.groups())
    q=a//b
    return _make_payload(raw_text, ['Решение.', f'{a} : {b} = {q}. Проверка: {q} × {b} = {q*b}.', f'Ответ: {q}.'])


_PRE_V204_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION = build_open_source_curriculum_explanation


