def _build_v208_choir(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'в хоре' not in lower or 'девочек' not in lower or 'мальчиков' not in lower:
        return None
    m = re.search(r'в хоре\s+(\d+)\s+ряд\w*.*?по\s+(\d+)\s+девочек.*?по\s+(\d+)\s+мальчиков', lower)
    if not m:
        return None
    rows,girls,boys=map(int,m.groups())
    girls_total=rows*girls; boys_total=rows*boys; total=girls_total+boys_total; diff=abs(girls_total-boys_total)
    ratio = max(girls_total,boys_total)//min(girls_total,boys_total)
    return _make_payload(raw_text, ['Решение.', f'Девочек: {girls} × {rows} = {girls_total}; мальчиков: {boys} × {rows} = {boys_total}.', f'Всего: {girls_total} + {boys_total} = {total}. Разница: {diff}. Кратное сравнение: {ratio}.', f'Ответ: {total}, {diff}, {ratio}.'])


