def _build_v208_bridge(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'от дома до начала моста' not in lower or 'до магазина' not in lower:
        return None
    m = re.search(r'до начала моста\s+(\d+)\s+шаг\w*.*?длина моста\s+(\d+)\s+шаг\w*.*?до магазина\s+(\d+)\s+шаг', lower)
    if not m:
        return None
    a,b,c=map(int,m.groups()); ans=c-a-b
    return _make_payload(raw_text, ['Решение.', f'До конца моста: {a} + {b} = {a+b} шагов.', f'От конца моста до магазина: {c} − {a+b} = {ans} шагов.', f'Ответ: {ans}.'])


def _build_v208_compose_number(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'состоящее из' not in lower or 'сот' not in lower or 'десят' not in lower:
        return None
    m = re.search(r'из\s+(\d+)\s+сот\w*,\s*(\d+)\s+десят\w*,\s*(\d+)\s+единиц', lower)
    if not m:
        return None
    h,t,o=map(int,m.groups()); ans=h*100+t*10+o
    return _make_payload(raw_text, ['Решение.', f'{h} сот. = {h*100}, {t} дес. = {t*10}, {o} ед. = {o}.', f'Ответ: {ans}.'])


def _build_v208_sequence(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'продолжи ряд' not in lower:
        return None
    nums = list(map(int, re.findall(r'\d+', lower)))
    if len(nums) < 3:
        return None
    a,b,c=nums[0],nums[1],nums[2]; d=b-a; n1=c+d; n2=n1+d
    return _make_payload(raw_text, ['Решение.', f'Шаг ряда: {b} − {a} = {d}.', f'Следующие числа: {n1}, {n2}.', f'Ответ: {n1}, {n2}.'])


def _build_v208_compare(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'поставь знак сравнения' not in lower:
        return None
    nums = list(map(int, re.findall(r'\d+', lower)))
    if len(nums) < 2:
        return None
    a,b=nums[0],nums[1]
    sign = '<' if a < b else '>' if a > b else '='
    return _make_payload(raw_text, ['Решение.', f'Сравниваем {a} и {b}: {a} {sign} {b}.', f'Ответ: {sign}.'])


def _build_v208_order_expr(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'вычисли по порядку действий' not in lower:
        return None
    expr = raw_text.strip().rstrip('.')
    if ':' in expr:
        expr = expr.split(':', 1)[1].strip()
    ans = _v208_eval_int(expr)
    if ans is None:
        return None
    return _make_payload(raw_text, ['Решение.', f'{expr} = {ans}.', f'Ответ: {ans}.'])


def _build_v208_area_compare(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'площадь площадки меньше площади бассейна' not in lower:
        return None
    m = re.search(r'длину\s+(\d+)\s*м\s+и\s+ширину\s+(\d+)\s*м.*?сторону\s+(\d+)\s*м', lower)
    if not m:
        return None
    l,w,s=map(int,m.groups())
    pool=l*w; square=s*s; ans=pool//square
    return _make_payload(raw_text, ['Решение.', f'Площадь бассейна: {l} × {w} = {pool} м². Площадь площадки: {s} × {s} = {square} м².', f'Кратное сравнение: {pool} : {square} = {ans}.', f'Ответ: {ans}.'])


def _build_v208_dry_product(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'свежего картофеля' not in lower or 'сушеного' not in lower:
        return None
    m = re.search(r'из\s+(\d+)\s*кг\s+свежего\s+картофеля\s+получается\s+(\d+)\s*кг\s+сушеного.*?получить\s+(\d+)\s*кг', lower)
    if not m:
        return None
    fresh,dry,need=map(int,m.groups()); ans=need*fresh//dry
    return _make_payload(raw_text, ['Решение.', f'{need} : {dry} = {need//dry} раз.', f'Свежего картофеля: {fresh} × {need//dry} = {ans} кг.', f'Ответ: {ans}.'])


def _build_v208_tree_rows(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'на двух участках' not in lower or 'одинаковых рядов' not in lower:
        return None
    m = re.search(r'на одном\s+(\d+)\s+одинаковых рядов.*?на другом\s+(\d+)\s+таких же рядов.*?всего посадили\s+(\d+)\s+дерев', lower)
    if not m:
        return None
    r1,r2,total=map(int,m.groups()); per=total//(r1+r2); first=per*r1; second=per*r2
    return _make_payload(raw_text, ['Решение.', f'Всего рядов: {r1} + {r2} = {r1+r2}. В одном ряду: {total} : {r1+r2} = {per}.', f'На участках: {per} × {r1} = {first}; {per} × {r2} = {second}.', f'Ответ: {first}, {second}.'])


def _build_v208_joint_work(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'работая вместе' not in lower or 'бригада' not in lower:
        return None
    m = re.search(r'посадить\s+(\d+)\s+деревьев\s+за\s+(\d+)\s+дн.*?другая\s+[-—]\s+за\s+(\d+)\s+дн', lower)
    if not m:
        return None
    work,d1,d2=map(int,m.groups())
    rate1=work//d1; rate2=work//d2; rate=rate1+rate2; ans=work//rate
    return _make_payload(raw_text, ['Решение.', f'Первая за день: {work} : {d1} = {rate1}; вторая: {work} : {d2} = {rate2}.', f'Вместе за день: {rate1} + {rate2} = {rate}. Нужно дней: {work} : {rate} = {ans}.', f'Ответ: {ans}.'])


def _build_v208_vegetables(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'ящиков моркови' not in lower or 'ящиков свеклы' not in lower:
        return None
    m = re.search(r'привезли\s+(\d+)\s+ящиков\s+моркови\s+по\s+(\d+)\s*кг.*?и\s+(\d+)\s+одинаковых.*?ящиков\s+свеклы.*?всего\s+привезли\s+(\d+)\s*кг', lower)
    if not m:
        return None
    cb,ck,bb,total=map(int,m.groups())
    carrots=cb*ck; beets=total-carrots; ans=beets//bb
    return _make_payload(raw_text, ['Решение.', f'Моркови: {cb} × {ck} = {carrots} кг. Свёклы всего: {total} − {carrots} = {beets} кг.', f'В одном ящике свёклы: {beets} : {bb} = {ans} кг.', f'Ответ: {ans}.'])


def _v208_truth_word(ok: bool) -> str:
    return 'истина (верно)' if ok else 'ложь (неверно)'


def _build_v208_true_false(raw_text: str) -> Optional[str]:
    lower = _v200_relaxed_text(raw_text)
    if 'верно ли утверждение' not in lower:
        return None
    # sequence: first three numbers and candidate after ellipsis
    if 'последовательности' in lower and 'пропущено число' in lower:
        nums = list(map(int, re.findall(r'\d+', lower)))
        if len(nums) >= 4:
            a,b,c,cand = nums[0],nums[1],nums[2],nums[3]
            ok = (c + (b-a) == cand)
            return _make_payload(raw_text, ['Решение.', f'Шаг: {b} − {a} = {b-a}; следующее после {c}: {c+(b-a)}.', f'Ответ: {_v208_truth_word(ok)}.'])
    if re.search(r'\d+\s*:\s*\d+\s*=\s*\d+\s*\(\s*ост', lower):
        m = re.search(r'(\d+)\s*:\s*(\d+)\s*=\s*(\d+)\s*\(\s*ост\.?\s*(\d+)\s*\)', lower)
        if m:
            a,b,q,r=map(int,m.groups()); ok=(a//b==q and a%b==r)
            return _make_payload(raw_text, ['Решение.', f'{a} : {b} = {a//b} (ост. {a%b}).', f'Ответ: {_v208_truth_word(ok)}.'])
    if 'не изменится если убрать скобки' in lower:
        m = re.search(r'выражения\s+(.+?)\s+не изменится', lower)
        if m:
            expr = m.group(1).strip()
            a = _v208_eval_int(expr)
            b = _v208_eval_int(expr.replace('(', '').replace(')', ''))
            if a is not None and b is not None:
                ok = (a == b)
                return _make_payload(raw_text, ['Решение.', f'Со скобками: {a}; без скобок: {b}.', f'Ответ: {_v208_truth_word(ok)}.'])
    if 'массы' in lower and 'порядке увеличения' in lower:
        vals=[]
        for num,unit in re.findall(r'(\d+)\s*(кг|ц|т)', lower):
            n=int(num); vals.append(n if unit=='кг' else n*100 if unit=='ц' else n*1000)
        if len(vals) >= 3:
            ok = all(vals[i] < vals[i+1] for i in range(len(vals)-1))
            return _make_payload(raw_text, ['Решение.', f'В килограммах: {vals}.', f'Ответ: {_v208_truth_word(ok)}.'])
    if 'длины' in lower and 'порядке уменьшения' in lower:
        vals=[]
        for num,unit in re.findall(r'(\d+)\s*(км|м|см)', lower):
            n=int(num); vals.append(n*100000 if unit=='км' else n*100 if unit=='м' else n)
        if len(vals) >= 3:
            ok = all(vals[i] > vals[i+1] for i in range(len(vals)-1))
            return _make_payload(raw_text, ['Решение.', f'В сантиметрах: {vals}.', f'Ответ: {_v208_truth_word(ok)}.'])
    return None


_PRE_V208_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION = build_open_source_curriculum_explanation


def build_open_source_curriculum_explanation(raw_text: str) -> Optional[str]:
    return (
        _build_v208_choir(raw_text)
        or _build_v208_equation(raw_text)
        or _build_v208_division_check(raw_text)
        or _build_v208_bridge(raw_text)
        or _build_v208_compose_number(raw_text)
        or _build_v208_sequence(raw_text)
        or _build_v208_compare(raw_text)
        or _build_v208_order_expr(raw_text)
        or _build_v208_area_compare(raw_text)
        or _build_v208_dry_product(raw_text)
        or _build_v208_tree_rows(raw_text)
        or _build_v208_joint_work(raw_text)
        or _build_v208_vegetables(raw_text)
        or _build_v208_true_false(raw_text)
        or _PRE_V208_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION(raw_text)
    )

