# --- v209 Moro 3–4 part 2 pages 104–113 local handlers ---
# Synthetic thematic variants only; no verbatim textbook task bank is embedded.

def _v209_norm(text: str) -> str:
    return re.sub(r'\s+', ' ', str(text or '').lower().replace('ё', 'е')).strip()


def _v209_eval_int(expr: str) -> Optional[int]:
    text = str(expr or '').replace('−','-').replace('–','-').replace('—','-').replace('∙','*').replace('·','*').replace('×','*').replace(':','//')
    text = re.sub(r'\s+', '', text)
    if not re.fullmatch(r'[0-9+\-*/().]+', text):
        return None
    try:
        return int(eval(text, {'__builtins__': {}}, {}))
    except Exception:
        return None


def _v209_payload(raw_text: str, lines: list[str]) -> str:
    return _make_payload(raw_text, lines)


def _build_v209_inverse_fact(raw_text: str) -> Optional[str]:
    lower = _v209_norm(raw_text)
    if 'если' not in lower or 'заполни пропуск' not in lower:
        return None
    m = re.search(r'если\s+(\d+)\s*[·*xх]\s*(\d+)\s*=\s*(\d+).*?то\s*(\d+)\s*:\s*(\d+)\s*=\s*\?', lower)
    if not m:
        return None
    a,b,p,p2,divisor = map(int, m.groups())
    ans = p2 // divisor
    return _v209_payload(raw_text, ['Решение.', f'Используем связь действий: {p2} : {divisor} = {ans}.', f'Ответ: {ans}.'])


def _build_v209_factor_pair(raw_text: str) -> Optional[str]:
    lower = _v209_norm(raw_text)
    if 'произведением каких двух' not in lower:
        return None
    m = re.search(r'число\s+(\d+)', lower)
    if not m:
        return None
    n = int(m.group(1))
    for a in range(1,10):
        for b in range(a,10):
            if a*b == n:
                return _v209_payload(raw_text, ['Решение.', f'{a} × {b} = {n}.', f'Ответ: {a}, {b}.'])
    return None


def _build_v209_expression_value(raw_text: str) -> Optional[str]:
    lower = _v209_norm(raw_text)
    if 'вычисли значение выражения' not in lower:
        return None
    expr = raw_text.split(':', 1)[1].strip().rstrip('.') if ':' in raw_text else raw_text
    ans = _v209_eval_int(expr)
    if ans is None:
        return None
    return _v209_payload(raw_text, ['Решение.', f'{expr} = {ans}.', f'Ответ: {ans}.'])


def _build_v209_daily_production(raw_text: str) -> Optional[str]:
    lower = _v209_norm(raw_text)
    if 'мастерской' not in lower or 'рабочих дней' not in lower or 'издел' not in lower:
        return None
    m = re.search(r'за\s+(\d+)\s+дн\w*\s+изготовили\s+(\d+)\s+издел.*?за\s+(\d+)\s+рабоч', lower)
    if not m:
        return None
    days,total,workdays = map(int, m.groups())
    per = total // days; ans = per * workdays
    return _v209_payload(raw_text, ['Решение.', f'За день: {total} : {days} = {per} изделий.', f'За {workdays} дней: {per} × {workdays} = {ans}.', f'Ответ: {ans}.'])


def _build_v209_unit_price(raw_text: str) -> Optional[str]:
    lower = _v209_norm(raw_text)
    if 'ткани' not in lower or 'цена одного метра' not in lower:
        return None
    m = re.search(r'за\s+(\d+)\s*м\s+ткани\s+заплатили\s+(\d+)\s+руб', lower)
    if not m:
        return None
    meters,total = map(int, m.groups())
    ans = total // meters
    return _v209_payload(raw_text, ['Решение.', f'Цена одного метра: {total} : {meters} = {ans} рублей.', f'Ответ: {ans}.'])


def _build_v209_one_action(raw_text: str) -> Optional[str]:
    lower = _v209_norm(raw_text)
    if 'во сколько раз' in lower:
        nums = list(map(int, re.findall(r'\d+', lower)))
        if len(nums) >= 2:
            ans = max(nums[0], nums[1]) // min(nums[0], nums[1])
            return _v209_payload(raw_text, ['Решение.', f'{max(nums[0], nums[1])} : {min(nums[0], nums[1])} = {ans}.', f'Ответ: {ans}.'])
    if 'сколько стоит вся покупка' in lower:
        m = re.search(r'купили\s+(\d+)\s+\w+\s+по\s+(\d+)\s+руб', lower)
        if m:
            qty,price=map(int,m.groups()); ans=qty*price
            return _v209_payload(raw_text, ['Решение.', f'{price} × {qty} = {ans}.', f'Ответ: {ans}.'])
    if 'сколько наклеек купили' in lower:
        nums = list(map(int, re.findall(r'\d+', lower)))
        if len(nums) >= 2:
            price,total = nums[0], nums[1]; ans = total // price
            return _v209_payload(raw_text, ['Решение.', f'{total} : {price} = {ans}.', f'Ответ: {ans}.'])
    if 'цену одной тетради' in lower:
        m = re.search(r'за\s+(\d+)\s+одинаковых\s+тетрадей\s+заплатили\s+(\d+)', lower)
        if m:
            qty,total=map(int,m.groups()); ans=total//qty
            return _v209_payload(raw_text, ['Решение.', f'{total} : {qty} = {ans}.', f'Ответ: {ans}.'])
    return None


def _build_v209_segment_compare(raw_text: str) -> Optional[str]:
    lower = _v209_norm(raw_text)
    if 'отрезок ab' not in lower or 'во сколько раз' not in lower:
        return None
    nums = list(map(int, re.findall(r'\d+', lower)))
    if len(nums) < 2:
        return None
    a,b = nums[0], nums[1]
    long,short=max(a,b),min(a,b)
    ratio=long//short; diff=long-short
    return _v209_payload(raw_text, ['Решение.', f'Кратное сравнение: {long} : {short} = {ratio}. Разностное сравнение: {long} − {short} = {diff} см.', f'Ответ: {ratio}, {diff}.'])


def _build_v209_geometry_measure(raw_text: str) -> Optional[str]:
    lower = _v209_norm(raw_text)
    nums = list(map(int, re.findall(r'\d+', lower)))
    if 'длину ломаной' in lower and len(nums) >= 3:
        ans = sum(nums[:3])
        return _v209_payload(raw_text, ['Решение.', f'Длина ломаной равна сумме звеньев: {" + ".join(map(str, nums[:3]))} = {ans}.', f'Ответ: {ans}.'])
    if 'периметр прямоугольника' in lower and len(nums) >= 2:
        a,b=nums[0],nums[1]; ans=(a+b)*2
        return _v209_payload(raw_text, ['Решение.', f'Периметр: ({a} + {b}) × 2 = {ans}.', f'Ответ: {ans}.'])
    if 'площадь прямоугольника' in lower and len(nums) >= 2:
        a,b=nums[0],nums[1]; ans=a*b
        return _v209_payload(raw_text, ['Решение.', f'Площадь: {a} × {b} = {ans}.', f'Ответ: {ans}.'])
    return None


def _build_v209_missing_sequence(raw_text: str) -> Optional[str]:
    lower = _v209_norm(raw_text)
    if 'восстанови пропущенные числа' not in lower:
        return None
    nums = list(map(int, re.findall(r'\d+', lower)))
    if len(nums) < 4:
        return None
    a,b,c,last = nums[0],nums[1],nums[2],nums[3]
    step=b-a
    missing=[c+step, c+2*step, c+3*step]
    return _v209_payload(raw_text, ['Решение.', f'Шаг ряда: {step}. Пропущенные числа: {missing[0]}, {missing[1]}, {missing[2]}.', f'Ответ: {missing[0]}, {missing[1]}, {missing[2]}.'])


def _build_v209_missing_equation(raw_text: str) -> Optional[str]:
    lower = _v209_norm(raw_text).replace('□', 'x').replace(' ', '')
    if 'найдипропущенноечисло' not in lower:
        return None
    # x + a = b - c; a + x = b - c
    m = re.search(r'(\d+)\+x=(\d+)-(\d+)', lower)
    if m:
        a,b,c=map(int,m.groups()); ans=(b-c)-a
        return _v209_payload(raw_text, ['Решение.', f'Правая часть: {b} − {c} = {b-c}; пропуск: {b-c} − {a} = {ans}.', f'Ответ: {ans}.'])
    m = re.search(r'(\d+)\+(\d+)=x-(\d+)', lower)
    if m:
        a,b,c=map(int,m.groups()); ans=a+b+c
        return _v209_payload(raw_text, ['Решение.', f'Левая часть: {a} + {b} = {a+b}; уменьшаемое: {a+b} + {c} = {ans}.', f'Ответ: {ans}.'])
    m = re.search(r'(\d+):x=(\d+)', lower)
    if m:
        a,b=map(int,m.groups()); ans=a//b
        return _v209_payload(raw_text, ['Решение.', f'Делитель: {a} : {b} = {ans}.', f'Ответ: {ans}.'])
    m = re.search(r'x[·*xх](\d+)=(\d+)', lower)
    if m:
        a,b=map(int,m.groups()); ans=b//a
        return _v209_payload(raw_text, ['Решение.', f'Множитель: {b} : {a} = {ans}.', f'Ответ: {ans}.'])
    return None


def _build_v209_fraction_compare(raw_text: str) -> Optional[str]:
    lower = _v209_norm(raw_text)
    if 'сравни доли' not in lower:
        return None
    m = re.search(r'(\d+)\s*/\s*(\d+)\s*\?\s*(\d+)\s*/\s*(\d+)', lower)
    if not m:
        return None
    a,b,c,d=map(int,m.groups())
    left=a*d; right=c*b
    sign='<' if left < right else '>' if left > right else '='
    return _v209_payload(raw_text, ['Решение.', f'Сравним перекрёстно: {a}×{d} = {left}, {c}×{b} = {right}.', f'Ответ: {sign}.'])


def _build_v209_mass_product(raw_text: str) -> Optional[str]:
    lower = _v209_norm(raw_text)
    if 'проса' not in lower and 'пшена' not in lower:
        return None
    m = re.search(r'из\s+(\d+)\s*кг\s+проса\s+получается\s+(\d+)\s*кг\s+пшена.*?из\s+(\d+)\s*кг\s+проса', lower)
    if not m:
        return None
    base_in,base_out,need=map(int,m.groups())
    ans=need*base_out//base_in
    return _v209_payload(raw_text, ['Решение.', f'{need} : {base_in} = {need//base_in} раз; {base_out} × {need//base_in} = {ans}.', f'Ответ: {ans}.'])


def _build_v209_farm_half(raw_text: str) -> Optional[str]:
    lower = _v209_norm(raw_text)
    if 'ферме' not in lower or 'половина' not in lower or 'молока' not in lower:
        return None
    m = re.search(r'от каждой из\s+(\d+)\s+коров.*?по\s+(\d+)\s*кг', lower)
    if not m:
        return None
    cows,per=map(int,m.groups()); total=cows*per; ans=total//2
    return _v209_payload(raw_text, ['Решение.', f'Всего молока: {cows} × {per} = {total} кг.', f'Половина: {total} : 2 = {ans} кг.', f'Ответ: {ans}.'])


def _build_v209_opposite(raw_text: str) -> Optional[str]:
    lower = _v209_norm(raw_text)
    if 'противоположных направлениях' not in lower or 'м/мин' not in lower:
        return None
    m = re.search(r'скорость теплохода\s+(\d+)\s*м/мин.*?на\s+(\d+)\s*м/мин\s+меньше.*?через\s+(\d+)\s*ч', lower)
    if not m:
        return None
    fast,diff,h=map(int,m.groups()); slow=fast-diff; m_total=(fast+slow)*h*60; km=m_total//1000
    return _v209_payload(raw_text, ['Решение.', f'Скорость катера: {fast} − {diff} = {slow} м/мин. Скорость удаления: {fast} + {slow} = {fast+slow} м/мин.', f'За {h} ч: {fast+slow} × {h} × 60 = {m_total} м = {km} км.', f'Ответ: {km}.'])


def _build_v209_speed_difference(raw_text: str) -> Optional[str]:
    lower = _v209_norm(raw_text)
    if 'по шоссе' not in lower or 'в городе' not in lower:
        return None
    m = re.search(r'проезжает\s+(\d+)\s*км\s+за\s+(\d+)\s*ч.*?за\s+(\d+)\s*ч', lower)
    if not m:
        return None
    dist,h1,h2=map(int,m.groups()); s1=dist//h1; s2=dist//h2; ans=s1-s2
    return _v209_payload(raw_text, ['Решение.', f'Скорость по шоссе: {dist} : {h1} = {s1} км/ч; в городе: {dist} : {h2} = {s2} км/ч.', f'Разница: {s1} − {s2} = {ans} км/ч.', f'Ответ: {ans}.'])


def _build_v209_area_units(raw_text: str) -> Optional[str]:
    lower = _v209_norm(raw_text)
    if 'перевод или сравнение площади' not in lower:
        return None
    if 'км² больше 1 га' in lower:
        ans=100
    elif '1 га больше' in lower:
        m = re.search(r'1\s*га\s+больше\s+(\d+)\s*а', lower)
        if not m: return None
        ans=100-int(m.group(1))
    else:
        m = re.search(r':\s*(\d+)\s*(а|га|м²|км²)', lower)
        if not m: return None
        n=int(m.group(1)); unit=m.group(2)
        if unit == 'а':
            if ' в м²' in lower: ans=n*100
            elif ' в га' in lower: ans=n//100
            else: ans=n
        elif unit == 'га':
            if ' в а' in lower: ans=n*100
            elif ' в м²' in lower: ans=n*10000
            else: ans=n
        elif unit == 'м²':
            if ' в а' in lower: ans=n//100
            else: ans=n
        elif unit == 'км²':
            if ' в га' in lower: ans=n*100
            else: ans=n
        else:
            return None
    return _v209_payload(raw_text, ['Решение.', 'Используем: 1 а = 100 м², 1 га = 100 а, 1 км² = 100 га.', f'Ответ: {ans}.'])


def _build_v209_field_yield(raw_text: str) -> Optional[str]:
    lower = _v209_norm(raw_text)
    if 'центнеров с гектара' not in lower or 'два участка' not in lower:
        return None
    m = re.search(r'площадь первого\s+(\d+)\s*га,\s*второго\s+(\d+)\s*га.*?по\s+(\d+)\s*ц.*?всего\s+собрали\s+(\d+)\s*ц', lower)
    if not m:
        return None
    area1,area2,yield1,total=map(int,m.groups())
    first=area1*yield1; second=total-first; ans=second//area2
    return _v209_payload(raw_text, ['Решение.', f'С первого участка: {area1} × {yield1} = {first} ц. Со второго: {total} − {first} = {second} ц.', f'Урожайность второго: {second} : {area2} = {ans} ц/га.', f'Ответ: {ans}.'])


def _build_v209_plan_area(raw_text: str) -> Optional[str]:
    lower = _v209_norm(raw_text)
    if 'на плане прямоугольный участок' not in lower:
        return None
    m = re.search(r'размеры\s+(\d+)\s*см\s+и\s+(\d+)\s*см.*?1\s*см²\s+изображает\s+(\d+)\s*м²', lower)
    if not m:
        return None
    a,b,scale=map(int,m.groups()); plan=a*b; ans=plan*scale
    return _v209_payload(raw_text, ['Решение.', f'Площадь на плане: {a} × {b} = {plan} см². На местности: {plan} × {scale} = {ans} м².', f'Ответ: {ans}.'])


def _build_v209_sequence_next(raw_text: str) -> Optional[str]:
    lower = _v209_norm(raw_text)
    if 'запиши следующее число' not in lower:
        return None
    nums = list(map(int, re.findall(r'\d+', lower)))
    if len(nums) < 4:
        return None
    a,b,c,d=nums[0],nums[1],nums[2],nums[3]
    step=b-a; ans=d+step
    return _v209_payload(raw_text, ['Решение.', f'Шаг: {b} − {a} = {step}. Следующее число: {d} + {step} = {ans}.', f'Ответ: {ans}.'])


def _build_v209_solid(raw_text: str) -> Optional[str]:
    lower = _v209_norm(raw_text)
    if 'прямоугольного параллелепипеда' in lower and 'сколько' in lower:
        return _v209_payload(raw_text, ['Решение.', 'У прямоугольного параллелепипеда 6 граней, 12 рёбер и 8 вершин.', 'Ответ: 6, 12, 8.'])
    if 'поверхность состоит из прямоугольника и двух кругов' in lower:
        return _v209_payload(raw_text, ['Решение.', 'Такую развёртку имеет цилиндр.', 'Ответ: цилиндр.'])
    if 'апельсин' in lower and 'арбуз' in lower:
        return _v209_payload(raw_text, ['Решение.', 'Эти предметы имеют форму шара.', 'Ответ: шар.'])
    return None


