    initial_markers = ('сначала', 'первоначально', 'сколько всего', 'в книжке', 'должно стоять', 'сколько денег ему дали', 'сколько листьев засушила', 'сколько страниц в книге', 'сколько всего значков было', 'сколько всего грядок', 'сколько всего метров', 'сколько всего килограммов', 'сколько всего путевок', 'сколько всего путёвок')
