    if any(w in text for w in ('осталось', 'остались', 'остался', 'осталась', 'остались кататься', 'осталось еще', 'осталось ещё')):
        return _zad3_v212_answer(raw_text, vals[-2] + vals[-1], 'начальное количество равно сделанной/убранной части плюс остаток')
