# v212c final refinements.
def _zad3_v212_part_whole(raw_text: str, text: str, nums: list[tuple[int, int, str, str]], question: str) -> Optional[str]:
    vals = _zad3_v212_values(text)
    if len(vals) < 2:
        return None
    strong = re.search(r'\bиз них\b|\bостальные\b|\bостальная\b|\bостальных\b|\bесли\b|\bв наборе\b', text)
    if strong:
        total = vals[0]
        known = vals[-1]
        if total >= known:
            return _zad3_v212_answer(raw_text, total - known, 'из целого вычитаем известную часть')
    # Total is explicitly stated with "всего", then one part is known.
    if 'всего' in text and not any(w in question for w in ('всего', 'стало', 'вместе')) and len(vals) == 2:
        if vals[0] >= vals[1]:
            return _zad3_v212_answer(raw_text, vals[0] - vals[1], 'из общего количества вычитаем известную часть')
    if any(marker in text for marker in ('за два дня', 'за две ручки', 'в двух кусках', 'в первый день', 'в первом куске', 'всего за два дня')) and any(marker in question for marker in ('второй', 'во второй', 'за второй', 'вторая', 'втором')):
        total = max(vals[0], vals[-1]) if 'всего за два дня' in text else vals[0]
        known = min(vals[0], vals[-1]) if 'всего за два дня' in text else vals[-1]
        if total >= known:
            return _zad3_v212_answer(raw_text, total - known, 'из общего количества за два объекта/дня вычитаем известную часть')
    category_markers = ('саша и ваня', 'игоря и жени', 'белых и', 'желтой и', 'красной и', 'со свеклой и', 'свеклу и капусту', 'рыжих и белых', 'красных и синих', 'лип и кленов', 'лип и клёнов', 'сонорных и всегда')
    if len(vals) == 2 and not any(w in question for w in ('всего', 'стало', 'вместе')) and any(w in text for w in category_markers):
        if vals[0] >= vals[1]:
            return _zad3_v212_answer(raw_text, vals[0] - vals[1], 'из общего количества вычитаем известную часть')
    return None


def _zad3_v212_remaining_or_removed(raw_text: str, text: str, nums: list[tuple[int, int, str, str]], question: str) -> Optional[str]:
    vals = _zad3_v212_values(text)
