    if any(w in text for w in ('осталось', 'остались', 'остался', 'осталась')) and any(w in question for w in removed_markers):
        total = vals[0]
        rest = vals[-1]
        if total >= rest:
            return _zad3_v212_answer(raw_text, total - rest, 'из общего количества вычитаем остаток')
