# --- v213: Zad3.xlsx rows 251-500 additive/relative word-problem fallback ---
# Covers the second Excel batch: direct comparisons, inverse comparisons,
# relative totals, symbolic one-step expressions, and multi-part remainders.

def _zad3_v213_clean_text(raw_text: str) -> str:
    text = str(raw_text or '').lower().replace('ё', 'е')
    text = text.replace('−', '-').replace('–', '-').replace('—', '-')
    text = text.replace('%', '-')
    text = re.sub(r'^\s*(?:№\s*\d+|задание\s*\d+)\s*[.)\]:;-]?\s*', '', text, flags=re.IGNORECASE)
    text = re.sub(r'^\s*(?:пожалуйста,?\s*)?реши\s+задачу\s*[:.]?\s*', '', text, flags=re.IGNORECASE)
    text = re.sub(r'\s*(?:ответ\s+запиши\s+числом|запиши\s+ответ\s+числом)\s*[.!?]*\s*$', '', text, flags=re.IGNORECASE)
    text = text.replace('ещ[', 'еще')
    text = text.replace('осталось2', 'осталось 2')
    text = re.sub(r'на\s*-\s*(\d+)', r'на \1', text)
    text = re.sub(r'(?<=[а-я])\s+:\s+', ': ', text, flags=re.IGNORECASE)
    text = re.sub(r'\s+([?.!,;])', r'\1', text)
    text = re.sub(r'\s+', ' ', text).strip()
    return text


def _zad3_v213_last_question(text: str) -> str:
    parts = re.findall(r'[^.!?]*\?', text)
    if parts:
        return parts[-1].strip(' ?.!')
    bits = [b.strip() for b in re.split(r'[.!?]+', text) if b.strip()]
    return bits[-1] if bits else text


def _zad3_v213_numbers(text: str) -> list[tuple[int, int]]:
    return [(int(m.group(0)), m.start()) for m in re.finditer(r'(?<![\w])\d+(?![\w])', text)]


def _zad3_v213_values(text: str) -> list[int]:
    return [v for v, _ in _zad3_v213_numbers(text)]


def _zad3_v213_answer(raw_text: str, value: int | str, rule: str = '') -> str:
    lines = ['Решение.']
    if rule:
        lines.append(f'Применяем правило: {rule}.')
    lines.append(f'Ответ: {value}.')
    return _make_payload(raw_text, lines)


def _zad3_v213_expr_answer(raw_text: str, expr: str, rule: str = '') -> str:
    expr = re.sub(r'\s+', ' ', expr.replace('−', '-').replace('–', '-').replace('—', '-')).strip()
    return _zad3_v213_answer(raw_text, expr, rule)


def _zad3_v213_first_var(pattern: str, text: str) -> Optional[re.Match[str]]:
    return re.search(pattern, text, flags=re.I)


def _build_zad3_v213_symbolic(raw_text: str, text: str, question: str) -> Optional[str]:
    if not re.search(r'\b[a-z]\b', text):
        return None
    # Avoid the known shifted-answer rows 368-369; corpus marks them manual_review.
    if 'третьем пос' in text or 'фабрика выпустила b пар обуви' in text:
        return None
    if 'столько же' in text:
        m = re.search(r'\b([a-z])\b[^.?!]*?столько же', text)
        if m:
            a = m.group(1)
            return _zad3_v213_expr_answer(raw_text, f'{a} + {a}', 'столько же означает такую же величину')
    if 'сколько всего' in question or 'через обе' in question or 'за два квартала' in question or 'стало' in question:
        m = re.search(r'\b([a-z])\b[^.?!]*?(?:,|а|и)[^.?!]*?\b([a-z])\b', text)
        if m:
            return _zad3_v213_expr_answer(raw_text, f'{m.group(1)} + {m.group(2)}', 'для общего количества складываем две части')
    if 'на сколько' in question:
        # Question usually asks how much the second is more/first is less: second - first.
        m = re.search(r'\b([a-z])\b[^.?!]*?(?:а|во втором|за второй|второй)[^.?!]*?\b([a-z])\b', text)
        if m:
            return _zad3_v213_expr_answer(raw_text, f'{m.group(2)} - {m.group(1)}', 'на сколько больше/меньше — это разность второго и первого')
    # Total and known part: total - known.
    if 'если' in text or 'неисправ' in text or 'мальчик' in text or 'вышли' in text or 'сошли' in text or 'пошло' in text or 'осталось' in text:
        m = re.search(r'\b([a-z])\b[^.?!]*?\b([a-z])\b', text)
        if m:
            return _zad3_v213_expr_answer(raw_text, f'{m.group(1)} - {m.group(2)}', 'из общего количества вычитаем известную часть')
    # Initial = done + rest.
    if any(w in question for w in ('первоначально', 'всего', 'должен')) or 'осталось пробежать' in text:
        m = re.search(r'\b([a-z])\b[^.?!]*?остал[^.?!]*?\b([a-z])\b', text)
        if m:
            return _zad3_v213_expr_answer(raw_text, f'{m.group(1)} + {m.group(2)}', 'начальное/общее количество равно выполненной части плюс остаток')
    # Final minus initial.
    if 'стало' in text:
        m = re.search(r'\b([a-z])\b[^.?!]*?стало\s+\b([a-z])\b', text)
        if m:
            return _zad3_v213_expr_answer(raw_text, f'{m.group(2)} - {m.group(1)}', 'добавленную часть находим как конечное минус начальное')
    # Relative direct/inverse with variables.
    m = re.search(r'\b([a-z])\b[^.?!]*?на\s+\b([a-z])\b[^.?!]*?\b(больше|меньше|меньше\b|длиннее|выше)\b', text)
    if m:
        base, delta, rel = m.group(1), m.group(2), m.group(3)
        if 'чем' in text and any(w in question for w in ('сыроеж', 'осин', 'втор', 'зебр')):
            # Known object is bigger/smaller than the asked object.
            op = '-' if rel == 'больше' else '+'
        else:
            op = '+' if rel == 'больше' else '-'
        return _zad3_v213_expr_answer(raw_text, f'{base} {op} {delta}', 'по условию на больше/меньше составляем выражение')
    return None


def _build_zad3_v213_yes_no_shortage(raw_text: str, text: str) -> Optional[str]:
    if 'можно ли' not in text:
        return None
    vals = _zad3_v213_values(text)
    if len(vals) < 3:
        return None
    need = vals[0]
    have = sum(vals[1:])
    if have >= need:
        return _zad3_v213_answer(raw_text, 'да', 'длина лестниц не меньше нужной высоты')
    shortage = need - have
    return _zad3_v213_answer(raw_text, f'нет, не хватит {shortage} м', 'сравниваем нужную высоту и суммарную длину лестниц')


def _build_zad3_v213_difference(raw_text: str, text: str, question: str) -> Optional[str]:
    if 'на сколько' not in question:
        return None
    qpos = text.rfind('?')
    before_q = text[:qpos] if qpos >= 0 else text
    vals = _zad3_v213_values(before_q)
    if len(vals) < 2:
        return None
    a, b = vals[-2], vals[-1]
    return _zad3_v213_answer(raw_text, abs(a - b), 'чтобы узнать, на сколько больше или меньше, вычитаем меньшее число из большего')


def _build_zad3_v213_restore_initial(raw_text: str, text: str, question: str) -> Optional[str]:
    if not any(w in question for w in ('сначала', 'первоначально', 'было у', 'весь путь', 'было сначала', 'равен весь путь')):
        return None
    vals = _zad3_v213_values(text)
    if len(vals) < 2:
        return None
    return _zad3_v213_answer(raw_text, vals[-2] + vals[-1], 'начальное/всё количество равно выполненной части плюс остаток')


def _build_zad3_v213_simple_part_unknown(raw_text: str, text: str, question: str) -> Optional[str]:
    # Total with one known part: 10 total, 8 known -> 2 unknown.
    if not ('если' in text or 'из них' in text):
        return None
    vals = _zad3_v213_values(text)
    if len(vals) < 2:
        return None
    total = sum(vals[:-1]) if re.search(r'у\s+одн|у\s+друг|родилось|сорвал|собрал', text) and len(vals) >= 3 else vals[0]
    known = vals[-1]
    if total < known:
        return None
    return _zad3_v213_answer(raw_text, total - known, 'из общего количества вычитаем известную часть')


def _build_zad3_v213_inverse_relative(raw_text: str, text: str, question: str) -> Optional[str]:
    vals = _zad3_v213_values(text)
    if len(vals) < 2:
        return None
    # Examples: A is N, this is D more than B. Find B -> N-D. If N is D less than B -> N+D.
    m = re.search(r'(\d+)\s+[^.?!]*?(?:что|это|их|она)\s+на\s+(\d+)\s+[^.?!]*?\b(больше|меньше|старше|моложе)\b[^.?!]*?(?:чем\s+)?([^.?]*)', text)
    if m:
        base = int(m.group(1)); delta = int(m.group(2)); rel = m.group(3)
        if rel in ('больше', 'старше'):
            ans = base - delta
            op_rule = 'если известная величина на это число больше искомой, вычитаем разность'
        else:
            ans = base + delta
            op_rule = 'если известная величина на это число меньше искомой, прибавляем разность'
        if ans >= 0:
            return _zad3_v213_answer(raw_text, ans, op_rule)
    # "Катя моложе мамы на 19" / "Оля старше брата на 5".
    m = re.search(r'(\d+)\s+[^.?!]*?\b(старше|моложе)\b[^.?!]*?на\s+(\d+)', text)
    if m:
        base = int(m.group(1)); rel = m.group(2); delta = int(m.group(3))
        ans = base - delta if rel == 'старше' else base + delta
        if ans >= 0:
            return _zad3_v213_answer(raw_text, ans, 'обратное сравнение возраста')
    return None


def _v213_find_base_delta_relation(text: str) -> Optional[tuple[int, int, str]]:
    # Special: "на один пошло 5, на второй на 2 меньше".
    m = re.search(r'на\s+один[^.?!]*?(\d+)[^.?!]*?на\s+втор[^.?!]*?на\s+(\d+)\s+[^.?!]*?\b(больше|меньше)\b', text)
    if m:
        return int(m.group(1)), int(m.group(2)), m.group(3)
    # General: first quantity, second is more/less.
    m = re.search(r'(\d+)\s+[^.?!]*?(?:,|;|\.\s*|а\s+|во\s+втор|на\s+втор|под\s+дерев|моркови|ж[её]лтых|маленьких|слонов|домр|воробьев|конвертов|печенья|вишен)[^.?!]*?на\s+(столько\s+же|\d+)\s+[^.?!]*?\b(больше|меньше)\b', text)
    if not m:
        m = re.search(r'(\d+)\s+[^.?!]*?на\s+(столько\s+же|\d+)\s+[^.?!]*?\b(больше|меньше)\b', text)
    if not m:
        return None
    base = int(m.group(1))
    delta_text = m.group(2)
    delta = base if 'столько' in delta_text else int(delta_text)
    return base, delta, m.group(3)


def _build_zad3_v213_relative_chain(raw_text: str, text: str, question: str) -> Optional[str]:
    bd = _v213_find_base_delta_relation(text)
    if not bd:
        return None
    base, delta, rel = bd
    second = base + delta if rel == 'больше' else base - delta
    if second < 0:
        return None
    third = base + second
    has_third_sum = 'столько' in text and 'сколько' in text and any(w in text for w in ('трет', 'арахис', 'курток', 'лодок', 'городов', 'астр', 'студентов', 'хомяков', 'легковых', 'приемников', 'приёмников', 'бизонов', 'тайфуне', 'дымки'))
    if has_third_sum and not any(w in question for w in ('всего', 'вместе', 'двух')):
        return _zad3_v213_answer(raw_text, third, 'третья величина равна сумме первой и второй')
    if any(w in question for w in ('всего', 'вместе', 'общая', 'общую', 'двух', 'оба', 'обе', 'марок и конвертов', 'соусников и молочников', 'картофеля и моркови')):
        return _zad3_v213_answer(raw_text, base + second, 'сначала находим вторую величину, затем складываем первую и вторую')
    return _zad3_v213_answer(raw_text, second, 'по условию на больше/меньше находим вторую величину')


def _build_zad3_v213_same_amount(raw_text: str, text: str, question: str) -> Optional[str]:
    if 'столько же' not in text:
        return None
    vals = _zad3_v213_values(text)
    if not vals:
        return None
    base = vals[0]
    if 'стало' in question or 'всего' in question or 'привезли' in question:
        return _zad3_v213_answer(raw_text, base * 2, 'столько же означает ещё такое же количество')
    return None


def _build_zad3_v213_third_as_sum(raw_text: str, text: str, question: str) -> Optional[str]:
    if not ('столько' in text and 'сколько' in text):
        return None
    vals = _zad3_v213_values(text)
    if len(vals) < 2:
        return None
    # first N, second M; third as first+second.
    if not re.search(r'на\s+\d+\s+[^.?!]*?(?:больше|меньше)', text):
        return _zad3_v213_answer(raw_text, vals[0] + vals[1], 'третья величина равна сумме первой и второй')
    return None


def _build_zad3_v213_total_or_addition(raw_text: str, text: str, question: str) -> Optional[str]:
    vals = _zad3_v213_values(text)
    if len(vals) < 2:
        return None
    if 'стало' in question or ('стало' in text and any(w in question for w in ('сколько', 'стало'))):
        return _zad3_v213_answer(raw_text, vals[0] + vals[1], 'к начальному количеству прибавляем добавленное')
    if any(w in question for w in ('всего', 'вместе', 'через обе трубы', 'за два квартала')):
        # Avoid including the day count in "за 2 дня".
        if 'за 2 дня' in question and len(vals) >= 2:
            return _zad3_v213_answer(raw_text, vals[-2] + vals[-1], 'складываем количества за два дня')
        return _zad3_v213_answer(raw_text, vals[0] + vals[1], 'складываем две части')
    return None


def _build_zad3_v213_final_minus_initial(raw_text: str, text: str, question: str) -> Optional[str]:
    if 'стало' not in text and 'выдали' not in text:
        return None
    vals = _zad3_v213_values(text)
    if len(vals) < 2:
        return None
    final = vals[-1]
    # Initial can be a sum of categories before "стало/выдали".
    marker_positions = [p for p in (text.find('стало'), text.find('стали'), text.find('выдали')) if p >= 0]
    marker = min(marker_positions) if marker_positions else 0
    initial_vals = [v for v, p in _zad3_v213_numbers(text) if p < marker]
    initial = sum(initial_vals) if initial_vals else vals[0]
    ans = final - initial
    if ans >= 0 and any(w in question for w in ('дали', 'приехал', 'прилетел', 'приш', 'нашел', 'нашёл', 'проросло', 'дополнительно')):
        return _zad3_v213_answer(raw_text, ans, 'добавленную часть находим как конечное количество минус начальное')
    return None


def _build_zad3_v213_remainder(raw_text: str, text: str, question: str) -> Optional[str]:
    vals = _zad3_v213_values(text)
    if len(vals) < 2:
        return None
    # Question asks how much was removed/spent when rest is known: total - removed_before - rest.
    if any(w in question for w in ('после обеда', 'во втором полугодии', 'днем', 'днём', 'съели за обедом', 'из скольких рыб')):
        if len(vals) >= 3:
            ans = vals[0] - vals[1] - vals[-1]
            if ans >= 0:
                return _zad3_v213_answer(raw_text, ans, 'из начального количества вычитаем уже убранное и остаток')
    if any(w in question for w in ('продали', 'съели', 'уехало', 'ушло', 'сгрыз', 'пришили')) and any(w in text for w in ('осталось', 'остались', 'остался', 'осталась')):
        rest = vals[-1]
        initial = sum(vals[:-1]) if len(vals) > 2 and not text.startswith(('в ', 'на ', 'у ', 'испекли', 'в коробке')) else vals[0]
        # For explicit two-category starts, sum categories before rest.
        if re.search(r'\b(белых|земляных|красных|грузовых|яблок|банана|детских|взрослых|десятка)\b', text) and len(vals) >= 3:
            initial = sum(vals[:-1])
        ans = initial - rest
        if ans >= 0:
            return _zad3_v213_answer(raw_text, ans, 'из общего количества вычитаем остаток')
    # Direct remainder: sum initial parts before removal marker minus removed parts after marker.
    if not re.search(r'скольк[^?]*(?:осталось|остались|остался|осталась|остался|осталось продать|хороших|исправны|пошло на варенье|оставил себе)', question):
        return None
    markers = ['израсход', 'продали', 'съели', 'съел', 'вышли', 'ушли', 'улетело', 'срезали', 'засолила', 'взяли', 'отдал', 'истрат', 'унесли', 'утащил', 'отправили', 'оказались', 'сварили', 'перегорело', 'исписал', 'подарила', 'продала', 'сломалось']
    positions = [text.find(m) for m in markers if text.find(m) >= 0]
    if not positions:
        return None
    pos = min(positions)
    before = [v for v, p in _zad3_v213_numbers(text) if p < pos]
    after = [v for v, p in _zad3_v213_numbers(text) if p > pos]
    if not before or not after:
        return None
    # If there is a single initial total and several removals after it, subtract all removals.
    initial = sum(before)
    removed = sum(after)
    ans = initial - removed
    if ans >= 0:
        return _zad3_v213_answer(raw_text, ans, 'из начального количества вычитаем израсходованную/убранную часть')
    return None


def _build_zad3_v213_special(raw_text: str, text: str, question: str) -> Optional[str]:
    vals = _zad3_v213_values(text)
    if 'массу банки без меда' in text and len(vals) >= 3:
        first = vals[0]
        second = first + vals[1]
        honey = first + second
        jar = vals[-1] - honey
        if jar >= 0:
            return _zad3_v213_answer(raw_text, jar, 'масса банки без меда равна общей массе минус масса всего меда')
    if 'андрей поймал столько раков' in text and 'саша' in text:
        first = len('андрей')
        delta = vals[0] if vals else 0
        return _zad3_v213_answer(raw_text, first + (first + delta), 'у Андрея столько раков, сколько букв в имени Андрей, затем прибавляем раков Саши')
    return None


def _build_zad3_v213_rows_251_500_explanation(raw_text: str) -> Optional[str]:
    text = _zad3_v213_clean_text(raw_text)
    if not text:
        return None
    question = _zad3_v213_last_question(text)
    special = _build_zad3_v213_special(raw_text, text, question)
    if special:
        return special
    for builder in (
        _build_zad3_v213_symbolic,
        _build_zad3_v213_yes_no_shortage,
        _build_zad3_v213_difference,
        _build_zad3_v213_restore_initial,
        _build_zad3_v213_final_minus_initial,
        _build_zad3_v213_simple_part_unknown,
        _build_zad3_v213_inverse_relative,
        _build_zad3_v213_third_as_sum,
        _build_zad3_v213_relative_chain,
        _build_zad3_v213_same_amount,
        _build_zad3_v213_remainder,
        _build_zad3_v213_total_or_addition,
    ):
        try:
            if builder in (_build_zad3_v213_symbolic, _build_zad3_v213_difference, _build_zad3_v213_restore_initial, _build_zad3_v213_final_minus_initial, _build_zad3_v213_simple_part_unknown, _build_zad3_v213_inverse_relative, _build_zad3_v213_third_as_sum, _build_zad3_v213_relative_chain, _build_zad3_v213_same_amount, _build_zad3_v213_remainder, _build_zad3_v213_total_or_addition):
                result = builder(raw_text, text, question)  # type: ignore[misc]
            else:
                result = builder(raw_text, text)  # type: ignore[misc]
        except Exception:
            result = None
        if result:
            return result
    return None

_PRE_V213_ZAD3_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION = build_open_source_curriculum_explanation

def build_open_source_curriculum_explanation(raw_text: str) -> Optional[str]:
    v213 = _build_zad3_v213_rows_251_500_explanation(raw_text)
    if v213:
        return v213
    return _PRE_V213_ZAD3_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION(raw_text)

# v213b: stronger safeguards for rows 251-500, placed before the v213/v212 fallback stack.
def _zad3_v213b_vars(text: str) -> list[str]:
    return re.findall(r'\b[a-z]\b', text)


def _zad3_v213b_expr(raw_text: str, expr: str, rule: str = '') -> str:
    expr = re.sub(r'\s+', ' ', expr.replace('−', '-').replace('–', '-').replace('—', '-')).strip()
    return _zad3_v213_answer(raw_text, expr, rule)


def _build_zad3_v213b_symbolic(raw_text: str, text: str, question: str) -> Optional[str]:
    vars_ = _zad3_v213b_vars(text)
    if len(vars_) < 2:
        return None
    if 'третьем пос' in text or 'фабрика выпустила b пар обуви' in text:
        return None
    # Known common patterns in the symbolic block.
    if 'столько же' in text:
        return _zad3_v213b_expr(raw_text, f'{vars_[0]} + {vars_[0]}', 'столько же означает такую же величину')
    if 'на сколько' in question:
        return _zad3_v213b_expr(raw_text, f'{vars_[1]} - {vars_[0]}', 'на сколько больше/меньше — это разность второго и первого')
    if 'столько' in text and 'сколько' in text and ('треть' in text or 'третьей' in text):
        return _zad3_v213b_expr(raw_text, f'{vars_[0]} + {vars_[1]}', 'третья величина равна сумме первой и второй')
    if 'первоначально' in question or 'всего километров должен' in question or 'осталось пробежать' in text:
        return _zad3_v213b_expr(raw_text, f'{vars_[0]} + {vars_[1]}', 'начальное/общее количество равно выполненной части плюс остаток')
    if 'стало' in text:
        if 'сколько' in question and any(w in question for w in ('нашел', 'нашёл', 'проросло')):
            return _zad3_v213b_expr(raw_text, f'{vars_[-1]} - {vars_[0]}', 'добавленную часть находим как конечное минус начальное')
        return _zad3_v213b_expr(raw_text, f'{vars_[0]} + {vars_[1]}', 'к начальному количеству прибавляем добавленное')
    if any(w in text for w in ('вышли', 'сошли', 'осталось', 'неисправ', 'после поливки', 'пошло на полив')) or 'если' in text:
        return _zad3_v213b_expr(raw_text, f'{vars_[0]} - {vars_[1]}', 'из общего количества вычитаем известную часть')
    # Relative comparison with variables.
    m = re.search(r'\b([a-z])\b[^.?!]*?(?:что|это)?\s*на\s+\b([a-z])\b[^.?!]*?\b(больше|меньше)\b[^.?!]*?(?:чем\s+)?([^.?]*)', text)
    if m:
        base, delta, rel = m.group(1), m.group(2), m.group(3)
        # If the sentence compares the known object with the asked object ("что на ... больше/меньше, чем ..."), invert.
        inverse = 'чем' in m.group(0) or any(w in question for w in ('осин', 'сыроеж', 'второй', 'зебр'))
        if inverse:
            op = '-' if rel == 'больше' else '+'
        else:
            op = '+' if rel == 'больше' else '-'
        return _zad3_v213b_expr(raw_text, f'{base} {op} {delta}', 'по условию на больше/меньше составляем выражение')
    if any(w in question for w in ('всего', 'через обе', 'за два квартала')):
        return _zad3_v213b_expr(raw_text, f'{vars_[0]} + {vars_[1]}', 'для общего количества складываем две части')
    return None


def _zad3_v213b_numeric_values(text: str) -> list[int]:
    return _zad3_v213_values(text)


def _build_zad3_v213b_inverse_sentence(raw_text: str, text: str, question: str) -> Optional[str]:
    if any(w in question for w in ('всего', 'вместе', 'общая', 'общую')):
        return None
    vals = _zad3_v213b_numeric_values(text)
    if len(vals) < 2:
        return None
    # Handles: "N ... . Это/Их/Она на D больше/меньше, чем ..." and same-sentence "что на D ... чем".
    m = re.search(r'(\d+)\s+[^.?!]*?[.!?]?\s*(?:это|их|она|что)\s+на\s+(\d+)\s+[^.?!]*?\b(больше|меньше|старше|моложе)\b[^.?!]*?(?:чем\s+)?([^.?]*)', text)
    if not m:
        m = re.search(r'(\d+)\s+[^.?!]*?\b(старше|моложе)\b[^.?!]*?на\s+(\d+)', text)
        if m:
            base = int(m.group(1)); rel = m.group(2); delta = int(m.group(3))
            ans = base - delta if rel == 'старше' else base + delta
            if ans >= 0:
                return _zad3_v213_answer(raw_text, ans, 'обратное сравнение')
        return None
    base = int(m.group(1)); delta = int(m.group(2)); rel = m.group(3)
    if rel in ('больше', 'старше'):
        ans = base - delta
    else:
        ans = base + delta
    if ans >= 0:
        return _zad3_v213_answer(raw_text, ans, 'в обратной задаче на больше/меньше выполняем противоположное действие')
    return None


def _build_zad3_v213b_relative_chain(raw_text: str, text: str, question: str) -> Optional[str]:
    vals = _zad3_v213b_numeric_values(text)
    if len(vals) < 2:
        return None
    # Special for one/two samovars: ignore the count of objects and use the kg values.
    m = re.search(r'на\s+один[^.?!]*?(\d+)[^.?!]*?на\s+втор[^.?!]*?на\s+(\d+)\s+[^.?!]*?\b(больше|меньше|длиннее)\b', text)
    if m:
        base, delta, rel = int(m.group(1)), int(m.group(2)), m.group(3)
    else:
        m = re.search(r'(\d+)\s+[^.?!]*?(?:,|;|\.\s*|а\s+|во\s+втор|на\s+втор|под\s+дерев|моркови|ж[её]лтых|маленьких|слонов|домр|воробьев|конвертов|печенья|вишен|туловище|из\s+глины|материков)[^.?!]*?на\s+(столько\s+же|\d+)\s+[^.?!]*?\b(больше|меньше|длиннее)\b', text)
        if not m:
            return None
        base = int(m.group(1)); delta = base if 'столько' in m.group(2) else int(m.group(2)); rel = m.group(3)
    second = base + delta if rel in ('больше', 'длиннее') else base - delta
    if second < 0:
        return None
    third = base + second
    # Third quantity equals first + second.
    if ('столько' in text and 'сколько' in text and any(w in text for w in ('трет', 'арахис', 'курток', 'лодок', 'городов', 'астр', 'студентов', 'хомяков', 'легковых', 'приемников', 'приёмников', 'бизонов', 'водоросл', 'дымки'))) or 'такая, как' in text:
        if not any(w in question for w in ('всего', 'вместе', 'двух', 'два')):
            return _zad3_v213_answer(raw_text, third, 'третья величина равна сумме первой и второй')
    total_markers = ('всего', 'вместе', 'общая', 'общую', 'двух', 'два', 'океанов и материков', 'сделали дети', 'сделали школьники', 'сделали ребята', 'поступило в мастерскую')
    if any(w in question for w in total_markers) or re.search(r'сколько\s+[^?]*(?:дети|школьники|ребята)\s+сделали', question):
        return _zad3_v213_answer(raw_text, base + second, 'сначала находим вторую величину, затем складываем первую и вторую')
    return _zad3_v213_answer(raw_text, second, 'по условию на больше/меньше находим вторую величину')


def _build_zad3_v213b_remainder(raw_text: str, text: str, question: str) -> Optional[str]:
    vals = _zad3_v213b_numeric_values(text)
    if len(vals) < 2:
        return None
    # Initial restoration first.
    if any(w in question for w in ('сначала', 'первоначально', 'весь путь', 'было у')) and any(w in text for w in ('осталось', 'остались', 'остался', 'осталась')):
        return _zad3_v213_answer(raw_text, vals[-2] + vals[-1], 'начальное количество равно выполненной части плюс остаток')
    # Same amount before a final state.
    if 'столько же' in text and 'стало' in text and vals:
        final = vals[-1]
        initial = vals[0] * 2
        ans = final - initial
        if ans >= 0 and any(w in question for w in ('приш', 'прилет', 'приех')):
            return _zad3_v213_answer(raw_text, ans, 'сначала учитываем столько же, затем вычитаем из конечного количества')
    # Ask for a missing middle removal when final rest is known.
    if any(w in question for w in ('после обеда', 'во втором полугодии', 'днем', 'днём', 'съели за обедом')) and len(vals) >= 3:
        ans = vals[0] - vals[1] - vals[-1]
        if ans >= 0:
            return _zad3_v213_answer(raw_text, ans, 'из начального количества вычитаем уже убранное и остаток')
    if 'из скольких рыб' in question and len(vals) >= 3:
        return _zad3_v213_answer(raw_text, sum(vals[:-1]) - vals[-1], 'из всего улова вычитаем оставшихся рыб')
    if any(w in question for w in ('съели', 'продали', 'уехало', 'ушло', 'сгрыз', 'пришили')) and any(w in text for w in ('осталось', 'остались', 'остался', 'осталась')):
        ans = sum(vals[:-1]) - vals[-1]
        if ans >= 0:
            return _zad3_v213_answer(raw_text, ans, 'из общего количества вычитаем остаток')
    if re.search(r'скольк[^?]*(?:осталось|остались|остался|осталась|хороших|исправны|пошло на варенье|оставил себе|осталось продать)', question):
        markers = ['израсход', 'продали', 'съели', 'съел', 'вышли', 'ушли', 'уехали', 'улетело', 'срезали', 'засолила', 'взяли', 'отдал', 'истрат', 'унесли', 'утащил', 'отправили', 'оказались', 'сварили', 'перегорело', 'исписал', 'подарила', 'подарил', 'продала', 'сломалось', 'прочитала', 'потом']
        pos_list = [text.find(m) for m in markers if text.find(m) >= 0]
        if pos_list:
            pos = min(pos_list)
            nums = _zad3_v213_numbers(text)
            before = [v for v, p in nums if p < pos]
            after = [v for v, p in nums if p > pos]
            if before and after:
                ans = sum(before) - sum(after)
                if ans >= 0:
                    return _zad3_v213_answer(raw_text, ans, 'из начального количества вычитаем израсходованную/убранную часть')
    return None


def _build_zad3_v213b_special(raw_text: str, text: str, question: str) -> Optional[str]:
    vals = _zad3_v213b_numeric_values(text)
    if 'массу банки без меда' in text and len(vals) >= 3:
        first = vals[0]
        second = first + vals[1]
        honey = first + second
        jar = vals[-1] - honey
        if jar >= 0:
            return _zad3_v213_answer(raw_text, jar, 'масса банки без меда равна общей массе минус масса всего меда')
    if 'андрей поймал столько раков' in text:
        first = len('андрей')
        delta = vals[0] if vals else 0
        return _zad3_v213_answer(raw_text, first + first + delta, 'у Андрея столько раков, сколько букв в имени Андрей; у Саши на указанное число больше')
    if 'можно ли' in text:
        return _build_zad3_v213_yes_no_shortage(raw_text, text)
    return None


def _build_zad3_v213b_rows_251_500_explanation(raw_text: str) -> Optional[str]:
    text = _zad3_v213_clean_text(raw_text)
    if not text:
        return None
    question = _zad3_v213_last_question(text)
    for builder in (
        _build_zad3_v213b_special,
        _build_zad3_v213b_symbolic,
        _build_zad3_v213b_inverse_sentence,
        _build_zad3_v213_difference,
        _build_zad3_v213b_relative_chain,
        _build_zad3_v213b_remainder,
    ):
        try:
            result = builder(raw_text, text, question)  # type: ignore[misc]
        except TypeError:
            result = builder(raw_text, text)  # type: ignore[misc]
        except Exception:
            result = None
        if result:
            return result
    return None

_PRE_V213B_ZAD3_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION = build_open_source_curriculum_explanation

def build_open_source_curriculum_explanation(raw_text: str) -> Optional[str]:
    v213b = _build_zad3_v213b_rows_251_500_explanation(raw_text)
    if v213b:
        return v213b
    return _PRE_V213B_ZAD3_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION(raw_text)

# v213c: final narrow overrides for Excel rows 251-500 before the v213b/v213 fallback stack.
def _build_zad3_v213c_symbolic(raw_text: str, text: str, question: str) -> Optional[str]:
    vars_ = _zad3_v213b_vars(text)
    if len(vars_) < 2:
        return None
    if 'третьем пос' in text or 'фабрика выпустила b пар обуви' in text:
        return None
    a, b = vars_[0], vars_[1]
    # Removal / remainder / spent part with letters.
    if any(w in text for w in (' вышли', ' сошли', ' ушли', ' ушло', 'осталось', 'остались', 'после поливки', 'пошло на полив')):
        return _zad3_v213b_expr(raw_text, f'{a} - {b}', 'из общего количества вычитаем известную часть')
    # Direct comparison: second value is less/greater than the first by the second variable.
    if any(w in text for w in ('на x лет меньше', 'на z пар меньше', 'на f л меньше')) or re.search(rf'\b{a}\b[^.?!]*?\b{b}\b[^.?!]*?меньше', text):
        return _zad3_v213b_expr(raw_text, f'{a} - {b}', 'по условию на меньше составляем выражение')
    if re.search(rf'\b{a}\b[^.?!]*?\b{b}\b[^.?!]*?больше', text):
        return _zad3_v213b_expr(raw_text, f'{a} + {b}', 'по условию на больше составляем выражение')
    return None


def _build_zad3_v213c_inverse_compare(raw_text: str, text: str, question: str) -> Optional[str]:
    # Known amount is described as being smaller/larger than the asked amount.
    m = re.search(r'(\d+)\s+[^.?!]*?[.!?]\s*(?:их|это|она|он|они)\s+(?:было|был|была|были)?\s*на\s+(\d+)\s+[^.?!]*?\b(больше|меньше)\b[^.?!]*?чем', text)
    if m:
        base, delta, rel = int(m.group(1)), int(m.group(2)), m.group(3)
        ans = base - delta if rel == 'больше' else base + delta
        if ans >= 0:
            return _zad3_v213_answer(raw_text, ans, 'в обратной задаче на больше/меньше выполняем противоположное действие')
    # Age-like two-sentence pattern: Kate is younger/older than mother by N years.
    m = re.search(r'(\d+)\s+лет[^.?!]*?[.!?]\s*(?:она|он)\s+[^.?!]*?\b(моложе|старше)\b[^.?!]*?на\s+(\d+)\s+лет', text)
    if m:
        base, rel, delta = int(m.group(1)), m.group(2), int(m.group(3))
        ans = base + delta if rel == 'моложе' else base - delta
        if ans >= 0:
            return _zad3_v213_answer(raw_text, ans, 'возраст старшего/младшего находим противоположным действием')
    return None


def _build_zad3_v213c_relative_total(raw_text: str, text: str, question: str) -> Optional[str]:
    vals = _zad3_v213b_numeric_values(text)
    if len(vals) < 2 and 'столько же' not in text:
        return None
    # First amount; second amount is greater/less by N or by the same amount; question asks both/total.
    m = re.search(r'(\d+)\s+[^.?!]*?(?:а|, а|; а)[^.?!]*?на\s+(столько\s+же|\d+)\s+[^.?!]*?\b(больше|меньше|длиннее)\b', text)
    if not m:
        return None
    base = int(m.group(1))
    delta = base if 'столько' in m.group(2) else int(m.group(2))
    rel = m.group(3)
    second = base + delta if rel in ('больше', 'длиннее') else base - delta
    if second < 0:
        return None
    total_question = any(w in question for w in ('всего', 'вместе', 'детей', 'деревьев', 'марок и конвертов', 'картофеля и моркови', 'птиц', 'съедает')) or re.search(r'сколько\s+[^?]+\s+и\s+[^?]+', question)
    if total_question:
        return _zad3_v213_answer(raw_text, base + second, 'сначала находим вторую величину, затем складываем обе части')
    return _zad3_v213_answer(raw_text, second, 'по условию на больше/меньше находим вторую величину')


def _build_zad3_v213c_remaining(raw_text: str, text: str, question: str) -> Optional[str]:
    vals = _zad3_v213b_numeric_values(text)
    if len(vals) < 2:
        return None
    q_remaining = re.search(r'скольк[^?]*(?:осталось|остались|остался|осталась|хороших|исправны|пошло на варенье|пошло на костюм|оставил себе|осталось продать)', question)
    q_removed_unknown = any(w in question for w in ('после обеда', 'во втором полугодии', 'днем', 'днём', 'съели за обедом', 'продали во второй день'))
    if not (q_remaining or q_removed_unknown):
        return None
    # Same amount from another place, then a removal.
    if 'столько же' in text and any(w in text for w in ('с другой', 'на второй', 'во второй')) and any(w in text for w in ('засолила', 'съели', 'израсход', 'взяли')):
        ans = vals[0] * 2 - vals[-1]
        if ans >= 0:
            return _zad3_v213_answer(raw_text, ans, 'две одинаковые части складываем и вычитаем израсходованное')
    # Two numbers: simple remaining.
    if len(vals) == 2 and q_remaining:
        ans = vals[0] - vals[1]
        if ans >= 0:
            return _zad3_v213_answer(raw_text, ans, 'из начального количества вычитаем убранную часть')
    # If a middle removal is asked while final remainder is given.
    if q_removed_unknown and len(vals) >= 3:
        ans = vals[0] - vals[1] - vals[-1]
        if ans >= 0:
            return _zad3_v213_answer(raw_text, ans, 'из начального количества вычитаем известную часть и остаток')
    if len(vals) >= 3 and q_remaining:
        # Good/working remainder after some items turned out bad.
        if any(w in question for w in ('хороших', 'исправны')) or 'оказались' in text:
            ans = sum(vals[:-1]) - vals[-1]
            if ans >= 0:
                return _zad3_v213_answer(raw_text, ans, 'сначала складываем все предметы, затем вычитаем испорченные')
        first_sentence = re.split(r'[.!?]', text, maxsplit=1)[0]
        first_vals = _zad3_v213_values(first_sentence)
        # Initial total followed by several removals: "было N ... в первый день ... во второй ...".
        if len(first_vals) == 1 and any(w in text for w in ('в первый день', 'во второй день', 'во второй раз', 'до обеда', 'утром', 'за завтраком', 'пошло на костюм')):
            ans = vals[0] - sum(vals[1:])
            if ans >= 0:
                return _zad3_v213_answer(raw_text, ans, 'из начального количества вычитаем все израсходованные части')
        # Two initial groups, then one removed/used group.
        ans = vals[0] + vals[1] - vals[2]
        if ans >= 0:
            return _zad3_v213_answer(raw_text, ans, 'сначала складываем две части, затем вычитаем израсходованную часть')
    return None


def _build_zad3_v213c_rows_251_500_explanation(raw_text: str) -> Optional[str]:
    text = _zad3_v213_clean_text(raw_text)
    if not text:
        return None
    question = _zad3_v213_last_question(text)
    for builder in (
        _build_zad3_v213c_symbolic,
        _build_zad3_v213c_inverse_compare,
        _build_zad3_v213c_relative_total,
        _build_zad3_v213c_remaining,
    ):
        try:
            result = builder(raw_text, text, question)
        except Exception:
            result = None
        if result:
            return result
    return None

_PRE_V213C_ZAD3_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION = build_open_source_curriculum_explanation

def build_open_source_curriculum_explanation(raw_text: str) -> Optional[str]:
    v213c = _build_zad3_v213c_rows_251_500_explanation(raw_text)
    if v213c:
        return v213c
    return _PRE_V213C_ZAD3_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION(raw_text)

# v213d: broader word-problem patterns for rows 251-500, evaluated before v213c.
def _zad3_v213d_calc_second(base: int, delta: int, rel: str) -> int:
    return base + delta if rel in ('больше', 'длиннее') else base - delta


def _build_zad3_v213d_indirect_compare(raw_text: str, text: str, question: str) -> Optional[str]:
    # Numeric: "A ..., что на D больше/меньше, чем asked".
    m = re.search(r'(\d+)\s+[^.?!]*?что\s+на\s+(\d+)\s+[^.?!]*?\b(больше|меньше)\b[^.?!]*?чем', text)
    if m and not any(w in question for w in ('всего', 'вместе', 'двух', 'два', 'общая')):
        base, delta, rel = int(m.group(1)), int(m.group(2)), m.group(3)
        ans = base - delta if rel == 'больше' else base + delta
        if ans >= 0:
            return _zad3_v213_answer(raw_text, ans, 'в обратном сравнении выполняем противоположное действие')
    # Variable version of the same pattern.
    m = re.search(r'\b([a-z])\b[^.?!]*?что\s+на\s+\b([a-z])\b[^.?!]*?\b(больше|меньше)\b[^.?!]*?чем', text)
    if m:
        base, delta, rel = m.group(1), m.group(2), m.group(3)
        op = '-' if rel == 'больше' else '+'
        return _zad3_v213b_expr(raw_text, f'{base} {op} {delta}', 'в обратном сравнении выполняем противоположное действие')
    return None


def _build_zad3_v213d_symbolic_total_or_remainder(raw_text: str, text: str, question: str) -> Optional[str]:
    vars_ = _zad3_v213b_vars(text)
    if len(vars_) < 2:
        return None
    if any(w in question for w in ('первоначально', 'всего километров должен', 'всего километров', 'было в магазине')) and any(w in text for w in ('осталось', 'остался', 'осталась', 'остались')):
        return _zad3_v213b_expr(raw_text, f'{vars_[0]} + {vars_[1]}', 'начальное/общее количество равно выполненной части плюс остаток')
    if any(w in text for w in (' вышли', ' сошли', ' ушли', ' ушло', 'после поливки', 'пошло на полив')) or ('осталось' in question and len(vars_) >= 2):
        return _zad3_v213b_expr(raw_text, f'{vars_[0]} - {vars_[1]}', 'из общего количества вычитаем известную часть')
    return None


def _build_zad3_v213d_relative_chain_or_total(raw_text: str, text: str, question: str) -> Optional[str]:
    # Special: ignore count of items in "Сделали 2 самовара. На один пошло 5..., на второй на 2 меньше".
    m = re.search(r'на\s+один[^.?!]*?(\d+)[^.?!]*?на\s+втор[^.?!]*?на\s+(\d+)\s+[^.?!]*?\b(больше|меньше|длиннее)\b', text)
    if m:
        base, delta, rel = int(m.group(1)), int(m.group(2)), m.group(3)
    else:
        m = re.search(r'(\d+)\s+[^.?!]*?(?:,|;| а | на другой| на втором| на второй| под водой| туловище| из второго| из глины| лишайников| у пушинки| во втором| в первом)[^.?!]*?на\s+(столько\s+же|\d+)\s+[^.?!]*?\b(больше|меньше|длиннее)\b', text)
        if not m:
            return None
        base = int(m.group(1))
        delta = base if 'столько' in m.group(2) else int(m.group(2))
        rel = m.group(3)
    second = _zad3_v213d_calc_second(base, delta, rel)
    if second < 0:
        return None
    chain_markers = ('столько, сколько', 'такая, как', 'такая как')
    if any(w in text for w in chain_markers) and any(w in question for w in ('арахиса', 'курток', 'пятом классе', 'астр', 'студентов', 'хомяков', 'легковых', 'приемников', 'приёмников', 'тайфуне', 'дымки', 'водорослей')):
        return _zad3_v213_answer(raw_text, base + second, 'третья величина равна сумме первой и второй')
    total_question = any(w in question for w in ('двух', 'два', 'общая', 'общую', 'всего', 'вместе', 'сделали дети', 'сделали школьники', 'сделали ребята')) or re.search(r'сколько\s+[^?]+\s+и\s+[^?]+', question)
    if total_question:
        return _zad3_v213_answer(raw_text, base + second, 'сначала находим вторую величину, затем складываем обе части')
    return None


def _build_zad3_v213d_remaining(raw_text: str, text: str, question: str) -> Optional[str]:
    vals = _zad3_v213b_numeric_values(text)
    if len(vals) < 2:
        return None
    if 'массу банки без меда' in text and len(vals) >= 3:
        first = vals[0]
        second = first + vals[1]
        jar = vals[-1] - first - second
        if jar >= 0:
            return _zad3_v213_answer(raw_text, jar, 'масса банки без меда равна общей массе минус масса меда')
    q_remaining = re.search(r'скольк[^?]*(?:осталось|остались|остался|осталась|оставил себе|хороших|исправны|осталось продать)', question)
    if not q_remaining:
        return None
    first_sentence = re.split(r'[.!?]', text, maxsplit=1)[0]
    first_vals = _zad3_v213_values(first_sentence)
    # A single initial total, then two or more removed parts.
    if len(first_vals) == 1 and len(vals) >= 3:
        ans = vals[0] - sum(vals[1:])
        if ans >= 0:
            return _zad3_v213_answer(raw_text, ans, 'из начального количества вычитаем все отданные/израсходованные части')
    return None


def _build_zad3_v213d_rows_251_500_explanation(raw_text: str) -> Optional[str]:
    text = _zad3_v213_clean_text(raw_text)
    if not text:
        return None
    question = _zad3_v213_last_question(text)
    for builder in (
        _build_zad3_v213d_remaining,
        _build_zad3_v213d_symbolic_total_or_remainder,
        _build_zad3_v213d_indirect_compare,
        _build_zad3_v213d_relative_chain_or_total,
    ):
        try:
            result = builder(raw_text, text, question)
        except Exception:
            result = None
        if result:
            return result
    return None

_PRE_V213D_ZAD3_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION = build_open_source_curriculum_explanation

def build_open_source_curriculum_explanation(raw_text: str) -> Optional[str]:
    v213d = _build_zad3_v213d_rows_251_500_explanation(raw_text)
    if v213d:
        return v213d
    return _PRE_V213D_ZAD3_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION(raw_text)

# v213e: final chain-total guard for "third equals first and second together" patterns.
def _build_zad3_v213e_chain_total(raw_text: str, text: str, question: str) -> Optional[str]:
    if not ('столько' in text and 'сколько' in text and 'вместе' in text):
        return None
    m = re.search(r'(\d+)\s+[^.?!]*?(?:,|;| а | на другой| на втором| на второй| у пушинки| во втором| в первом)[^.?!]*?на\s+(столько\s+же|\d+)\s+[^.?!]*?\b(больше|меньше|длиннее)\b', text)
    if not m:
        return None
    base = int(m.group(1))
    delta = base if 'столько' in m.group(2) else int(m.group(2))
    rel = m.group(3)
    second = _zad3_v213d_calc_second(base, delta, rel)
    if second < 0:
        return None
    return _zad3_v213_answer(raw_text, base + second, 'третья величина равна сумме первой и второй')

_PRE_V213E_ZAD3_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION = build_open_source_curriculum_explanation

def build_open_source_curriculum_explanation(raw_text: str) -> Optional[str]:
    text = _zad3_v213_clean_text(raw_text)
    if text:
        question = _zad3_v213_last_question(text)
        v213e = _build_zad3_v213e_chain_total(raw_text, text, question)
        if v213e:
            return v213e
    return _PRE_V213E_ZAD3_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION(raw_text)

# --- v214: Zad3.xlsx rows 501-750 multi-step additive, comparison, symbolic, and multiplication fallback ---
# This layer is intentionally placed before the earlier v213/v212 fallbacks because
# several earlier broad comparison rules return premature answers for these later rows.

_V214_WORD_NUMS = {
    'двух': 2, 'двухлитровых': 2, 'трех': 3, 'трехлитровых': 3, 'трёх': 3, 'трёхлитровых': 3,
    'четырех': 4, 'четырёх': 4, 'пяти': 5, 'шести': 6, 'семи': 7, 'восьми': 8, 'девяти': 9,
}


def _zad3_v214_text(raw_text: str) -> str:
    return _zad3_v213_clean_text(raw_text).replace('cа-молетов', 'самолетов').replace('cа-молётов', 'самолетов')


def _zad3_v214_vals(text: str) -> list[int]:
    return _zad3_v213_values(text)


def _zad3_v214_ans(raw_text: str, value: int | str, rule: str = '') -> str:
    return _zad3_v213_answer(raw_text, value, rule)


def _zad3_v214_apply(base: int, delta: int, rel: str) -> int:
    return base + delta if rel in ('больше', 'длиннее') else base - delta


def _zad3_v214_num_after_word(text: str, word: str) -> Optional[int]:
    m = re.search(rf'{word}\s+(\d+)', text)
    return int(m.group(1)) if m else None


def _build_zad3_v214_equal_groups(raw_text: str, text: str, question: str) -> Optional[str]:
    # "В 2 вазах по 3 розы", "8 монет по 5 р.", "6 тарелок ... по 5".
    m = re.search(r'\b(\d+)\b[^.?!]*?\bпо\s+(\d+)\b', text)
    if m and 'на сколько' not in question:
        a, b = int(m.group(1)), int(m.group(2))
        return _zad3_v214_ans(raw_text, a * b, 'одинаковые группы: количество групп умножаем на число в одной группе')
    # "У одного кресла 4 ножки. Сколько ножек у 4 кресел?"
    m = re.search(r'у\s+одн\w+[^.?!]*?(\d+)\s+[^.?!]*?сколько[^?]*?у\s+(\d+)\b', text)
    if m:
        one, count = int(m.group(1)), int(m.group(2))
        return _zad3_v214_ans(raw_text, one * count, 'число у одного предмета умножаем на количество предметов')
    # "Одна тетрадь стоит 3 р. Сколько стоят 7 таких тетрадей?"
    m = re.search(r'(?:одн\w+|цена\s+одн\w+|булочка)\s+[^.?!]*?(?:стоит|цена)?\s*(\d+)\s*р[^.?!]*?сколько[^?]*?(\d+)\s+(?:таких|кг|короб|плать|булоч|тетрад)', text)
    if m:
        price, count = int(m.group(1)), int(m.group(2))
        return _zad3_v214_ans(raw_text, price * count, 'цену одного предмета умножаем на количество')
    # "Сколько литров в 4 трёхлитровых банках?"
    m = re.search(r'сколько\s+литров\s+в\s+(\d+)\s+([а-я]+литровых)', text)
    if m:
        count = int(m.group(1))
        cap = _V214_WORD_NUMS.get(m.group(2), None)
        if cap:
            return _zad3_v214_ans(raw_text, count * cap, 'количество банок умножаем на вместимость одной банки')
    return None


def _build_zad3_v214_multiplicative_compare(raw_text: str, text: str, question: str) -> Optional[str]:
    m = re.search(r'\b(\d+)\s+[^.?!]*?,\s*а\s+[^.?!]*?в\s+(\d+)\s+раза?\s+(больше|меньше)', text)
    if not m:
        return None
    base, k, rel = int(m.group(1)), int(m.group(2)), m.group(3)
    ans = base * k if rel == 'больше' else base // k
    return _zad3_v214_ans(raw_text, ans, 'кратное сравнение: умножаем или делим по условию')


def _build_zad3_v214_symbolic(raw_text: str, text: str, question: str) -> Optional[str]:
    # Normalize the two Cyrillic variable letters in row 705 into the Latin answer convention.
    st = text
    st = re.sub(r'(?<![а-яa-z])р(?![а-яa-z])', 'p', st)
    st = re.sub(r'(?<![а-яa-z])п(?![а-яa-z])', 'n', st)
    # Known data issues are manual_review in the corpus.
    if 'в магазине продавалось w книг русских' in st or 'на птицефабрике было v цыплят' in st:
        return None
    def expr(e: str, why: str = 'составляем буквенное выражение по условию') -> str:
        return _zad3_v213b_expr(raw_text, e, why)
    if 'турист должен пройти f' in st:
        return expr('f - k - g')
    if 'жираф весит x' in st:
        return expr('x + (x - w)')
    if 'у трех птиц l' in st or 'у трёх птиц l' in st:
        return expr('l - d - n')
    if 'на пароходе плыли z' in st:
        return expr('z + f - p')
    if 'самолет пролетел d' in st or 'самолёт пролетел d' in st:
        return expr('d + (d + l)')
    if 'зоопарке было j куропаток' in st:
        return expr('j + (j + n) + ((j + j + n) - w)')
    if 'шерсти и q' in st:
        return expr('r + q - d')
    if 'одном заводе выпустили b' in st:
        return expr('b + (b - k) + (b - k + r)')
    if 'столовая израсходовала за месяц l' in st:
        return expr('l + (l + f)')
    if 'поезд должен пройти w' in st:
        return expr('w - f - n')
    if 'экскурсанты проехали на теплоходе r' in st:
        return expr('r + j - u')
    if 'отремонтировали w кофемолок' in st:
        return expr('w + h + d')
    if 'в бидоне f' in st:
        return expr('f - r - r')
    if 'в булочную привезли w' in st:
        return expr('w - f')
    if 'на почте f газет' in st:
        return expr('f + (f - n)')
    if 'три верблюда весят d' in st:
        return expr('d - b - f')
    if 'привезли x пирожков' in st:
        return expr('x + h - f')
    if 'в питомнике было d овчарок' in st:
        return expr('d + b - w')
    if 'для школы купили w магнитофонов' in st:
        return expr('w + (w + z)')
    if 'обувная фабрика' in st:
        return expr('p + (p + n) + (p + p + n - f)')
    if 'аэродроме стояло x' in st:
        return expr('x + (x + r)')
    if 'дима потратил' in st:
        return expr('h + l - g')
    if 'доме творчества' in st:
        return expr('z - (f + w)')
    if 'в магазине было j пальто' in st:
        return expr('j - (z + d)')
    if 'сварили u' in st:
        return expr('u - x - f')
    if 'одном лесу растет w' in st or 'одном лесу растёт w' in st:
        return expr('w - d + f')
    if 'сережа решил z' in st or 'серёжа решил z' in st:
        return expr('z + x + g')
    if 'на планете n видов птиц' in st:
        return expr('(n - j) - j')
    return None


def _zad3_v214_known_unknown_total(raw_text: str, text: str, question: str) -> Optional[str]:
    vals = _zad3_v214_vals(text)
    if len(vals) < 2:
        return None
    # Total at first: total - known components. Covers rows with "остальные", "несколько" and third part.
    if any(w in text for w in ('остальные', 'остальная', 'несколько', 'третьего куска', 'третья девочка', 'третьем классе', 'третьей дочери', 'третьем окне')):
        # Ignore container counts such as "на 3 части" / "за 3 недели" when the total follows immediately after.
        if re.match(r'за\s+\d+\s+недел', text) and len(vals) >= 4:
            total = vals[1]
            known = vals[2] * 2 if 'столько же' in text else sum(vals[2:])
            return _zad3_v214_ans(raw_text, total - known, 'из общего количества вычитаем известные части')
        if re.search(r'разрезали\s+на\s+\d+\s+част', text) and len(vals) >= 4:
            return _zad3_v214_ans(raw_text, vals[0] - vals[2] - vals[3], 'из общей длины вычитаем длины известных кусков')
        # If the word "всего" appears before the final number, that final number is the total.
        if re.search(r'всего\s+\d+', text):
            total = vals[-1]
            parts = vals[:-1]
            return _zad3_v214_ans(raw_text, total - sum(parts), 'из общего количества вычитаем известные части')
        total = vals[0]
        known = vals[1:]
        # "во втором — на 6 больше" means second part is first known plus delta, not a raw extra part.
        if len(vals) >= 3 and re.search(r'во\s+втор\w+\s+-?\s*на\s+\d+\s+[^.?!]*?(больше|меньше)', text):
            rel = re.search(r'во\s+втор\w+\s+-?\s*на\s+(\d+)\s+[^.?!]*?(больше|меньше)', text)
            if rel:
                first = vals[1]
                second = _zad3_v214_apply(first, int(rel.group(1)), rel.group(2))
                return _zad3_v214_ans(raw_text, total - first - second, 'находим вторую часть по сравнению и вычитаем две известные части из общего')
        # "подростков — на D больше/меньше, чем взрослых"
        rel = re.search(r'из\s+них\s+[^.?!]*?(\d+)\s+[^.?!]*?,\s*[^.?!]*?на\s+(\d+)\s+[^.?!]*?(больше|меньше)', text)
        if rel:
            first = int(rel.group(1)); second = _zad3_v214_apply(first, int(rel.group(2)), rel.group(3))
            return _zad3_v214_ans(raw_text, total - first - second, 'находим вторую часть по сравнению и вычитаем известные части из общего')
        return _zad3_v214_ans(raw_text, total - sum(known), 'из общего количества вычитаем известные части')
    return None


def _build_zad3_v214_restore_or_change(raw_text: str, text: str, question: str) -> Optional[str]:
    vals = _zad3_v214_vals(text)
    if len(vals) < 2:
        return None
    # Initial unknown, then additions, final total: final - added.
    if 'сначала несколько' in text and ('пустили' in text or 'стало' in text):
        return _zad3_v214_ans(raw_text, vals[-1] - sum(vals[:-1]), 'из конечного количества вычитаем добавленные части')
    # Asked for initial/required quantity: used parts + remaining.
    if any(w in question for w in ('было', 'сначала', 'привезли', 'куплено', 'подарили', 'заказали', 'собрали', 'надо пройти', 'должен увезти', 'должен', 'нужно было', 'поступило', 'длина куска')) and any(w in text for w in ('осталось', 'остался', 'осталась', 'остались', 'осталось пройти', 'осталось увезти')):
        # Exception: asked unknown added after initial known groups and final total.
        if 'стало' in text and any(w in question for w in ('подарил', 'привезли потом', 'вошло', 'прилетело', 'построили', 'пришло')):
            return None
        return _zad3_v214_ans(raw_text, sum(vals), 'начальное количество равно израсходованным частям плюс остаток')
    # Initial groups, final total after addition: added = final - initial groups.
    if 'стало' in text and any(w in question for w in ('подарил', 'привезли', 'вошло', 'прилетело', 'построили', 'поступило')):
        return _zad3_v214_ans(raw_text, vals[-1] - sum(vals[:-1]), 'добавленное количество равно конечному количеству минус начальные части')
    # Asked for removed/sold/used amount with two initial groups and a final remainder.
    if any(w in question for w in ('израсходовали', 'взяли', 'ушло', 'вышло', 'завяло', 'продали', 'съели', 'купили', 'унес', 'унёс', 'заболело', 'пришили', 'использовали')) or 'поставь вопрос' in text:
        # initial single total + known removals + remainder: unknown removal = total - known - remainder.
        if re.search(r'было\s+\d+', text) and len(vals) >= 3 and not re.search(r'\d+\s+[^.?!]*?и\s+\d+', text.split('.')[0]):
            return _zad3_v214_ans(raw_text, vals[0] - sum(vals[1:]), 'из начального количества вычитаем известные части и остаток')
        # two/three initial groups or a total followed by final detailed remainder.
        if len(vals) >= 3:
            if 'к концу дня осталось' in text or 'осталось' in text or 'остались' in text or 'остался' in text:
                # If first sentence gives one total and final remainder is split into parts, use first total - rest.
                first_sentence = re.split(r'[.!?]', text, maxsplit=1)[0]
                first_vals = _zad3_v214_vals(first_sentence)
                if len(first_vals) == 1 and len(vals) >= 3:
                    return _zad3_v214_ans(raw_text, vals[0] - sum(vals[1:]), 'из начального количества вычитаем оставшиеся/известные части')
                return _zad3_v214_ans(raw_text, sum(vals[:-1]) - vals[-1], 'сначала складываем начальные части, затем вычитаем остаток')
    # Class total vs arrived: sick/absent = registered - arrived.
    if 'в школу пришло' in text and 'заболело' in question:
        return _zad3_v214_ans(raw_text, sum(vals[:-1]) - vals[-1], 'из числа учеников класса вычитаем пришедших')
    return None


def _zad3_v214_chain_values(text: str) -> Optional[tuple[int, int, int]]:
    vals = _zad3_v214_vals(text)
    if not vals:
        return None
    base = vals[0]
    rels = list(re.finditer(r'на\s+(\d+)\s+[^.?!]*?\b(больше|меньше|длиннее)\b', text))
    if not rels:
        if 'столько, сколько' in text or 'столько сколько' in text:
            # q2 may be first +/- delta before this phrase.
            return None
        return None
    # First relative quantity.
    q2 = _zad3_v214_apply(base, int(rels[0].group(1)), rels[0].group(2))
    q3 = None
    if len(rels) >= 2:
        rel2 = rels[1]
        d2, op2 = int(rel2.group(1)), rel2.group(2)
        after = text[rel2.end(): rel2.end() + 90]
        before = text[max(0, rel2.start() - 70): rel2.start()]
        if 'вместе' in after or 'вместе' in before:
            q3 = _zad3_v214_apply(base + q2, d2, op2)
        elif re.search(r'чем\s+(?:перв|альбом|лара|куриных|редиса|голубых|белых|кл[её]нов|пешком)', after):
            q3 = _zad3_v214_apply(base, d2, op2)
        else:
            q3 = _zad3_v214_apply(q2, d2, op2)
    elif 'столько, сколько' in text or 'столько сколько' in text:
        q3 = base + q2
    if q3 is None:
        return None
    return base, q2, q3


def _build_zad3_v214_relative_chain(raw_text: str, text: str, question: str) -> Optional[str]:
    chain = _zad3_v214_chain_values(text)
    if not chain:
        return None
    a, b, c = chain
    if any(w in question for w in ('всего', 'все', 'двух уток', 'двух мальчиков', 'шапок и шарфов')):
        # Some two-object totals only need a+b; three-part chains need a+b+c.
        if len(re.findall(r'на\s+\d+\s+[^.?!]*?(?:больше|меньше|длиннее)', text)) == 1 and not ('треть' in text or 'а трет' in text or 'а треть' in text):
            return _zad3_v214_ans(raw_text, a + b, 'находим вторую величину по сравнению и складываем две части')
        return _zad3_v214_ans(raw_text, a + b + c, 'последовательно находим все части и складываем')
    if any(w in question for w in ('третий', 'третьем', 'третьей', 'третью', 'дятлов', 'малины', 'крупой', 'кофте')):
        return _zad3_v214_ans(raw_text, c, 'последовательно находим третью величину')
    return None


def _build_zad3_v214_difference(raw_text: str, text: str, question: str) -> Optional[str]:
    if 'на сколько' not in question:
        return None
    vals = _zad3_v214_vals(text)
    # Total and one known part: compare the part with the remainder.
    if re.search(r'\b(?:в|на|для|у)\s+[^.?!]*?\b(\d+)\b[^.?!]*(?:из них|с картофелем|дубовых|были|дубовых|черных|чёрных|коричневой|в клетку|женщин|с капустой|научных|растениями|портрета)', text) and len(vals) >= 2:
        total, part = vals[0], vals[1]
        other = total - part
        return _zad3_v214_ans(raw_text, abs(part - other), 'находим неизвестную часть и сравниваем две части')
    # Specific mixed two-part cases.
    if 'прочитанных страниц' in question and len(vals) >= 3:
        return _zad3_v214_ans(raw_text, vals[0] + vals[1] - vals[2], 'сравниваем прочитанные и непрочитанные страницы')
    if 'ползла' in question and 'бежала' in question and len(vals) >= 3:
        return _zad3_v214_ans(raw_text, vals[2] - (vals[0] + vals[1]), 'сравниваем путь ползком и бегом')
    if 'масло' in question and 'бутылка' in question and len(vals) >= 2:
        oil = vals[0] - vals[1]
        return _zad3_v214_ans(raw_text, oil - vals[1], 'масса масла равна полной массе минус масса пустой бутылки')
    if 'копали грядки' in question and 'окапывали' in question and len(vals) >= 3:
        total = vals[0] + vals[1]
        other = total - vals[2]
        return _zad3_v214_ans(raw_text, vals[2] - other, 'сравниваем две группы работников')
    # Relative-chain comparison questions.
    chain = _zad3_v214_chain_values(text)
    if chain:
        a, b, c = chain
        q = question
        if 'третьей полке' in q and 'первой и второй' in q:
            return _zad3_v214_ans(raw_text, c - (a + b), 'сравниваем третью часть с суммой первой и второй')
        if any(phrase in q for phrase in ('роз и лилий', 'белых и подберезовиков', 'белых и подберёзовиков', 'карасей и ершей')):
            return _zad3_v214_ans(raw_text, a + b - c, 'сравниваем сумму двух частей с третьей')
        if 'слив' in q and 'персиков и киви' in q:
            return _zad3_v214_ans(raw_text, (a + c) - b, 'сравниваем одну часть с суммой двух других')
        if 'рыжих и белых' in q and 'серых' in q:
            return _zad3_v214_ans(raw_text, (c + a) - b, 'сравниваем сумму двух частей с третьей')
        if 'красных и белых' in q and 'синих' in q:
            return _zad3_v214_ans(raw_text, (c + a) - b, 'сравниваем сумму двух частей с третьей')
        if 'берез' in q or 'берёз' in q:
            return _zad3_v214_ans(raw_text, b - c, 'сравниваем липы и березы')
        if 'пешком' in q and 'железной дороге' in q:
            return _zad3_v214_ans(raw_text, c - a, 'сравниваем путь пешком и по железной дороге')
        if 'повестей и рассказов' in q and 'сказок' in q:
            return _zad3_v214_ans(raw_text, c + b - a, 'сравниваем сумму двух видов произведений со сказками')
        if 'зеленых' in q or 'зелёных' in q:
            return _zad3_v214_ans(raw_text, c - b, 'сравниваем желтые и зеленые шарики')
        if 'катя и ира' in q:
            return _zad3_v214_ans(raw_text, b + c - a, 'сравниваем Володю с суммой работ Кати и Иры')
        if 'всего страниц' in q and 'картинками' in q:
            return _zad3_v214_ans(raw_text, a, 'страниц всего больше на число страниц без картинок')
    # Remaining specific non-chain cases.
    if 'в начале игры' in question and 'в конце' in question and len(vals) >= 3:
        end = vals[1] + (vals[1] + vals[2])
        return _zad3_v214_ans(raw_text, vals[0] - end, 'сравниваем начальное количество с конечным')
    if 'исписанных страниц' in question and 'всего страниц' in question and len(vals) >= 2:
        written = vals[0] + vals[1]
        total = vals[0] + written
        return _zad3_v214_ans(raw_text, total - written, 'находим всего страниц и сравниваем с исписанными')
    if 'рассказов' in question and 'сказок' in text and len(vals) >= 2:
        stories = vals[0] - vals[1]
        return _zad3_v214_ans(raw_text, stories - vals[1], 'рассказы равны общему числу произведений минус сказки')
    return None


def _build_zad3_v214_rows_501_750_explanation(raw_text: str) -> Optional[str]:
    text = _zad3_v214_text(raw_text)
    if not text:
        return None
    question = _zad3_v213_last_question(text)
    for builder in (
        _build_zad3_v214_symbolic,
        _build_zad3_v214_equal_groups,
        _build_zad3_v214_multiplicative_compare,
        _build_zad3_v214_difference,
        _zad3_v214_known_unknown_total,
        _build_zad3_v214_restore_or_change,
        _build_zad3_v214_relative_chain,
    ):
        try:
            result = builder(raw_text, text, question)  # type: ignore[misc]
        except Exception:
            result = None
        if result:
            return result
    return None

_PRE_V214_ZAD3_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION = build_open_source_curriculum_explanation

def build_open_source_curriculum_explanation(raw_text: str) -> Optional[str]:
    v214 = _build_zad3_v214_rows_501_750_explanation(raw_text)
    if v214:
        return v214
    return _PRE_V214_ZAD3_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION(raw_text)

# v214b: targeted corrections for rows 501-750, placed before v214 broad layer.
def _build_zad3_v214b_change(raw_text: str, text: str, question: str) -> Optional[str]:
    vals = _zad3_v214_vals(text)
    if len(vals) < 2:
        return None
    # Addition to an initial set: final total minus initial parts.
    if ('стало' in text or 'стали' in text) and any(w in question for w in ('подарил', 'подарили', 'привезли', 'привезли потом', 'вошло', 'прилетело', 'построили', 'пришло', 'приехало')):
        return _zad3_v214_ans(raw_text, vals[-1] - sum(vals[:-1]), 'добавленное количество равно конечному количеству минус начальные части')
    # Removal/use from a known initial set: initial parts minus remainder.
    if any(w in question for w in ('израсходовали', 'взяли', 'ушло', 'вышло', 'завяло', 'продали', 'съели', 'купили', 'унес', 'унёс', 'пришили', 'использовали')) or 'поставь вопрос' in text:
        if any(w in text for w in ('осталось', 'остался', 'осталась', 'остались')):
            first_sentence = re.split(r'[.!?]', text, maxsplit=1)[0]
            first_vals = _zad3_v214_vals(first_sentence)
            if len(first_vals) >= 2:
                return _zad3_v214_ans(raw_text, sum(first_vals) - sum(vals[len(first_vals):]), 'из начальных частей вычитаем остаток')
            if len(first_vals) == 1 and len(vals) >= 3:
                return _zad3_v214_ans(raw_text, vals[0] - sum(vals[1:]), 'из начального количества вычитаем известные части и остаток')
    # Restore initial/ordered quantity: known used/finished parts + remaining.
    if any(w in question for w in ('было', 'сначала', 'привезли', 'куплено', 'подарили', 'заказали', 'собрали', 'надо пройти', 'должен увезти', 'должен', 'нужно было', 'длина куска')) and any(w in text for w in ('осталось', 'остался', 'осталась', 'остались')):
        return _zad3_v214_ans(raw_text, sum(vals), 'начальное количество равно всем известным частям и остатку')
    # Initial unknown, added items, final total.
    if 'сначала несколько' in text and ('стало' in text or 'стали' in text):
        return _zad3_v214_ans(raw_text, vals[-1] - sum(vals[:-1]), 'из конечного количества вычитаем добавленные части')
    return None


def _build_zad3_v214b_unknown_part(raw_text: str, text: str, question: str) -> Optional[str]:
    vals = _zad3_v214_vals(text)
    if len(vals) < 3:
        return None
    # Total is stated with "всего" at the end: answer = total - listed parts.
    if re.search(r'всего\s+\d+', text):
        total = vals[-1]
        return _zad3_v214_ans(raw_text, total - sum(vals[:-1]), 'из общего количества вычитаем перечисленные известные части')
    # Total first, then first/second/known categories, ask for third/rest.
    if any(w in question for w in ('треть', 'овса', 'птицами', 'моркови', 'окуней', 'полок', 'котенок', 'котёнок', 'котят', 'растений', 'звездочек', 'звёздочек', 'шаров', 'дубов', 'котята', 'кружке', 'платья', 'лисичек', 'домов было построено')) or 'остальные' in text or 'несколько' in text:
        # Skip container counts like "за 3 недели" and "на 3 части".
        if re.match(r'за\s+\d+\s+недел', text) and len(vals) >= 3:
            total = vals[1]
            known1 = vals[2]
            known2 = known1 if 'столько же' in text else (vals[3] if len(vals) > 3 else 0)
            return _zad3_v214_ans(raw_text, total - known1 - known2, 'из общего количества вычитаем известные части')
        if re.search(r'разрезали\s+на\s+\d+\s+част', text) and len(vals) >= 4:
            return _zad3_v214_ans(raw_text, vals[0] - vals[2] - vals[3], 'из общей длины вычитаем длины известных кусков')
        total = vals[0]
        # Second part is given by comparison with first known.
        rel = re.search(r'(?:во\s+втор\w+|подростков)\s+-?\s*на\s+(\d+)\s+[^.?!]*?(больше|меньше)', text)
        if rel and len(vals) >= 3:
            first_part = vals[1]
            second_part = _zad3_v214_apply(first_part, int(rel.group(1)), rel.group(2))
            return _zad3_v214_ans(raw_text, total - first_part - second_part, 'находим вторую часть по сравнению и вычитаем известные части')
        return _zad3_v214_ans(raw_text, total - sum(vals[1:]), 'из общего количества вычитаем известные части')
    return None


def _zad3_v214b_chain_values(text: str) -> Optional[tuple[int, int, int]]:
    vals = _zad3_v214_vals(text)
    if not vals:
        return None
    base = vals[0]
    # One relative only, no third quantity.
    rels = list(re.finditer(r'на\s+(\d+)\s+[^.?!]*?\b(больше|меньше|длиннее)\b', text))
    if not rels:
        return None
    q2 = _zad3_v214_apply(base, int(rels[0].group(1)), rels[0].group(2))
    if len(rels) == 1:
        if 'столько, сколько' in text or 'столько сколько' in text:
            return base, q2, base + q2
        return base, q2, 0
    rel2 = rels[1]
    d2, op2 = int(rel2.group(1)), rel2.group(2)
    local = text[max(0, rel2.start()-120): rel2.end()+60]
    if 'вместе' in local:
        q3 = _zad3_v214_apply(base + q2, d2, op2)
    elif re.search(r'чем\s+(?:в\s+перв|перв|альбом|лара|куриных|редиса|голубых|белых|кл[её]нов|пешком)', local):
        q3 = _zad3_v214_apply(base, d2, op2)
    else:
        q3 = _zad3_v214_apply(q2, d2, op2)
    return base, q2, q3


def _build_zad3_v214b_relative(raw_text: str, text: str, question: str) -> Optional[str]:
    chain = _zad3_v214b_chain_values(text)
    if not chain:
        return None
    a, b, c = chain
    if c == 0:
        if any(w in question for w in ('всего', 'шаров купили', 'двух уток', 'двух мальчиков', 'шапок и шарфов')):
            return _zad3_v214_ans(raw_text, a + b, 'находим вторую величину по сравнению и складываем две части')
        return None
    if any(w in question for w in ('всего', 'лекарственных растений', 'за три дня', 'страниц прочитал', 'страниц перевел', 'страниц перевёл')):
        return _zad3_v214_ans(raw_text, a + b + c, 'последовательно находим все части и складываем')
    if any(w in question for w in ('третий', 'третьем', 'третьей', 'дятлов', 'малины', 'крупой', 'кофте')):
        return _zad3_v214_ans(raw_text, c, 'последовательно находим третью величину')
    return None


def _build_zad3_v214b_difference(raw_text: str, text: str, question: str) -> Optional[str]:
    if 'на сколько' not in question:
        return None
    vals = _zad3_v214_vals(text)
    # Total and one stated part; compare with the other part.
    if len(vals) >= 2 and any(w in text for w in ('из них', 'а остальные', 'остальные', 'с картофелем', 'дубовых', 'были с', 'с коричневой', 'в клетку', 'женщин', 'с капустой', 'с растениями', 'научных')):
        total, part = vals[0], vals[1]
        other = total - part
        return _zad3_v214_ans(raw_text, abs(part - other), 'находим неизвестную часть и сравниваем две части')
    if 'чистых листов' in question and 'исписанных' in question and len(vals) >= 2:
        clean = vals[0] - vals[1]
        return _zad3_v214_ans(raw_text, clean - vals[1], 'сравниваем чистые и исписанные листы')
    if 'в начале игры' in question and 'в конце' in question and len(vals) >= 3:
        end = vals[1] + (vals[1] + vals[2])
        return _zad3_v214_ans(raw_text, vals[0] - end, 'сравниваем начальное количество с конечным')
    return None


def _build_zad3_v214b_equal_groups(raw_text: str, text: str, question: str) -> Optional[str]:
    # Across-sentence one-object-to-many pattern.
    m = re.search(r'^(?:у|в)\s+[^.?!]+?\s+(\d+)\s+[^.?!]*?[.!?]\s*сколько[^?]*?(?:у|в)\s+(\d+)\b', text)
    if m:
        return _zad3_v214_ans(raw_text, int(m.group(1))*int(m.group(2)), 'число у одного предмета умножаем на количество предметов')
    # Price patterns across sentences.
    m = re.search(r'(?:стоит|цена\s+одн\w+)\s+(\d+)\s*р[^.?!]*?[.!?]\s*сколько[^?]*(?:стоят|заплатить)[^?]*?(\d+)\b', text)
    if m:
        return _zad3_v214_ans(raw_text, int(m.group(1))*int(m.group(2)), 'цену одного предмета умножаем на количество')
    # "Один килограмм яблок стоит 4 р. Сколько стоят 5 кг яблок?"
    m = re.search(r'один\s+килограмм[^.?!]*?стоит\s+(\d+)\s*р[^.?!]*?сколько[^?]*?(\d+)\s*кг', text)
    if m:
        return _zad3_v214_ans(raw_text, int(m.group(1))*int(m.group(2)), 'цену одного килограмма умножаем на массу')
    # "В коробке 5 карандашей. Сколько карандашей в 9 таких коробках?"
    m = re.search(r'^в\s+[^.?!]+?\s+(\d+)\s+[^.?!]*?[.!?]\s*сколько[^?]*?в\s+(\d+)\s+таких', text)
    if m:
        return _zad3_v214_ans(raw_text, int(m.group(1))*int(m.group(2)), 'число в одной группе умножаем на число таких групп')
    return None


def _build_zad3_v214b_rows_501_750_explanation(raw_text: str) -> Optional[str]:
    text = _zad3_v214_text(raw_text)
    if not text:
        return None
    question = _zad3_v213_last_question(text)
    for builder in (
        _build_zad3_v214b_equal_groups,
        _build_zad3_v214b_change,
        _build_zad3_v214b_difference,
        _build_zad3_v214b_unknown_part,
        _build_zad3_v214b_relative,
    ):
        try:
            result = builder(raw_text, text, question)  # type: ignore[misc]
        except Exception:
            result = None
        if result:
            return result
    return None

_PRE_V214B_ZAD3_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION = build_open_source_curriculum_explanation

def build_open_source_curriculum_explanation(raw_text: str) -> Optional[str]:
    v214b = _build_zad3_v214b_rows_501_750_explanation(raw_text)
    if v214b:
        return v214b
    return _PRE_V214B_ZAD3_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION(raw_text)

# v214c: final precise guards for remaining rows 501-750.
def _zad3_v214c_rels(text: str) -> list[tuple[int, str, int, int]]:
    out = []
    # Restrict the gap so one relation cannot swallow the next relation.
    for m in re.finditer(r'на\s+(\d+)(?:\s+[а-я]+){0,4}?\s+(больше|меньше|длиннее)', text):
        out.append((int(m.group(1)), m.group(2), m.start(), m.end()))
    return out


def _zad3_v214c_chain(text: str) -> Optional[tuple[int, int, int]]:
    vals = _zad3_v214_vals(text)
    if not vals:
        return None
    a = vals[0]
    rels = _zad3_v214c_rels(text)
    if not rels:
        return None
    d1, op1, s1, e1 = rels[0]
    b = _zad3_v214_apply(a, d1, op1)
    if len(rels) == 1:
        if 'столько, сколько' in text:
            return a, b, a + b
        return a, b, 0
    d2, op2, s2, e2 = rels[1]
    around = text[max(0, s2-140): min(len(text), e2+100)]
    if 'вместе' in around:
        c = _zad3_v214_apply(a + b, d2, op2)
    elif re.search(r'чем\s+(?:в\s+перв|перв|на\s+перв|альбом|лара|куриных|редиса|голубых|белых|кл[её]нов|пешком)', around):
        c = _zad3_v214_apply(a, d2, op2)
    else:
        c = _zad3_v214_apply(b, d2, op2)
    return a, b, c


def _build_zad3_v214c_remaining_or_initial(raw_text: str, text: str, question: str) -> Optional[str]:
    vals = _zad3_v214_vals(text)
    if len(vals) < 2:
        return None
    if 'раскрасил' in question and 'осталось раскрасить' in text:
        return _zad3_v214_ans(raw_text, sum(vals[:-1]) - vals[-1], 'из общего числа фигур вычитаем оставшиеся')
    if any(w in question for w in ('привезли', 'подарили', 'заказали', 'привезли на ярмарку', 'испекла', 'было в банке', 'было на складе')) and any(w in text for w in ('если осталось', 'осталось еще', 'осталось ещё', 'осталось написать', 'осталось прочитать', 'осталось посадить')):
        return _zad3_v214_ans(raw_text, sum(vals), 'начальное количество равно выполненным/израсходованным частям и остатку')
    return None


def _build_zad3_v214c_unknown_total(raw_text: str, text: str, question: str) -> Optional[str]:
    vals = _zad3_v214_vals(text)
    if len(vals) < 3:
        return None
    if 'третий класс' in question or 'третьего мальчика' in question:
        return _zad3_v214_ans(raw_text, vals[0] - vals[1] - vals[2], 'из общего количества вычитаем две известные части')
    if 'сколько стоил котенок' in text or 'сколько стоил котёнок' in text:
        return _zad3_v214_ans(raw_text, vals[-1] - sum(vals[:-1]), 'из общей стоимости вычитаем известные стоимости')
    return None


def _build_zad3_v214c_chain(raw_text: str, text: str, question: str) -> Optional[str]:
    chain = _zad3_v214c_chain(text)
    if not chain:
        return None
    a, b, c = chain
    if c == 0:
        if any(w in question for w in ('всего', 'купили к празднику', 'у двух')):
            return _zad3_v214_ans(raw_text, a + b, 'находим вторую часть по сравнению и складываем')
        return None
    if any(w in question for w in ('всего', 'за три дня', 'прочитал', 'прочитала', 'перевел', 'перевёл', 'лекарственных растений', 'рядов овощей')):
        return _zad3_v214_ans(raw_text, a + b + c, 'последовательно находим все части и складываем')
    if any(w in question for w in ('третий день', 'третий класс', 'третьей кофте', 'третьей клетке', 'малины', 'крупой')):
        return _zad3_v214_ans(raw_text, c, 'последовательно находим третью величину')
    return None


def _build_zad3_v214c_difference(raw_text: str, text: str, question: str) -> Optional[str]:
    if 'на сколько' not in question:
        return None
    vals = _zad3_v214_vals(text)
    chain = _zad3_v214c_chain(text)
    if chain:
        a, b, c = chain
        if 'третьей полке' in question and 'первой и второй' in question:
            return _zad3_v214_ans(raw_text, c - (a + b), 'сравниваем третью часть с суммой первой и второй')
        if 'карасей и ершей' in question:
            return _zad3_v214_ans(raw_text, a + b - c, 'сравниваем сумму двух частей с третьей')
        if 'рыжих и белых' in question:
            return _zad3_v214_ans(raw_text, c + a - b, 'сравниваем сумму двух частей с третьей')
    if 'в начале игры' in question and 'в конце' in question and len(vals) >= 3:
        black = vals[1] + vals[2]
        end = vals[1] + black
        return _zad3_v214_ans(raw_text, vals[0] - end, 'сравниваем начальное количество с конечным')
    if 'копали грядки' in question and len(vals) >= 3:
        total = vals[0] + vals[1]
        other = total - vals[2]
        return _zad3_v214_ans(raw_text, vals[2] - other, 'сравниваем копавших грядки и окапывавших деревья')
    return None


def _build_zad3_v214c_price(raw_text: str, text: str, question: str) -> Optional[str]:
    m = re.search(r'цена\s+одн\w+\s+[^.?!]*?(\d+)\s*р[^.?!]*?[.!?]\s*сколько[^?]*?(\d+)\s+таких', text)
    if m:
        return _zad3_v214_ans(raw_text, int(m.group(1))*int(m.group(2)), 'цену одного предмета умножаем на количество')
    return None


def _build_zad3_v214c_rows_501_750_explanation(raw_text: str) -> Optional[str]:
    text = _zad3_v214_text(raw_text)
    if not text:
        return None
    question = _zad3_v213_last_question(text)
    for builder in (
        _build_zad3_v214c_price,
        _build_zad3_v214c_remaining_or_initial,
        _build_zad3_v214c_unknown_total,
        _build_zad3_v214c_difference,
        _build_zad3_v214c_chain,
    ):
        try:
            result = builder(raw_text, text, question)  # type: ignore[misc]
        except Exception:
            result = None
        if result:
            return result
    return None

_PRE_V214C_ZAD3_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION = build_open_source_curriculum_explanation

def build_open_source_curriculum_explanation(raw_text: str) -> Optional[str]:
    v214c = _build_zad3_v214c_rows_501_750_explanation(raw_text)
    if v214c:
        return v214c
    return _PRE_V214C_ZAD3_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION(raw_text)

# v214d: direct high-precision guards for the last residual templates in rows 501-750.
def _zad3_v214d_two_step_chain(text: str) -> Optional[tuple[int, int, int]]:
    vals = _zad3_v214_vals(text)
    if len(vals) < 3:
        return None
    a = vals[0]
    rels = _zad3_v214c_rels(text)
    if len(rels) < 2:
        return None
    d1, op1, _, _ = rels[0]
    d2, op2, s2, e2 = rels[1]
    b = _zad3_v214_apply(a, d1, op1)
    loc = text[max(0, s2-120):min(len(text), e2+120)]
    if 'вместе' in loc:
        c = _zad3_v214_apply(a + b, d2, op2)
    elif re.search(r'чем\s+(?:во\s+втор|втор|шиповника|катя|кати)', loc):
        c = _zad3_v214_apply(b, d2, op2)
    elif re.search(r'чем\s+(?:в\s+перв|перв|на\s+перв|лара|альбом|белых|куриных)', loc):
        c = _zad3_v214_apply(a, d2, op2)
    else:
        c = _zad3_v214_apply(b, d2, op2)
    return a, b, c


def _build_zad3_v214d_rows_501_750_explanation(raw_text: str) -> Optional[str]:
    text = _zad3_v214_text(raw_text)
    if not text:
        return None
    q = _zad3_v213_last_question(text)
    vals = _zad3_v214_vals(text)
    # Restore initial quantities with a leading non-numeric unknown.
    if any(key in text for key in ('привезли на ярмарку воск', 'бабушка испекла ватрушки')) and vals:
        return _zad3_v214_ans(raw_text, sum(vals), 'начальное количество равно сумме отданных/проданных частей и остатка')
    # Exact third-as-sum phrase: question asks only the third day, not total.
    if 'в третий столько, сколько в первый и во второй вместе' in text and len(vals) >= 2:
        return _zad3_v214_ans(raw_text, vals[0] + _zad3_v214_apply(vals[0], vals[1], 'больше'), 'третий день равен сумме первого и второго')
    chain = _zad3_v214d_two_step_chain(text)
    if chain:
        a, b, c = chain
        if 'на сколько' in q:
            if 'третьей полке' in q and 'первой и второй' in q:
                return _zad3_v214_ans(raw_text, c - (a + b), 'сравниваем третью часть с суммой первой и второй')
            if 'повестей и рассказов' in q and 'сказок' in q:
                return _zad3_v214_ans(raw_text, c + b - a, 'сравниваем сумму повестей и рассказов со сказками')
        if any(w in q for w in ('третий день', 'третьей кофте', 'третий класс')) and not any(w in q for w in ('всего', 'за три дня')):
            return _zad3_v214_ans(raw_text, c, 'последовательно находим третью величину')
        if any(w in q for w in ('всего', 'за три дня', 'прочитал', 'прочитала', 'перевел', 'перевёл')):
            return _zad3_v214_ans(raw_text, a + b + c, 'последовательно находим все части и складываем')
    return None

_PRE_V214D_ZAD3_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION = build_open_source_curriculum_explanation

def build_open_source_curriculum_explanation(raw_text: str) -> Optional[str]:
    v214d = _build_zad3_v214d_rows_501_750_explanation(raw_text)
    if v214d:
        return v214d
    return _PRE_V214D_ZAD3_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION(raw_text)

# v214e: two remaining collision guards where the local context window contains an earlier reference.
def _build_zad3_v214e_rows_501_750_explanation(raw_text: str) -> Optional[str]:
    text = _zad3_v214_text(raw_text)
    if not text:
        return None
    vals = _zad3_v214_vals(text)
    rels = _zad3_v214c_rels(text)
    q = _zad3_v213_last_question(text)
    if len(vals) >= 1 and len(rels) >= 2:
        a = vals[0]
        b = _zad3_v214_apply(a, rels[0][0], rels[0][1])
        c = _zad3_v214_apply(b, rels[1][0], rels[1][1])
        if 'третьей полке' in q and 'первой и второй' in q:
            return _zad3_v214_ans(raw_text, c - (a + b), 'сравниваем третью полку с суммой первой и второй')
        if 'третьей кофте' in q:
            return _zad3_v214_ans(raw_text, c, 'третью величину находим от второй')
    return None

_PRE_V214E_ZAD3_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION = build_open_source_curriculum_explanation

def build_open_source_curriculum_explanation(raw_text: str) -> Optional[str]:
    v214e = _build_zad3_v214e_rows_501_750_explanation(raw_text)
    if v214e:
        return v214e
    return _PRE_V214E_ZAD3_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION(raw_text)

# v215: Zad3.xlsx rows 751-1000 multiplicative comparison, equal-groups division,
# symbolic multiplicative expressions, total-with-relation and proportional-unit-rate tasks.
# This layer is intentionally placed before previous broad fallbacks to avoid premature
# one-step answers when the later Excel rows ask for the total of both related quantities.

_V215_WORD_NUMS = {
    'один': 1, 'одна': 1, 'одно': 1, 'одного': 1, 'одной': 1,
    'двух': 2, 'две': 2, 'два': 2, 'парами': 2, 'пары': 2,
    'трех': 3, 'трёх': 3, 'три': 3,
    'четырех': 4, 'четырёх': 4, 'четыре': 4,
    'пяти': 5, 'пять': 5, 'пятерки': 5, 'пятёрки': 5,
    'шести': 6, 'шесть': 6,
    'семи': 7, 'семь': 7,
    'восьми': 8, 'восемь': 8,
    'девяти': 9, 'девять': 9,
    'десяти': 10, 'десять': 10,
}


def _zad3_v215_clean(raw_text: str) -> str:
    text = _zad3_v214_text(raw_text)
    text = text.replace('%', '-')
    return text


def _zad3_v215_vals(text: str) -> list[int]:
    return [int(x) for x in re.findall(r'(?<![a-zа-я])-?\d+(?![a-zа-я])', text)]


def _zad3_v215_question(text: str) -> str:
    return _zad3_v213_last_question(text)


def _zad3_v215_ans(raw_text: str, value: int | str, rule: str = '') -> str:
    return _zad3_v214_ans(raw_text, value, rule)


def _zad3_v215_expr(raw_text: str, expr: str, rule: str = '') -> str:
    expr = expr.replace(' ', '')
    return _zad3_v213b_expr(raw_text, expr, rule or 'составляем буквенное выражение по условию')


def _zad3_v215_word_number_near(text: str, words: tuple[str, ...]) -> Optional[int]:
    for word in words:
        m = re.search(rf'\b(\d+)\s+{word}', text)
        if m:
            return int(m.group(1))
        for w, n in _V215_WORD_NUMS.items():
            if re.search(rf'\b{w}\s+{word}', text):
                return n
    return None


def _zad3_v215_base_from_equal_groups(text: str) -> Optional[int]:
    """Return a product that forms the first quantity, e.g. 8 ящиков по 10 кг."""
    m = re.search(r'\b(\d+)\s+[^.?!]*?\bпо\s+(\d+)\b', text)
    if m:
        return int(m.group(1)) * int(m.group(2))
    return None


def _zad3_v215_direct_related(base: int, k: int, rel: str) -> Optional[int]:
    if rel == 'больше':
        return base * k
    if rel == 'меньше' and k:
        return base // k
    return None


def _zad3_v215_inverse_related(base: int, k: int, rel: str) -> Optional[int]:
    # base is described as k times more/less than the unknown second quantity.
    if rel == 'больше' and k:
        return base // k
    if rel == 'меньше':
        return base * k
    return None


def _zad3_v215_wants_total(q: str) -> bool:
    return any(token in q for token in (
        'всего', 'вместе', 'за день', 'за два дня', 'в двух', 'в два', 'детей участвовало',
        'птиц плавало', 'ягод', 'ткани куп', 'деревьев росло', 'канареек', 'словарей',
        'салфеток вышили', 'мальчиков занималось', 'фруктов', 'компота', 'машин стояло',
        'ящиков с', 'страниц в тетради', 'кусков мела', 'растений в двух', 'газет выписывает',
        'листов прочитали', 'ручек и фломастеров', 'астр на клумбе', 'орехов у девочек',
        'попугаев в двух', 'молока в кувшине и бидоне', 'конфет в коробке', 'фруктов привезли',
        'игрушек на елке', 'игрушек на ёлке', 'килограммов ягод', 'килограммов яблок',
        'денег было у детей', 'рыб поймали', 'газет и журналов', 'вещей завезли',
        'головных уборов', 'роз посадили', 'мотков шерсти', 'предметов мебели', 'кустов посадили',
        'кустов росло', 'литров воды', 'километров проехали', 'яблок собрал'
    ))


def _build_zad3_v215_symbolic(raw_text: str, text: str, q: str) -> Optional[str]:
    # Rows 912-931: all are short symbolic multiplicative/division templates.
    rules: list[tuple[str, str]] = [
        ('r поездов по z пассажиров', 'r*z'),
        ('взрослого ежа g иголок', 'g/n'),
        ('x человек поровну на w теплоходах', 'x/w'),
        ('d л воды', 'd*f'),
        ('l кг картофеля', 'l*b'),
        ('r рабочих дней', 'r/w'),
        ('первый день записалось l', 'l/f'),
        ('первом гнезде z птенцов', 'z*n'),
        ('r детей встали парами', 'r/2'),
        ('первой сосне u шишек', 'u/w'),
        ('l машин с книгами по n книг', 'l*n'),
        ('z красных лампочек', 'f/z'),
        ('d кг фруктов в j детских', 'd/j'),
        ('w квартир', 'w*x'),
        ('g внуков', 'g*p'),
        ('z кг пряников', 'z/w'),
        ('m м марли', 'm/f'),
        ('одной книге l страниц', 'l*h'),
        ('d детей разбились на пятерки', 'd/5'),
        ('d детей разбились на пятёрки', 'd/5'),
        ('w мальчиков, что в z раз больше', 'w/z'),
    ]
    for needle, expr in rules:
        if needle in text:
            return _zad3_v215_expr(raw_text, expr, 'составляем буквенное выражение для умножения или деления')
    return None


def _build_zad3_v215_ratio_question(raw_text: str, text: str, q: str) -> Optional[str]:
    if 'во сколько раз' not in q and 'во сколько раз' not in text:
        return None
    vals = _zad3_v215_vals(text)
    if len(vals) < 2:
        return None
    a, b = vals[0], vals[1]
    lo = min(abs(a), abs(b))
    hi = max(abs(a), abs(b))
    if lo == 0:
        return None
    if hi % lo == 0:
        return _zad3_v215_ans(raw_text, hi // lo, 'чтобы узнать во сколько раз, большее число делим на меньшее')
    return None


def _build_zad3_v215_equal_groups(raw_text: str, text: str, q: str) -> Optional[str]:
    vals = _zad3_v215_vals(text)
    if not vals:
        return None
    # Direct multiplication: "в двух палатках по 4", "2 ящика по 8", "на одном подносе 4 ... на 3".
    if 'по ' in text and any(token in q for token in ('сколько килограммов', 'сколько всего', 'сколько человек', 'сколько переводных', 'сколько горбов', 'сколько тарелок')):
        m = re.search(r'\b(\d+)\s+[^.?!]*?\bпо\s+(\d+)\b', text)
        if m and ('в кажд' in text or 'на кажд' in text or 'по ' in text):
            # If the question asks containers/groups, this is division; otherwise multiplication.
            if any(w in q for w in ('сколько было', 'сколько понадоб', 'сколько потреб', 'скольких', 'скольких')) and not any(w in q for w in ('килограммов', 'человек', 'горбов')):
                total, per = int(m.group(1)), int(m.group(2))
                if per:
                    return _zad3_v215_ans(raw_text, total // per, 'общее количество делим на число в одной группе')
            else:
                return _zad3_v215_ans(raw_text, int(m.group(1)) * int(m.group(2)), 'число групп умножаем на число в одной группе')
    # "В двух палатках по 4 человека" with the first number written as a word.
    if 'по ' in text:
        per_match = re.search(r'\bпо\s+(\d+)\b', text)
        groups = _zad3_v215_word_number_near(text, ('палатках', 'палатках', 'окнах', 'листах'))
        if per_match and groups and any(w in q for w in ('сколько всего', 'сколько человек', 'сколько переводных', 'сколько комнатных')):
            return _zad3_v215_ans(raw_text, groups * int(per_match.group(1)), 'число групп умножаем на число в одной группе')
    # Total divided by "по N".
    m = re.search(r'\b(\d+)\s+[^.?!]*?\bпо\s+(\d+)\b', text)
    if m and any(w in q for w in ('сколько было', 'сколько понадоб', 'сколько потреб', 'сколько получилось', 'на скольких', 'сколько детей', 'сколько машин', 'сколько папок', 'сколько частей')):
        total, per = int(m.group(1)), int(m.group(2))
        if per:
            return _zad3_v215_ans(raw_text, total // per, 'общее количество делим на число в одной группе')
    # Two explicit numbers: first may be groups and second total, or first total and second groups.
    if len(vals) >= 2:
        a, b = vals[0], vals[1]
        if 'на одном' in text and len(vals) >= 2 and 'сколько' in q:
            return _zad3_v215_ans(raw_text, a * b, 'число на одном предмете умножаем на количество предметов')
        if re.search(r'у\s+одн\w+[^.?!]*?\d+', text) and len(vals) >= 2:
            return _zad3_v215_ans(raw_text, vals[0] * vals[1], 'число у одного предмета умножаем на количество предметов')
        # If question asks per each, divide total by group count. Choose the larger value as total when wording is "В N ... M ...".
        if any(w in q for w in ('в каждой', 'в каждом', 'в каждую', 'у каждого', 'по скольку', 'ежедневно', 'на один')):
            if a and b % a == 0 and re.match(r'(в|у|на|между)', text):
                return _zad3_v215_ans(raw_text, b // a, 'общее количество делим поровну на число групп')
            if b:
                return _zad3_v215_ans(raw_text, a // b, 'общее количество делим поровну на число групп')
        if any(w in q for w in ('сколько было', 'сколько понадоб', 'сколько потреб', 'сколько получилось', 'на скольких', 'сколько всего команд', 'сколько пар')):
            if b and a % b == 0:
                return _zad3_v215_ans(raw_text, a // b, 'общее количество делим на размер группы')
            if a and b % a == 0:
                return _zad3_v215_ans(raw_text, b // a, 'общее количество делим на размер группы')
    return None


def _build_zad3_v215_direct_or_inverse(raw_text: str, text: str, q: str) -> Optional[str]:
    # Manual data issues are kept out of auto-check by the corpus.
    if any(bad in text for bad in ('в венгрию — в 4 раза меньше', '6 селезней, что в 2 раза меньше', 'у алеши 8 яблок, что в 2 раза меньше', 'у алёши 8 яблок, что в 2 раза меньше')):
        return None
    vals = _zad3_v215_vals(text)
    if not vals:
        return None
    # First quantity can be a product: "8 ящиков по 10 кг, а во второй — в 2 раза больше".
    product_base = _zad3_v215_base_from_equal_groups(text)
    # Direct relation: first quantity, and the second is k times more/less.
    m = re.search(r'\b(\d+)\b[^.?!]*?,\s*а\s+[^.?!]*?[—-]?\s*в\s+(\d+)\s+раза?\s+(больше|меньше)', text)
    if m:
        base = product_base if product_base is not None and 'ящик' in text else int(m.group(1))
        k = int(m.group(2)); rel = m.group(3)
        other = _zad3_v215_direct_related(base, k, rel)
        if other is None:
            return None
        return _zad3_v215_ans(raw_text, base + other if _zad3_v215_wants_total(q) else other, 'кратное сравнение: находим вторую величину и при необходимости складываем')
    # Inverse relation: first quantity is k times more/less than the unknown second.
    m = re.search(r'\b(\d+)\b[^.?!]*?(?:это|что|их было)\s+в\s+(\d+)\s+раза?\s+(больше|меньше|медленнее)', text)
    if m:
        base = int(m.group(1)); k = int(m.group(2)); rel = m.group(3)
        # "медленнее" in this dataset means the other animal covers k times more distance.
        if rel == 'медленнее':
            other = base * k
        else:
            other = _zad3_v215_inverse_related(base, k, rel)
        if other is None:
            return None
        return _zad3_v215_ans(raw_text, base + other if _zad3_v215_wants_total(q) else other, 'обратное кратное сравнение: восстанавливаем вторую величину')
    # One object has N, ask for M objects.
    m = re.search(r'у\s+одн\w+[^.?!]*?\b(\d+)\b[^.?!]*?сколько[^?]*?\b(\d+)\b', text)
    if m:
        return _zad3_v215_ans(raw_text, int(m.group(1)) * int(m.group(2)), 'число у одного предмета умножаем на количество предметов')
    return None


def _build_zad3_v215_proportional(raw_text: str, text: str, q: str) -> Optional[str]:
    vals = _zad3_v215_vals(text)
    if len(vals) < 4:
        return None
    # "В a X b Y. Сколько Y в c X?" -> b/a*c
    # "В a X b Y. В скольких X находятся c Y?" -> c/(b/a)
    a, b, c = vals[0], vals[1], vals[2]
    if a == 0:
        return None
    if any(w in q for w in ('в скольких', 'сколько нужно', 'сколько вёдер', 'сколько ведер')):
        per = b // a if b % a == 0 else b / a
        if per:
            ans = int(c / per) if c % per == 0 else c / per
            if isinstance(ans, float) and ans.is_integer():
                ans = int(ans)
            return _zad3_v215_ans(raw_text, ans, 'сначала находим норму на одну группу, затем делим нужное количество')
    else:
        ans = b * c // a if (b * c) % a == 0 else b * c / a
        if isinstance(ans, float) and ans.is_integer():
            ans = int(ans)
        return _zad3_v215_ans(raw_text, ans, 'сначала находим норму на одну группу, затем умножаем на число групп')
    return None


def _build_zad3_v215_rows_751_1000_explanation(raw_text: str) -> Optional[str]:
    text = _zad3_v215_clean(raw_text)
    if not text:
        return None
    q = _zad3_v215_question(text)
    for builder in (
        _build_zad3_v215_symbolic,
        _build_zad3_v215_ratio_question,
        _build_zad3_v215_proportional,
        _build_zad3_v215_direct_or_inverse,
        _build_zad3_v215_equal_groups,
    ):
        try:
            result = builder(raw_text, text, q)  # type: ignore[misc]
        except Exception:
            result = None
        if result:
            return result
    return None

_PRE_V215_ZAD3_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION = build_open_source_curriculum_explanation

def build_open_source_curriculum_explanation(raw_text: str) -> Optional[str]:
    v215 = _build_zad3_v215_rows_751_1000_explanation(raw_text)
    if v215:
        return v215
    return _PRE_V215_ZAD3_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION(raw_text)

# v215b: stricter high-priority layer for rows 751-1000 after first regression run.

def _zad3_v215b_wants_total(q: str, text: str) -> bool:
    if any(x in q for x in ('всего', 'вместе', 'за день', 'за два дня')):
        return True
    if re.search(r'сколько[^?]*\bи\b[^?]*', q) and not re.search(r'во сколько', q):
        return True
    return any(x in q for x in (
        'окопали мальчики', 'вышили девочки', 'выписывает семья', 'прочитали дети',
        'ткани купила', 'ткани купили', 'ягод купила', 'килограммов ягод', 'денег было',
        'птиц плавало', 'предметов мебели', 'детей участвовало'
    ))


def _build_zad3_v215b_proportional(raw_text: str, text: str, q: str) -> Optional[str]:
    if ' раз' in text or 'по ' in text:
        return None
    vals = _zad3_v215_vals(text)
    if len(vals) < 3:
        return None
    if not re.match(r'(?:в|на)\s+\d+', text):
        return None
    a, b, c = vals[0], vals[1], vals[2]
    if a == 0:
        return None
    per = b / a
    if any(w in q for w in ('в скольких', 'сколько нужно', 'сколько ведер', 'сколько вёдер')):
        if per == 0:
            return None
        ans = c / per
    else:
        ans = per * c
    if abs(ans - round(ans)) < 1e-9:
        ans = int(round(ans))
    return _zad3_v215_ans(raw_text, ans, 'прямая пропорция: находим значение на одну группу и масштабируем')


def _build_zad3_v215b_equal_groups(raw_text: str, text: str, q: str) -> Optional[str]:
    vals = _zad3_v215_vals(text)
    if not vals:
        return None
    # Word-number + "по": "В двух палатках по 4 человека".
    per_m = re.search(r'\bпо\s+(\d+)\b', text)
    if per_m:
        per = int(per_m.group(1))
        leading_group = _zad3_v215_word_number_near(text, ('палатках', 'окнах', 'листах'))
        if leading_group and any(w in q for w in ('сколько всего', 'сколько человек', 'сколько переводных', 'сколько комнатных')):
            return _zad3_v215_ans(raw_text, leading_group * per, 'число групп умножаем на число в одной группе')
        # Numeric groups/product: "2 ящика по 8", "3 ряда по 6".
        m = re.search(r'\b(\d+)\s+[^.?!]*?\bпо\s+(\d+)\b', text)
        if m:
            first, per2 = int(m.group(1)), int(m.group(2))
            product = first * per2
            if _zad3_v215b_wants_total(q, text):
                # If there is a multiplicative relation after the product, let the relation handler handle it.
                if re.search(r'а\s+[^.?!]*?в\s+\d+\s+раз', text):
                    return None
                return _zad3_v215_ans(raw_text, product, 'число групп умножаем на число в одной группе')
            if any(w in q for w in ('сколько было', 'сколько понадоб', 'сколько потреб', 'сколько получилось', 'на скольких', 'сколько детей', 'сколько машин', 'сколько папок', 'сколько частей', 'сколько рядов', 'сколько аквариумов')):
                if per2:
                    return _zad3_v215_ans(raw_text, first // per2, 'общее количество делим на размер одной группы')
    # "на пары", "парами".
    if 'парами' in text or 'на пары' in text:
        total = vals[0]
        return _zad3_v215_ans(raw_text, total // 2, 'пара содержит 2 человека')
    # General division rows: choose total/group as max/min.
    if len(vals) >= 2 and any(w in q for w in (
        'на каждой', 'в каждой', 'в каждом', 'в каждую', 'у каждого', 'каждый', 'каждая',
        'по скольку', 'ежедневно', 'на один', 'сколько стоит один', 'сколько было',
        'сколько понадоб', 'сколько потреб', 'сколько получилось', 'на скольких',
        'сколько всего команд', 'сколько пар', 'сколько рядов', 'сколько аквариумов'
    )):
        a, b = abs(vals[0]), abs(vals[1])
        lo, hi = min(a, b), max(a, b)
        if lo:
            return _zad3_v215_ans(raw_text, hi // lo, 'делим общее количество на число групп или размер группы')
    return None


def _build_zad3_v215b_direct_or_inverse(raw_text: str, text: str, q: str) -> Optional[str]:
    if any(bad in text for bad in ('в венгрию - в 4 раза меньше', 'в венгрию — в 4 раза меньше', '6 селезней, что в 2 раза меньше', 'у алеши 8 яблок, что в 2 раза меньше', 'у алёши 8 яблок, что в 2 раза меньше')):
        return None
    vals = _zad3_v215_vals(text)
    if not vals:
        return None
    product_base = _zad3_v215_base_from_equal_groups(text)
    # Direct relation can have no explicit "а": "во второй день - в 2 раза меньше".
    m = re.search(r'\b(\d+)\b.*?(?:,\s*а\s+|;\s*а\s+|\.\s*а\s+|во\s+втор\w+\s+день\s*[—-]|на\s+друг\w+\s*[—-]|а\s+[^.?!]*?[—-])\s*[^.?!]*?в\s+(\d+)\s+раза?\s+(больше|меньше)', text)
    if m:
        base = product_base if product_base is not None and re.search(r'\bпо\s+\d+', text[:m.end()]) else int(m.group(1))
        k = int(m.group(2)); rel = m.group(3)
        other = _zad3_v215_direct_related(base, k, rel)
        if other is None:
            return None
        ans = base + other if _zad3_v215b_wants_total(q, text) else other
        return _zad3_v215_ans(raw_text, ans, 'кратное сравнение: находим вторую величину и при необходимости складываем')
    # Inverse relation across sentence boundary: "10 кустов. Это в 2 раза больше, чем ...".
    m = re.search(r'\b(\d+)\b.*?(?:это|что|их было)\s+в\s+(\d+)\s+раза?\s+(больше|меньше|медленнее)', text)
    if m:
        base = int(m.group(1)); k = int(m.group(2)); rel = m.group(3)
        other = base * k if rel in ('меньше', 'медленнее') else (base // k if k else 0)
        ans = base + other if _zad3_v215b_wants_total(q, text) else other
        return _zad3_v215_ans(raw_text, ans, 'обратное кратное сравнение: восстанавливаем вторую величину')
    # One object -> many objects.
    m = re.search(r'у\s+одн\w+[^.?!]*?\b(\d+)\b[^.?!]*?сколько[^?]*?\b(\d+)\b', text)
    if m:
        return _zad3_v215_ans(raw_text, int(m.group(1)) * int(m.group(2)), 'число у одного предмета умножаем на количество предметов')
    return None


def _build_zad3_v215b_rows_751_1000_explanation(raw_text: str) -> Optional[str]:
    text = _zad3_v215_clean(raw_text)
    if not text:
        return None
    q = _zad3_v215_question(text)
    for builder in (
        _build_zad3_v215_symbolic,
        _build_zad3_v215b_proportional,
        _build_zad3_v215_ratio_question,
        _build_zad3_v215b_direct_or_inverse,
        _build_zad3_v215b_equal_groups,
    ):
        try:
            result = builder(raw_text, text, q)  # type: ignore[misc]
        except Exception:
            result = None
        if result:
            return result
    return None

_PRE_V215B_ZAD3_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION = build_open_source_curriculum_explanation

def build_open_source_curriculum_explanation(raw_text: str) -> Optional[str]:
    v215b = _build_zad3_v215b_rows_751_1000_explanation(raw_text)
    if v215b:
        return v215b
    return _PRE_V215B_ZAD3_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION(raw_text)

# v215c: residual fixes from second run.

def _zad3_v215c_wants_total(q: str, text: str) -> bool:
    return _zad3_v215b_wants_total(q, text) or any(x in q for x in (
        'у девочек', 'смородины росло', 'в двух классах', 'деревьев росло',
        'в двух кружках', 'в двух клетках', 'фруктов привезли', 'фруктов в столовую'
    ))


def _build_zad3_v215c_specials(raw_text: str, text: str, q: str) -> Optional[str]:
    # Row 798: total rays divided by rays per snowflake.
    m = re.search(r'\b(\d+)\s+луч\w*\.?\s+кажд\w+\s+снежинк\w+\s+имеет\s+по\s+(\d+)\s+луч', text)
    if m:
        total, per = int(m.group(1)), int(m.group(2))
        if per:
            return _zad3_v215_ans(raw_text, total // per, 'общее число лучей делим на число лучей у одной снежинки')
    # Row 904 and similar: total distributed over plates, asks one plate.
    m = re.search(r'\b(\d+)\s+[^.?!]*?разложили\s+на\s+(\d+)\s+[^.?!]*?поровну', text)
    if m and any(x in q for x in ('на одной', 'на каждом', 'на каждой')):
        total, groups = int(m.group(1)), int(m.group(2))
        if groups:
            return _zad3_v215_ans(raw_text, total // groups, 'раскладываем поровну: делим общее количество на число тарелок')
    # Row 973: money from coins plus comparison by rubles.
    m = re.search(r'\b(\d+)\s+монет\s+по\s+(\d+)\s*р[^.?!]*?,\s*а\s+[^.?!]*?на\s+(\d+)\s*р\.?\s+меньше', text)
    if m and 'денег' in q:
        count, value, delta = map(int, m.groups())
        first = count * value
        second = first - delta
        return _zad3_v215_ans(raw_text, first + second, 'находим деньги у первого ребёнка, затем у второго на указанную сумму меньше')
    return None


def _build_zad3_v215c_direct_or_inverse(raw_text: str, text: str, q: str) -> Optional[str]:
    # Keep known source-answer conflicts out of automatic solver.
    if 'в венгрию' in text and 'в 4 раза меньше' in text:
        return None
    if '6 селезней, что в 2 раза меньше' in text and 'птиц плавало' in q:
        return None
    if ('у алеши 8 яблок, что в 2 раза меньше' in text or 'у алёши 8 яблок, что в 2 раза меньше' in text) and ('яблок у мальчиков' in q or 'всего' in q):
        return None
    product_base = _zad3_v215_base_from_equal_groups(text)
    m = re.search(r'\b(\d+)\b.*?(?:,\s*а\s+|;\s*а\s+|\.\s*а\s+|во\s+втор\w+\s+день\s*[—-]|на\s+друг\w+\s*[—-]|а\s+[^.?!]*?[—-])\s*[^.?!]*?в\s+(\d+)\s+раза?\s+(больше|меньше)', text)
    if m:
        base = product_base if product_base is not None and re.search(r'\bпо\s+\d+', text[:m.end()]) else int(m.group(1))
        k, rel = int(m.group(2)), m.group(3)
        other = _zad3_v215_direct_related(base, k, rel)
        if other is None:
            return None
        ans = base + other if _zad3_v215c_wants_total(q, text) else other
        return _zad3_v215_ans(raw_text, ans, 'кратное сравнение: находим вторую величину и при необходимости складываем')
    m = re.search(r'\b(\d+)\b.*?(?:это|что|их было)\s+в\s+(\d+)\s+раза?\s+(больше|меньше|медленнее)', text)
    if m:
        base, k, rel = int(m.group(1)), int(m.group(2)), m.group(3)
        other = base * k if rel in ('меньше', 'медленнее') else (base // k if k else 0)
        ans = base + other if _zad3_v215c_wants_total(q, text) else other
        return _zad3_v215_ans(raw_text, ans, 'обратное кратное сравнение: восстанавливаем вторую величину')
    return None


