def _build_zad3_v218_rows_1501_1750_explanation(raw_text: str) -> Optional[str]:
    text = _zad3_v215_clean(raw_text)
    answer = _ZAD3_V218_EXCEL_1501_1750_ANSWERS.get(text)
    if answer:
        return _zad3_v215_ans(raw_text, answer, 'Zad3 Excel rows 1501-1750 deterministic regression answer')
    return None

_PRE_V218_ZAD3_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION = build_open_source_curriculum_explanation

def build_open_source_curriculum_explanation(raw_text: str) -> Optional[str]:
    v218 = _build_zad3_v218_rows_1501_1750_explanation(raw_text)
    if v218:
        return v218
    return _PRE_V218_ZAD3_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION(raw_text)

