def _build_zad3_v219_rows_1751_2000_explanation(raw_text: str) -> Optional[str]:
    text = _zad3_v215_clean(raw_text)
    answer = _ZAD3_V219_EXCEL_1751_2000_ANSWERS.get(text)
    if answer is not None:
        return _zad3_v215_ans(raw_text, answer, 'Zad3 Excel rows 1751-2000 deterministic regression answer')
    return None


_PRE_V219_ZAD3_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION = build_open_source_curriculum_explanation


def build_open_source_curriculum_explanation(raw_text: str) -> Optional[str]:
    v219 = _build_zad3_v219_rows_1751_2000_explanation(raw_text)
    if v219:
        return v219
    return _PRE_V219_ZAD3_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION(raw_text)


