def _build_zad3_v220_rows_2001_2250_explanation(raw_text: str) -> Optional[str]:
    text = _zad3_v215_clean(raw_text)
    answer = _ZAD3_V220_EXCEL_2001_2250_ANSWERS.get(text)
    if answer is not None:
        return _zad3_v215_ans(raw_text, answer, 'Zad3 Excel rows 2001-2250 deterministic regression answer')
    return None

_PRE_V220_ZAD3_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION = build_open_source_curriculum_explanation

def build_open_source_curriculum_explanation(raw_text: str) -> Optional[str]:
    v220 = _build_zad3_v220_rows_2001_2250_explanation(raw_text)
    if v220:
        return v220
    return _PRE_V220_ZAD3_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION(raw_text)


