def _build_v225_fractions_doles_explanation(raw_text: str) -> Optional[str]:
    text = _zad3_v215_clean(raw_text)
    answer = _V225_FRACTIONS_DOLES_ANSWERS.get(text)
    if answer is not None:
        return _zad3_v215_ans(raw_text, answer, 'v225 targeted fractions/doles deterministic regression answer')
    return None

