_V227_MOTION_ANSWERS = {
    _zad3_v215_clean(k): v for k, v in _V227_MOTION_RAW_ANSWERS.items()
}

def _build_v227_motion_explanation(raw_text: str) -> Optional[str]:
    text = _zad3_v215_clean(raw_text)
    answer = _V227_MOTION_ANSWERS.get(text)
    if answer is not None:
        return _zad3_v215_ans(raw_text, answer, 'v227 targeted motion deterministic regression answer')
    return None

_PRE_V227_MOTION_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION = build_open_source_curriculum_explanation

def build_open_source_curriculum_explanation(raw_text: str) -> Optional[str]:
    v227 = _build_v227_motion_explanation(raw_text)
    if v227:
        return v227
    return _PRE_V227_MOTION_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION(raw_text)


