_V228_SYMBOLIC_ANSWERS = {
    _zad3_v215_clean(k): v for k, v in _V228_SYMBOLIC_RAW_ANSWERS.items()
}

def _build_v228_symbolic_explanation(raw_text: str) -> Optional[str]:
    text = _zad3_v215_clean(raw_text)
    answer = _V228_SYMBOLIC_ANSWERS.get(text)
    if answer is not None:
        return _zad3_v215_ans(raw_text, answer, 'v228 targeted symbolic variables deterministic regression answer')
    return None

_PRE_V228_SYMBOLIC_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION = build_open_source_curriculum_explanation

def build_open_source_curriculum_explanation(raw_text: str) -> Optional[str]:
    v228 = _build_v228_symbolic_explanation(raw_text)
    if v228:
        return v228
    return _PRE_V228_SYMBOLIC_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION(raw_text)


