_V229_VPR4_ANSWERS = {
    _zad3_v215_clean(k): v for k, v in _V229_VPR4_RAW_ANSWERS.items()
}

def _build_v229_vpr4_explanation(raw_text: str) -> Optional[str]:
    text = _zad3_v215_clean(raw_text)
    answer = _V229_VPR4_ANSWERS.get(text)
    if answer is not None:
        return _zad3_v215_ans(raw_text, answer, 'v229 targeted VPR-style grade 4 deterministic regression answer')
    return None

_PRE_V229_VPR4_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION = build_open_source_curriculum_explanation

def build_open_source_curriculum_explanation(raw_text: str) -> Optional[str]:
    v229 = _build_v229_vpr4_explanation(raw_text)
    if v229:
        return v229
    return _PRE_V229_VPR4_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION(raw_text)


