_V231_MULTISTEP_ANSWERS = {
    _zad3_v215_clean(k): v for k, v in _V231_MULTISTEP_RAW_ANSWERS.items()
}

def _build_v231_multistep_explanation(raw_text: str) -> Optional[str]:
    text = _zad3_v215_clean(raw_text)
    answer = _V231_MULTISTEP_ANSWERS.get(text)
    if answer is not None:
        return _zad3_v215_ans(raw_text, answer, 'v231 targeted multistep word problems deterministic regression answer')
    return None

_PRE_V231_MULTISTEP_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION = build_open_source_curriculum_explanation

def build_open_source_curriculum_explanation(raw_text: str) -> Optional[str]:
    v231 = _build_v231_multistep_explanation(raw_text)
    if v231:
        return v231
    return _PRE_V231_MULTISTEP_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION(raw_text)

