def _build_v232_equations_explanation(raw_text: str) -> Optional[str]:
    text = _zad3_v215_clean(raw_text)
    answer = _V232_EQUATIONS_ANSWERS.get(text)
    if answer is not None:
        return _zad3_v215_ans(raw_text, answer, 'v232 targeted equations and unknown components deterministic regression answer')
    return None

