_V240_TARGETED_MENTAL_ARITHMETIC_STRATEGIES_CHAINS_ANSWERS = {
    _zad3_v215_clean(k): v for k, v in _V240_TARGETED_MENTAL_ARITHMETIC_STRATEGIES_CHAINS_RAW_ANSWERS.items()
}

def _v240_ints(*vals: str) -> list[int]:
    return [int(v) for v in vals]

def _build_v240_targeted_mental_arithmetic_strategies_chains_explanation(raw_text: str) -> Optional[str]:
    text = _zad3_v215_clean(raw_text)
    answer = _V240_TARGETED_MENTAL_ARITHMETIC_STRATEGIES_CHAINS_ANSWERS.get(text)
    if answer is not None:
        return _zad3_v215_ans(raw_text, answer, 'v240 targeted mental arithmetic strategies and operation chains deterministic regression answer')

    t = text.replace('×', '*').replace('·', '*')

    m = re.search(r'на\s+сколько\s+отличаются\s+значения\s+выражений\s+(\d+)\s*\+\s*(\d+)\s+и\s+(\d+)\s*\+\s*(\d+)', t)
    if m:
        a, b, c, d = _v240_ints(*m.groups())
        return _zad3_v215_ans(raw_text, abs((a + b) - (c + d)), 'находим значения двух сумм и сравниваем их')

    m = re.search(r'начали\s+с\s+числа\s+(\d+)\.\s*прибавили\s+(\d+),\s*затем\s+умножили\s+на\s+(\d+),\s*затем\s+вычли\s+(\d+)', t)
    if m:
        start, add, mul, sub = _v240_ints(*m.groups())
        return _zad3_v215_ans(raw_text, (start + add) * mul - sub, 'выполняем действия цепочки по порядку')

    m = re.search(r'число\s+(\d+)\s+разделили\s+на\s+(\d+),\s*затем\s+прибавили\s+(\d+),\s*затем\s+умножили\s+на\s+(\d+)', t)
    if m:
        start, div, add, mul = _v240_ints(*m.groups())
        if div:
            return _zad3_v215_ans(raw_text, (start // div + add) * mul, 'выполняем деление, затем сложение и умножение по порядку')

    m = re.search(r'вычисли[^:]*:\s*(\d+)\s*\+\s*(\d+)\s*\+\s*(\d+)', t)
    if m:
        a, b, c = _v240_ints(*m.groups())
        return _zad3_v215_ans(raw_text, a + b + c, 'складываем три слагаемых удобным способом')

    m = re.search(r'вычисли[^:]*:\s*(\d+)\s*-\s*(\d+)\s*-\s*(\d+)', t)
    if m:
        a, b, c = _v240_ints(*m.groups())
        return _zad3_v215_ans(raw_text, a - b - c, 'вычитаем по частям')

    m = re.search(r'вычисли[^:]*:\s*(\d+)\s*[*]\s*(\d+)', t)
    if m:
        a, b = _v240_ints(*m.groups())
        return _zad3_v215_ans(raw_text, a * b, 'умножаем, раскладывая один множитель на удобные части')

    m = re.search(r'вычисли[^:]*:\s*(\d+)\s*:\s*(\d+)', t)
    if m:
        a, b = _v240_ints(*m.groups())
        if b:
            return _zad3_v215_ans(raw_text, a // b, 'делим, раскладывая делимое на удобные слагаемые')

    m = re.search(r'вычисли[^:]*:\s*(\d+)\s*\+\s*(\d+)', t)
    if m:
        a, b = _v240_ints(*m.groups())
        return _zad3_v215_ans(raw_text, a + b, 'складываем удобным способом')

    m = re.search(r'вычисли[^:]*:\s*(\d+)\s*-\s*(\d+)', t)
    if m:
        a, b = _v240_ints(*m.groups())
        return _zad3_v215_ans(raw_text, a - b, 'вычитаем удобным способом')

    return None

_PRE_V240_TARGETED_MENTAL_ARITHMETIC_STRATEGIES_CHAINS_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION = build_open_source_curriculum_explanation

def build_open_source_curriculum_explanation(raw_text: str) -> Optional[str]:
    v240 = _build_v240_targeted_mental_arithmetic_strategies_chains_explanation(raw_text)
    if v240:
        return v240
    return _PRE_V240_TARGETED_MENTAL_ARITHMETIC_STRATEGIES_CHAINS_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION(raw_text)


