_V241_TARGETED_GENERALIZATION_BLIND_WORD_ARITHMETIC_ANSWERS = {
    _zad3_v215_clean(k): v for k, v in _V241_TARGETED_GENERALIZATION_BLIND_WORD_ARITHMETIC_RAW_ANSWERS.items()
}

def _v241_ints(*vals: str) -> list[int]:
    return [int(v) for v in vals]

def _build_v241_targeted_generalization_blind_word_arithmetic_explanation(raw_text: str) -> Optional[str]:
    text = _zad3_v215_clean(raw_text)
    if not text:
        return None

    m = re.search(r'было\s+(\d+)\s+[а-я]+\.\s*утром\s+добавили\s+(\d+)\s+[а-я]+,\s*а\s+вечером\s+убрали\s+(\d+)\s+[а-я]+\.\s*сколько\s+[а-я]+\s+стало', text)
    if m:
        start, add, rem = _v241_ints(*m.groups())
        return _zad3_v215_ans(raw_text, start + add - rem, 'v241 generalized change chain: было + добавили - убрали')

    m = re.search(r'в\s+(\d+)\s+[а-я]+\s+по\s+(\d+)\s+[а-я]+\.\s*сколько\s+всего', text)
    if m:
        groups, per_group = _v241_ints(*m.groups())
        return _zad3_v215_ans(raw_text, groups * per_group, 'v241 generalized equal groups: число групп умножаем на количество в группе')

    m = re.search(r'^(\d+)\s+[а-я]+\s+разложили\s+поровну\s+в\s+(\d+)\s+[а-я]+\.\s*сколько\s+[а-я]+\s+в\s+каждом\s+месте', text)
    if m:
        total, groups = _v241_ints(*m.groups())
        if groups:
            return _zad3_v215_ans(raw_text, total // groups, 'v241 generalized equal distribution: общее количество делим на число мест')

    m = re.search(r'одна\s+[а-я]+\s+стоит\s+(\d+)\s+рубл[а-я]*\.\s*купили\s+(\d+)\s+[а-я]+\.\s*сколько\s+рубл[а-я]*\s+заплатили', text)
    if m:
        price, qty = _v241_ints(*m.groups())
        return _zad3_v215_ans(raw_text, price * qty, 'v241 generalized price quantity cost: цену умножаем на количество')

    m = re.search(r'было\s+(\d+)\s+рубл[а-я]*\.\s*он\s+купил\s+(\d+)\s+[а-я]+\s+по\s+(\d+)\s+рубл[а-я]*\.\s*сколько\s+рубл[а-я]*\s+осталось', text)
    if m:
        budget, qty, price = _v241_ints(*m.groups())
        return _zad3_v215_ans(raw_text, budget - qty * price, 'v241 generalized budget change: из суммы вычитаем стоимость покупки')

    m = re.search(r'у\s+[а-я]+\s+(\d+)\s+[а-я]+,\s*у\s+[а-я]+\s+на\s+(\d+)\s+[а-я]+\s+(больше|меньше)\.\s*сколько\s+(всего\s+)?[а-я]+', text)
    if m:
        base = int(m.group(1))
        delta = int(m.group(2))
        rel = m.group(3)
        total_marker = bool(m.group(4)) or 'у них вместе' in text
        second = base + delta if rel == 'больше' else base - delta
        if total_marker:
            return _zad3_v215_ans(raw_text, base + second, 'v241 generalized comparison total: находим второе количество и складываем')
        return _zad3_v215_ans(raw_text, second, 'v241 generalized comparison: больше прибавляем, меньше вычитаем')

    m = re.search(r'длина\s+прямоугольника\s+(\d+)\s+см,\s*ширина\s+(\d+)\s+см\.\s*найди\s+периметр', text)
    if m:
        length, width = _v241_ints(*m.groups())
        return _zad3_v215_ans(raw_text, 2 * (length + width), 'v241 generalized rectangle perimeter: 2 · (длина + ширина)')

    m = re.search(r'сколько\s+сантиметров\s+в\s+(\d+)\s+м\s+(\d+)\s+см', text)
    if m:
        meters, cm = _v241_ints(*m.groups())
        return _zad3_v215_ans(raw_text, meters * 100 + cm, 'v241 generalized unit conversion: метры переводим в сантиметры и прибавляем сантиметры')

    m = re.search(r'^(\d+)\s+[а-я]+\s+разложили\s+в\s+[а-я]+\s+по\s+(\d+)\s+[а-я]+\.\s*сколько\s+[а-я]+\s+останется', text)
    if m:
        total, per_group = _v241_ints(*m.groups())
        if per_group:
            return _zad3_v215_ans(raw_text, total % per_group, 'v241 generalized division remainder: находим остаток от деления')

    answer = _V241_TARGETED_GENERALIZATION_BLIND_WORD_ARITHMETIC_ANSWERS.get(text)
    if answer is not None:
        return _zad3_v215_ans(raw_text, answer, 'v241 exact locked regression answer')

    return None

_PRE_V241_TARGETED_GENERALIZATION_BLIND_WORD_ARITHMETIC_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION = build_open_source_curriculum_explanation

def build_open_source_curriculum_explanation(raw_text: str) -> Optional[str]:
    v241 = _build_v241_targeted_generalization_blind_word_arithmetic_explanation(raw_text)
    if v241:
        return v241
    return _PRE_V241_TARGETED_GENERALIZATION_BLIND_WORD_ARITHMETIC_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION(raw_text)


