_V242_TARGETED_FRACTION_PARTS_ANSWERS = {
    _zad3_v215_clean(k): v for k, v in _V242_TARGETED_FRACTION_PARTS_RAW_ANSWERS.items()
}

_V242_UNIT_FRACTION_WORDS = {
    'половину': 2,
    'треть': 3,
    'четверть': 4,
    'пятую часть': 5,
    'шестую часть': 6,
    'восьмую часть': 8,
    'десятую часть': 10,
}

def _v242_frac_reduce(num: int, den: int) -> str:
    if den == 0:
        return str(num)
    a, b = abs(num), abs(den)
    while b:
        a, b = b, a % b
    g = a or 1
    num //= g
    den //= g
    if den < 0:
        num, den = -num, -den
    if den == 1:
        return str(num)
    return f'{num}/{den}'

def _v242_fraction_value(total: int, num: int, den: int) -> Optional[int]:
    if den == 0:
        return None
    value = total * num
    if value % den != 0:
        return None
    return value // den

def _build_v242_targeted_fraction_parts_generalization_explanation(raw_text: str) -> Optional[str]:
    text = _zad3_v215_clean(raw_text)
    if not text:
        return None

    answer = _V242_TARGETED_FRACTION_PARTS_ANSWERS.get(text)
    if answer is not None:
        return _zad3_v215_ans(raw_text, answer, 'v242 exact locked regression answer')

    m = re.search(r'найди\s+(половину|треть|четверть|пятую часть|шестую часть|восьмую часть|десятую часть)\s+числа\s+(\d+)', text)
    if m:
        den = _V242_UNIT_FRACTION_WORDS[m.group(1)]
        total = int(m.group(2))
        return _zad3_v215_ans(raw_text, total // den, 'v242 generalized unit fraction of a number')

    m = re.search(r'в\s+[а-я]+\s+было\s+(\d+)\s+[а-я]+\.\s*взяли\s+(\d+)/(\d+)\s+всех\s+[а-я]+\.\s*сколько\s+[а-я]+\s+взяли', text)
    if m:
        total, num, den = map(int, m.groups())
        value = _v242_fraction_value(total, num, den)
        if value is not None:
            return _zad3_v215_ans(raw_text, value, 'v242 generalized collection fraction taken')

    m = re.search(r'в\s+[а-я]+\s+было\s+(\d+)\s+[а-я]+\.\s*использовали\s+(\d+)/(\d+)\s+всех\s+[а-я]+\.\s*сколько\s+[а-я]+\s+осталось', text)
    if m:
        total, num, den = map(int, m.groups())
        used = _v242_fraction_value(total, num, den)
        if used is not None:
            return _zad3_v215_ans(raw_text, total - used, 'v242 generalized collection fraction remaining')

    m = re.search(r'1/(\d+)\s+числа\s+равна\s+(\d+)\.\s*найди\s+число', text)
    if m:
        den, part = map(int, m.groups())
        return _zad3_v215_ans(raw_text, part * den, 'v242 generalized whole from unit fraction')

    m = re.search(r'(\d+)/(\d+)\s+числа\s+равны\s+(\d+)\.\s*найди\s+число', text)
    if m:
        num, den, part = map(int, m.groups())
        if num:
            return _zad3_v215_ans(raw_text, part * den // num, 'v242 generalized whole from multiple fraction')

    m = re.search(r'(?:лента|веревка|полоска|дорожка|тесьма)\s+длиной\s+(\d+)\s+см\.\s*отрезали\s+(\d+)/(\d+)\s+(?:ленты|веревки|полоски|дорожки|тесьмы)\.\s*сколько\s+сантиметров\s+отрезали', text)
    if m:
        total, num, den = map(int, m.groups())
        value = _v242_fraction_value(total, num, den)
        if value is not None:
            return _zad3_v215_ans(raw_text, value, 'v242 generalized length fraction cut off')

    m = re.search(r'(?:лента|веревка|полоска|дорожка|тесьма)\s+длиной\s+(\d+)\s+см\.\s*закрасили\s+(\d+)/(\d+)\s+(?:ленты|веревки|полоски|дорожки|тесьмы)\.\s*сколько\s+сантиметров\s+осталось\s+незакрашенными', text)
    if m:
        total, num, den = map(int, m.groups())
        shaded = _v242_fraction_value(total, num, den)
        if shaded is not None:
            return _zad3_v215_ans(raw_text, total - shaded, 'v242 generalized remaining length after shaded fraction')

    m = re.search(r'у\s+[а-я]+\s+было\s+(\d+)\s+рубл[а-я]*\.\s*он\s+потратил\s+(\d+)/(\d+)\s+денег\.\s*сколько\s+рубл[а-я]*\s+потратил', text)
    if m:
        total, num, den = map(int, m.groups())
        value = _v242_fraction_value(total, num, den)
        if value is not None:
            return _zad3_v215_ans(raw_text, value, 'v242 generalized fraction of money spent')

    m = re.search(r'какую\s+часть\s+числа\s+(\d+)\s+составляет\s+число\s+(\d+)', text)
    if m:
        whole, part = map(int, m.groups())
        if whole:
            return _zad3_v215_ans(raw_text, _v242_frac_reduce(part, whole), 'v242 generalized part as fraction of whole')

    m = re.search(r'в\s+(?:прямоугольнике|круге|квадрате|отрезке|полоске)\s+закрашено\s+(\d+)\s+из\s+(\d+)\s+равных\s+частей\.\s*какая\s+доля\s+закрашена', text)
    if m:
        num, den = map(int, m.groups())
        return _zad3_v215_ans(raw_text, _v242_frac_reduce(num, den), 'v242 generalized shaded equal parts as a fraction')

    return None

_PRE_V242_TARGETED_FRACTION_PARTS_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION = build_open_source_curriculum_explanation

def build_open_source_curriculum_explanation(raw_text: str) -> Optional[str]:
    v242 = _build_v242_targeted_fraction_parts_generalization_explanation(raw_text)
    if v242:
        return v242
    return _PRE_V242_TARGETED_FRACTION_PARTS_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION(raw_text)


