_V244_TARGETED_MIXED_SECTIONS_1000_ANSWERS = {
    _zad3_v215_clean(k): v for k, v in _V244_TARGETED_MIXED_SECTIONS_1000_RAW_ANSWERS.items()
}

def _v244_ints(*vals: str) -> list[int]:
    return [int(v) for v in vals]

def _build_v244_targeted_mixed_sections_1000_explanation(raw_text: str) -> Optional[str]:
    text = _zad3_v215_clean(raw_text)
    if not text:
        return None

    answer = _V244_TARGETED_MIXED_SECTIONS_1000_ANSWERS.get(text)
    if answer is not None:
        return _zad3_v215_ans(raw_text, answer, 'v244 exact mixed locked regression answer')

    m = re.search(r'^в блокноте записали\s+(\d+)\s+примеров,\s+затем добавили\s+(\d+)\s+примеров\.\s*сколько\s+примеров\s+стало\s+в\s+блокноте', text)
    if m:
        a, b = _v244_ints(*m.groups())
        return _zad3_v215_ans(raw_text, a + b, 'v244 generalized mixed: addition total')

    m = re.search(r'^в папке лежало\s+(\d+)\s+листов,\s+из нее вынули\s+(\d+)\s+листов\.\s*сколько\s+листов\s+осталось\s+в\s+папке', text)
    if m:
        a, b = _v244_ints(*m.groups())
        return _zad3_v215_ans(raw_text, a - b, 'v244 generalized mixed: subtraction remaining')

    m = re.search(r'^у первой команды\s+(\d+)\s+очков,\s+у второй на\s+(\d+)\s+очков больше\.\s*сколько\s+очков\s+у\s+второй\s+команды', text)
    if m:
        a, d = _v244_ints(*m.groups())
        return _zad3_v215_ans(raw_text, a + d, 'v244 generalized mixed: comparison more')

    m = re.search(r'^у старшего брата\s+(\d+)\s+марок,\s+у младшего на\s+(\d+)\s+марок меньше\.\s*сколько\s+марок\s+у\s+младшего\s+брата', text)
    if m:
        a, d = _v244_ints(*m.groups())
        return _zad3_v215_ans(raw_text, a - d, 'v244 generalized mixed: comparison less')

    m = re.search(r'^в каждой коробке по\s+(\d+)\s+фломастеров\.\s*сколько\s+фломастеров\s+в\s+(\d+)\s+коробках', text)
    if m:
        a, b = _v244_ints(*m.groups())
        return _zad3_v215_ans(raw_text, a * b, 'v244 generalized mixed: multiplication equal groups')

    m = re.search(r'^(\d+)\s+открыток раздали поровну\s+(\d+)\s+детям\.\s*сколько\s+открыток\s+получил\s+каждый\s+ребенок', text)
    if m:
        total, groups = _v244_ints(*m.groups())
        if groups:
            return _zad3_v215_ans(raw_text, total // groups, 'v244 generalized mixed: division equal sharing')

    m = re.search(r'^реши уравнение:\s*x\s*\+\s*(\d+)\s*=\s*(\d+)\.\s*чему\s+равен\s+x', text)
    if m:
        a, b = _v244_ints(*m.groups())
        return _zad3_v215_ans(raw_text, b - a, 'v244 generalized mixed: equation x plus a')

    m = re.search(r'^реши уравнение:\s*(\d+)\s*-\s*x\s*=\s*(\d+)\.\s*найди\s+x', text)
    if m:
        a, b = _v244_ints(*m.groups())
        return _zad3_v215_ans(raw_text, a - b, 'v244 generalized mixed: equation a minus x')

    m = re.search(r'^найди значение выражения\s+(\d+)\s*\+\s*(\d+)\s*\*\s*(\d+)\s*-\s*(\d+)', text)
    if m:
        a, b, c, d = _v244_ints(*m.groups())
        return _zad3_v215_ans(raw_text, a + b * c - d, 'v244 generalized mixed: order of operations')

    m = re.search(r'^какое число получится, если взять\s+(\d+)-ю\s+часть\s+от\s+(\d+)', text)
    if m:
        k, n = _v244_ints(*m.groups())
        if k:
            return _zad3_v215_ans(raw_text, n // k, 'v244 generalized mixed: fraction part of number')

    m = re.search(r'^если\s+(\d+)-я\s+часть\s+неизвестного\s+числа\s+равна\s+(\d+),\s*чему\s+равно\s+все\s+число', text)
    if m:
        k, part = _v244_ints(*m.groups())
        return _zad3_v215_ans(raw_text, k * part, 'v244 generalized mixed: whole by fraction part')

    m = re.search(r'^на схеме указали\s+(\d+)\s+м\s+(\d+)\s+см\.\s*сколько\s+сантиметров\s+это\s+составляет', text)
    if m:
        meters, cm = _v244_ints(*m.groups())
        return _zad3_v215_ans(raw_text, meters * 100 + cm, 'v244 generalized mixed: meters centimeters to centimeters')

    m = re.search(r'^посылка имеет массу\s+(\d+)\s+кг\s+(\d+)\s+г\.\s*сколько\s+граммов\s+это\s+составляет', text)
    if m:
        kg, g = _v244_ints(*m.groups())
        return _zad3_v215_ans(raw_text, kg * 1000 + g, 'v244 generalized mixed: kilograms grams to grams')

    m = re.search(r'^сеанс продолжался\s+(\d+)\s+ч\s+(\d+)\s+мин\.\s*сколько\s+минут\s+это\s+составляет', text)
    if m:
        hours, minutes = _v244_ints(*m.groups())
        return _zad3_v215_ans(raw_text, hours * 60 + minutes, 'v244 generalized mixed: hours minutes to minutes')

    m = re.search(r'^цена одного блокнота\s+(\d+)\s+руб\.\s*купили\s+(\d+)\s+блокнотов\.\s*сколько\s+рублей\s+нужно\s+заплатить', text)
    if m:
        price, qty = _v244_ints(*m.groups())
        return _zad3_v215_ans(raw_text, price * qty, 'v244 generalized mixed: money price quantity cost')

    m = re.search(r'^на покупку дали\s+(\d+)\s+руб,\s+а чек составил\s+(\d+)\s+руб\.\s*сколько\s+рублей\s+сдачи\s+получат', text)
    if m:
        money, cost = _v244_ints(*m.groups())
        return _zad3_v215_ans(raw_text, money - cost, 'v244 generalized mixed: money change')

    m = re.search(r'^у прямоугольной рамки стороны\s+(\d+)\s+см\s+и\s+(\d+)\s+см\.\s*чему\s+равен\s+ее\s+периметр', text)
    if m:
        a, b = _v244_ints(*m.groups())
        return _zad3_v215_ans(raw_text, 2 * (a + b), 'v244 generalized mixed: rectangle perimeter')

    m = re.search(r'^у прямоугольной плитки стороны\s+(\d+)\s+см\s+и\s+(\d+)\s+см\.\s*чему\s+равна\s+ее\s+площадь', text)
    if m:
        a, b = _v244_ints(*m.groups())
        return _zad3_v215_ans(raw_text, a * b, 'v244 generalized mixed: rectangle area')

    m = re.search(r'^автобус ехал со скоростью\s+(\d+)\s+км/ч\s+(\d+)\s+ч\.\s*какое\s+расстояние\s+он\s+проехал', text)
    if m:
        speed, time = _v244_ints(*m.groups())
        return _zad3_v215_ans(raw_text, speed * time, 'v244 generalized mixed: speed time distance')

    m = re.search(r'^(\d+)\s+печений раскладывают в пакеты по\s+(\d+)\s+печений\.\s*сколько\s+печений\s+не\s+войдет\s+в\s+полные\s+пакеты', text)
    if m:
        total, group = _v244_ints(*m.groups())
        if group:
            return _zad3_v215_ans(raw_text, total % group, 'v244 generalized mixed: division with remainder')

    m = re.search(r'^по диаграмме видно:\s+красных шаров\s*-\s*(\d+),\s+синих\s*-\s*(\d+),\s+зеленых\s*-\s*(\d+)\.\s*сколько\s+шаров\s+всего', text)
    if m:
        a, b, c = _v244_ints(*m.groups())
        return _zad3_v215_ans(raw_text, a + b + c, 'v244 generalized mixed: data diagram sum')

    return None

_PRE_V244_TARGETED_MIXED_SECTIONS_1000_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION = build_open_source_curriculum_explanation

def build_open_source_curriculum_explanation(raw_text: str) -> Optional[str]:
    v244 = _build_v244_targeted_mixed_sections_1000_explanation(raw_text)
    if v244:
        return v244
    return _PRE_V244_TARGETED_MIXED_SECTIONS_1000_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION(raw_text)


# --- v245: pure blind mixed 1000-case generalized regression ---
# No exact task-answer lookup is used in this layer. Every task is solved by a
# generalized pattern so the package tests template generalization rather than
# memorized full-text answers.

def _v245_ints(*vals: str) -> list[int]:
    return [int(v) for v in vals]


def _v245_round_half_up(n: int, step: int) -> int:
    return (n // step + (1 if n % step >= step / 2 else 0)) * step


def _build_v245_targeted_mixed_pure_blind_1000_explanation(raw_text: str) -> Optional[str]:
    text = _zad3_v215_clean(raw_text)
    if not text:
        return None

    m = re.search(r'^в наборе было\s+(\d+)\s+карточек\.\s*учитель добавил\s+(\d+)\s+карточек\.\s*сколько карточек стало в наборе', text)
    if m:
        a, b = _v245_ints(*m.groups())
        return _zad3_v215_ans(raw_text, a + b, 'v245 generalized pure blind: addition total')

    m = re.search(r'^на стенде висело\s+(\d+)\s+рисунков\.\s*сняли\s+(\d+)\s+рисунков\.\s*сколько рисунков осталось на стенде', text)
    if m:
        a, b = _v245_ints(*m.groups())
        return _zad3_v215_ans(raw_text, a - b, 'v245 generalized pure blind: subtraction remaining')

    m = re.search(r'^у лены\s+(\d+)\s+марок,\s*а у коли на\s+(\d+)\s+марок больше\.\s*сколько марок у коли', text)
    if m:
        a, d = _v245_ints(*m.groups())
        return _zad3_v215_ans(raw_text, a + d, 'v245 generalized pure blind: comparison more')

    m = re.search(r'^у сережи\s+(\d+)\s+наклеек,\s*а у вики на\s+(\d+)\s+наклеек меньше\.\s*сколько наклеек у вики', text)
    if m:
        a, d = _v245_ints(*m.groups())
        return _zad3_v215_ans(raw_text, a - d, 'v245 generalized pure blind: comparison less')

    m = re.search(r'^в первом альбоме\s+(\d+)\s+фотографий,\s*во втором\s+(\d+)\s+фотографий\.\s*сколько фотографий в двух альбомах', text)
    if m:
        a, b = _v245_ints(*m.groups())
        return _zad3_v215_ans(raw_text, a + b, 'v245 generalized pure blind: sum two subjects')

    m = re.search(r'^в синей папке\s+(\d+)\s+листов,\s*а в зеленой\s+(\d+)\s+листов\.\s*на сколько листов в синей папке больше', text)
    if m:
        a, b = _v245_ints(*m.groups())
        return _zad3_v215_ans(raw_text, a - b, 'v245 generalized pure blind: difference how many more')

    m = re.search(r'^в каждой вазе по\s+(\d+)\s+цветков\.\s*сколько цветков в\s+(\d+)\s+таких вазах', text)
    if m:
        per, count = _v245_ints(*m.groups())
        return _zad3_v215_ans(raw_text, per * count, 'v245 generalized pure blind: multiplication equal groups')

    m = re.search(r'^(\d+)\s+орехов разложили поровну в\s+(\d+)\s+мисок\.\s*сколько орехов в каждой миске', text)
    if m:
        total, groups = _v245_ints(*m.groups())
        if groups:
            return _zad3_v215_ans(raw_text, total // groups, 'v245 generalized pure blind: division equal sharing')

    m = re.search(r'^(\d+)\s+карандашей раскладывают по\s+(\d+)\s+карандашей в стакан\.\s*сколько стаканов понадобится', text)
    if m:
        total, per = _v245_ints(*m.groups())
        if per:
            return _zad3_v215_ans(raw_text, total // per, 'v245 generalized pure blind: division groups count')

    m = re.search(r'^(\d+)\s+яблок раскладывают в пакеты по\s+(\d+)\s+яблока\.\s*сколько яблок останется', text)
    if m:
        total, per = _v245_ints(*m.groups())
        if per:
            return _zad3_v215_ans(raw_text, total % per, 'v245 generalized pure blind: division remainder')

    m = re.search(r'^реши уравнение:\s*x\s*\+\s*(\d+)\s*=\s*(\d+)\.\s*чему равен x', text)
    if m:
        a, b = _v245_ints(*m.groups())
        return _zad3_v215_ans(raw_text, b - a, 'v245 generalized pure blind: equation x plus a')

    m = re.search(r'^реши уравнение:\s*x\s*-\s*(\d+)\s*=\s*(\d+)\.\s*чему равен x', text)
    if m:
        a, b = _v245_ints(*m.groups())
        return _zad3_v215_ans(raw_text, a + b, 'v245 generalized pure blind: equation x minus a')

    m = re.search(r'^реши уравнение:\s*(\d+)\s*-\s*x\s*=\s*(\d+)\.\s*чему равен x', text)
    if m:
        a, b = _v245_ints(*m.groups())
        return _zad3_v215_ans(raw_text, a - b, 'v245 generalized pure blind: equation a minus x')

    m = re.search(r'^реши уравнение:\s*x\s*\*\s*(\d+)\s*=\s*(\d+)\.\s*найди x', text)
    if m:
        a, b = _v245_ints(*m.groups())
        if a:
            return _zad3_v215_ans(raw_text, b // a, 'v245 generalized pure blind: equation x times a')

    m = re.search(r'^реши уравнение:\s*(\d+)\s*\*\s*x\s*=\s*(\d+)\.\s*найди x', text)
    if m:
        a, b = _v245_ints(*m.groups())
        if a:
            return _zad3_v215_ans(raw_text, b // a, 'v245 generalized pure blind: equation a times x')

    m = re.search(r'^реши уравнение:\s*x\s*:\s*(\d+)\s*=\s*(\d+)\.\s*найди x', text)
    if m:
        a, b = _v245_ints(*m.groups())
        return _zad3_v215_ans(raw_text, a * b, 'v245 generalized pure blind: equation x divided by a')

    m = re.search(r'^реши уравнение:\s*(\d+)\s*:\s*x\s*=\s*(\d+)\.\s*найди x', text)
    if m:
        a, b = _v245_ints(*m.groups())
        if b:
            return _zad3_v215_ans(raw_text, a // b, 'v245 generalized pure blind: equation a divided by x')

    m = re.search(r'^проверь подстановкой:\s*при x\s*=\s*(\d+)\s+значение выражения x\s*\+\s*(\d+)\.\s*какой результат получится', text)
    if m:
        x, a = _v245_ints(*m.groups())
        return _zad3_v215_ans(raw_text, x + a, 'v245 generalized pure blind: substitution check x plus a')

    m = re.search(r'^неизвестное число увеличили на\s+(\d+)\s+и получили\s+(\d+)\.\s*найди неизвестное число', text)
    if m:
        a, b = _v245_ints(*m.groups())
        return _zad3_v215_ans(raw_text, b - a, 'v245 generalized pure blind: unknown addend text')

    m = re.search(r'^неизвестное число умножили на\s+(\d+)\s+и получили\s+(\d+)\.\s*найди неизвестное число', text)
    if m:
        a, b = _v245_ints(*m.groups())
        if a:
            return _zad3_v215_ans(raw_text, b // a, 'v245 generalized pure blind: unknown multiplier text')

    m = re.search(r'^найди значение выражения\s+(\d+)\s*\+\s*(\d+)\s*\*\s*(\d+)\s*-\s*(\d+)', text)
    if m:
        a, b, c, d = _v245_ints(*m.groups())
        return _zad3_v215_ans(raw_text, a + b * c - d, 'v245 generalized pure blind: order of operations')

    m = re.search(r'^найди значение выражения\s*\(\s*(\d+)\s*\+\s*(\d+)\s*\)\s*\*\s*(\d+)', text)
    if m:
        a, b, c = _v245_ints(*m.groups())
        return _zad3_v215_ans(raw_text, (a + b) * c, 'v245 generalized pure blind: parentheses expression')

    m = re.search(r'^на сколько значение выражения\s+(\d+)\s*\*\s*(\d+)\s+больше значения выражения\s+(\d+)\s*\+\s*(\d+)', text)
    if m:
        a, b, c, d = _v245_ints(*m.groups())
        return _zad3_v215_ans(raw_text, a * b - (c + d), 'v245 generalized pure blind: compare expressions difference')

    m = re.search(r'^сначала к числу\s+(\d+)\s+прибавили\s+(\d+),\s*потом результат умножили на\s+(\d+)\.\s*какое число получили', text)
    if m:
        a, b, c = _v245_ints(*m.groups())
        return _zad3_v215_ans(raw_text, (a + b) * c, 'v245 generalized pure blind: add then multiply chain')

    m = re.search(r'^от числа\s+(\d+)\s+отняли\s+(\d+),\s*затем прибавили\s+(\d+)\.\s*какой результат получили', text)
    if m:
        a, b, c = _v245_ints(*m.groups())
        return _zad3_v215_ans(raw_text, a - b + c, 'v245 generalized pure blind: subtract then add chain')

    m = re.search(r'^округли число\s+(\d+)\s+до (?:десятков|ближайшего десятка)', text)
    if m:
        n = int(m.group(1))
        return _zad3_v215_ans(raw_text, _v245_round_half_up(n, 10), 'v245 generalized pure blind: round to tens')

    m = re.search(r'^сколько полных десятков содержится в числе\s+(\d+)', text)
    if m:
        n = int(m.group(1))
        return _zad3_v215_ans(raw_text, n // 10, 'v245 generalized pure blind: full tens in number')

    m = re.search(r'^в числе\s+(\d+)\s+какая цифра стоит в разряде десятков', text)
    if m:
        n = int(m.group(1))
        return _zad3_v215_ans(raw_text, (n // 10) % 10, 'v245 generalized pure blind: tens digit place value')

    m = re.search(r'^округли число\s+(\d+)\s+до сотен', text)
    if m:
        n = int(m.group(1))
        return _zad3_v215_ans(raw_text, _v245_round_half_up(n, 100), 'v245 generalized pure blind: round to hundreds')

    m = re.search(r'^оцени сумму,\s*округлив каждое число до десятков:\s*(\d+)\s*\+\s*(\d+)\.\s*какой результат оценки', text)
    if m:
        a, b = _v245_ints(*m.groups())
        return _zad3_v215_ans(raw_text, _v245_round_half_up(a, 10) + _v245_round_half_up(b, 10), 'v245 generalized pure blind: estimate sum rounded to tens')

    m = re.search(r'^найди\s+(\d+)-ю часть числа\s+(\d+)', text)
    if m:
        k, n = _v245_ints(*m.groups())
        if k:
            return _zad3_v215_ans(raw_text, n // k, 'v245 generalized pure blind: fraction part of number')

    m = re.search(r'^величина\s+(\d+)-й части равна\s+(\d+)\.\s*каково целое число', text)
    if m:
        k, part = _v245_ints(*m.groups())
        return _zad3_v215_ans(raw_text, k * part, 'v245 generalized pure blind: whole by unit fraction')

    m = re.search(r'^от ленты длиной\s+(\d+)\s+см отрезали\s+(\d+)-ю часть\.\s*сколько сантиметров осталось', text)
    if m:
        n, k = _v245_ints(*m.groups())
        if k:
            return _zad3_v215_ans(raw_text, n - n // k, 'v245 generalized pure blind: fraction remaining after cut')

    m = re.search(r'^в саду\s+(\d+)\s+деревьев,\s*(\d+)\s*/\s*(\d+)\s+из них яблони\.\s*сколько яблонь в саду', text)
    if m:
        total, num, den = _v245_ints(*m.groups())
        if den:
            return _zad3_v215_ans(raw_text, total * num // den, 'v245 generalized pure blind: multiple fraction of collection')

    m = re.search(r'^у прямоугольника\s+(\d+)\s+равных частей,\s*закрасили\s+(\d+)\.\s*сколько частей не закрасили', text)
    if m:
        total, shaded = _v245_ints(*m.groups())
        return _zad3_v215_ans(raw_text, total - shaded, 'v245 generalized pure blind: unshaded equal parts')

    m = re.search(r'^(?:длина отрезка\s+|длину записали как\s+)(\d+)\s+м\s+(\d+)\s+см\.\s*сколько это сантиметров', text)
    if m:
        meters, cm = _v245_ints(*m.groups())
        return _zad3_v215_ans(raw_text, meters * 100 + cm, 'v245 generalized pure blind: meters centimeters to centimeters')

    m = re.search(r'^веревка длиной\s+(\d+)\s+дм\s+(\d+)\s+см\.\s*сколько это сантиметров', text)
    if m:
        dm, cm = _v245_ints(*m.groups())
        return _zad3_v215_ans(raw_text, dm * 10 + cm, 'v245 generalized pure blind: decimeters centimeters to centimeters')

    m = re.search(r'^масса посылки\s+(\d+)\s+кг\s+(\d+)\s+г\.\s*сколько это граммов', text)
    if m:
        kg, g = _v245_ints(*m.groups())
        return _zad3_v215_ans(raw_text, kg * 1000 + g, 'v245 generalized pure blind: kilograms grams to grams')

    m = re.search(r'^тренировка длилась\s+(\d+)\s+ч\s+(\d+)\s+мин\.\s*сколько это минут', text)
    if m:
        hours, minutes = _v245_ints(*m.groups())
        return _zad3_v215_ans(raw_text, hours * 60 + minutes, 'v245 generalized pure blind: hours minutes to minutes')

    m = re.search(r'^цена равна\s+(\d+)\s+руб\s+(\d+)\s+коп\.\s*сколько это копеек', text)
    if m:
        rub, kop = _v245_ints(*m.groups())
        return _zad3_v215_ans(raw_text, rub * 100 + kop, 'v245 generalized pure blind: rubles kopecks to kopecks')

    m = re.search(r'^одна тетрадь стоит\s+(\d+)\s+руб\.\s*купили\s+(\d+)\s+тетради\.\s*сколько рублей заплатили', text)
    if m:
        price, qty = _v245_ints(*m.groups())
        return _zad3_v215_ans(raw_text, price * qty, 'v245 generalized pure blind: money price quantity cost')

    m = re.search(r'^покупатель дал\s+(\d+)\s+руб\.\s*покупка стоила\s+(\d+)\s+руб\.\s*сколько рублей сдачи он получил', text)
    if m:
        money, cost = _v245_ints(*m.groups())
        return _zad3_v215_ans(raw_text, money - cost, 'v245 generalized pure blind: money change')

    m = re.search(r'^у класса было\s+(\d+)\s+руб\.\s*купили\s+(\d+)\s+альбомов по\s+(\d+)\s+руб\.\s*сколько рублей осталось', text)
    if m:
        budget, qty, price = _v245_ints(*m.groups())
        return _zad3_v215_ans(raw_text, budget - qty * price, 'v245 generalized pure blind: money budget remaining')

    m = re.search(r'^прямоугольник имеет стороны\s+(\d+)\s+см и\s+(\d+)\s+см\.\s*найди его периметр', text)
    if m:
        a, b = _v245_ints(*m.groups())
        return _zad3_v215_ans(raw_text, 2 * (a + b), 'v245 generalized pure blind: rectangle perimeter')

    m = re.search(r'^прямоугольная площадка имеет стороны\s+(\d+)\s+м и\s+(\d+)\s+м\.\s*найди площадь площадки', text)
    if m:
        a, b = _v245_ints(*m.groups())
        return _zad3_v215_ans(raw_text, a * b, 'v245 generalized pure blind: rectangle area')

    m = re.search(r'^сторона квадрата\s+(\d+)\s+см\.\s*чему равен периметр квадрата', text)
    if m:
        side = int(m.group(1))
        return _zad3_v215_ans(raw_text, 4 * side, 'v245 generalized pure blind: square perimeter')

    m = re.search(r'^(?:пешеход|курьер) шел со скоростью\s+(\d+)\s+км/ч\s+(\d+)\s+ч\.\s*какое расстояние он прошел', text)
    if m:
        speed, time = _v245_ints(*m.groups())
        return _zad3_v215_ans(raw_text, speed * time, 'v245 generalized pure blind: motion distance speed time')

    m = re.search(r'^(?:поезд прошел|электричка прошла)\s+(\d+)\s+км со скоростью\s+(\d+)\s+км/ч\.\s*сколько часов (?:он|она) был(?:а)? в пути', text)
    if m:
        distance, speed = _v245_ints(*m.groups())
        if speed:
            return _zad3_v215_ans(raw_text, distance // speed, 'v245 generalized pure blind: motion time distance speed')

    m = re.search(r'^в таблице указано:\s*яблок\s*-\s*(\d+),\s*груш\s*-\s*(\d+),\s*слив\s*-\s*(\d+)\.\s*сколько фруктов всего', text)
    if m:
        a, b, c = _v245_ints(*m.groups())
        return _zad3_v215_ans(raw_text, a + b + c, 'v245 generalized pure blind: data table sum')

    m = re.search(r'^по диаграмме:\s*в понедельник\s+(\d+)\s+посетителей,\s*во вторник\s+(\d+)\s+посетителей\.\s*на сколько посетителей во вторник больше', text)
    if m:
        a, b = _v245_ints(*m.groups())
        return _zad3_v215_ans(raw_text, b - a, 'v245 generalized pure blind: data chart difference')

    return None


_PRE_V245_TARGETED_MIXED_PURE_BLIND_1000_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION = build_open_source_curriculum_explanation


def build_open_source_curriculum_explanation(raw_text: str) -> Optional[str]:
    v245 = _build_v245_targeted_mixed_pure_blind_1000_explanation(raw_text)
    if v245:
        return v245
    return _PRE_V245_TARGETED_MIXED_PURE_BLIND_1000_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION(raw_text)

# --- v246: adversarial paraphrases 1000-case pure blind regression ---
# This layer intentionally avoids exact task-answer lookup. It parses broad
# paraphrase families and solves by arithmetic structure.

def _v246_numbers(text: str) -> list[int]:
    return [int(x) for x in re.findall(r'(?<![\w/])\d+(?![\w/])', text)]


def _v246_round_half_up(n: int, step: int) -> int:
    return (n // step + (1 if n % step >= step / 2 else 0)) * step


def _build_v246_targeted_adversarial_paraphrases_1000_explanation(raw_text: str) -> Optional[str]:
    text = _zad3_v215_clean(raw_text)
    if not text:
        return None
    nums = _v246_numbers(text)

    # Unknown components of arithmetic operations.
    m = re.search(r'чтобы получить\s+(\d+),\s*к числу\s+(\d+)\s+прибавили неизвестное число', text)
    if m:
        total, known = map(int, m.groups())
        return _zad3_v215_ans(raw_text, total - known, 'v246 generalized adversarial: unknown addend')
    m = re.search(r'к\s+(\d+)\s+прибавили некоторое число и получили\s+(\d+)', text)
    if m:
        known, total = map(int, m.groups())
        return _zad3_v215_ans(raw_text, total - known, 'v246 generalized adversarial: unknown addend')
    m = re.search(r'сумма числа\s+(\d+)\s+и неизвестного числа равна\s+(\d+)', text)
    if m:
        known, total = map(int, m.groups())
        return _zad3_v215_ans(raw_text, total - known, 'v246 generalized adversarial: unknown addend')
    m = re.search(r'(\d+)\s+плюс неизвестное число дает\s+(\d+)', text)
    if m:
        known, total = map(int, m.groups())
        return _zad3_v215_ans(raw_text, total - known, 'v246 generalized adversarial: unknown addend')

    m = re.search(r'из неизвестного числа вычли\s+(\d+)\s+и получили\s+(\d+)', text)
    if m:
        sub, result = map(int, m.groups())
        return _zad3_v215_ans(raw_text, sub + result, 'v246 generalized adversarial: unknown minuend')
    m = re.search(r'какое число надо уменьшить на\s+(\d+),\s*чтобы получить\s+(\d+)', text)
    if m:
        sub, result = map(int, m.groups())
        return _zad3_v215_ans(raw_text, sub + result, 'v246 generalized adversarial: unknown minuend')
    m = re.search(r'неизвестное число минус\s+(\d+)\s+равно\s+(\d+)', text)
    if m:
        sub, result = map(int, m.groups())
        return _zad3_v215_ans(raw_text, sub + result, 'v246 generalized adversarial: unknown minuend')
    m = re.search(r'после вычитания\s+(\d+)\s+из неизвестного числа получилось\s+(\d+)', text)
    if m:
        sub, result = map(int, m.groups())
        return _zad3_v215_ans(raw_text, sub + result, 'v246 generalized adversarial: unknown minuend')

    m = re.search(r'из\s+(\d+)\s+вычли неизвестное число и получили\s+(\d+)', text)
    if m:
        minuend, result = map(int, m.groups())
        return _zad3_v215_ans(raw_text, minuend - result, 'v246 generalized adversarial: unknown subtrahend')
    m = re.search(r'(\d+)\s+минус некоторое число равно\s+(\d+)', text)
    if m:
        minuend, result = map(int, m.groups())
        return _zad3_v215_ans(raw_text, minuend - result, 'v246 generalized adversarial: unknown subtrahend')
    m = re.search(r'какое число надо вычесть из\s+(\d+),\s*чтобы получилось\s+(\d+)', text)
    if m:
        minuend, result = map(int, m.groups())
        return _zad3_v215_ans(raw_text, minuend - result, 'v246 generalized adversarial: unknown subtrahend')
    m = re.search(r'после вычитания неизвестного числа из\s+(\d+)\s+осталось\s+(\d+)', text)
    if m:
        minuend, result = map(int, m.groups())
        return _zad3_v215_ans(raw_text, minuend - result, 'v246 generalized adversarial: unknown subtrahend')

    m = re.search(r'неизвестное число умножили на\s+(\d+)\s+и получили\s+(\d+)', text)
    if m:
        factor, product = map(int, m.groups())
        if factor:
            return _zad3_v215_ans(raw_text, product // factor, 'v246 generalized adversarial: unknown factor')
    m = re.search(r'некоторое число увеличили в\s+(\d+)\s+раза и получили\s+(\d+)', text)
    if m:
        factor, product = map(int, m.groups())
        if factor:
            return _zad3_v215_ans(raw_text, product // factor, 'v246 generalized adversarial: unknown factor')
    m = re.search(r'произведение неизвестного числа и\s+(\d+)\s+равно\s+(\d+)', text)
    if m:
        factor, product = map(int, m.groups())
        if factor:
            return _zad3_v215_ans(raw_text, product // factor, 'v246 generalized adversarial: unknown factor')
    m = re.search(r'число умножили на\s+(\d+);\s*результат\s+(\d+)', text)
    if m:
        factor, product = map(int, m.groups())
        if factor:
            return _zad3_v215_ans(raw_text, product // factor, 'v246 generalized adversarial: unknown factor')

    m = re.search(r'неизвестное число разделили на\s+(\d+)\s+и получили\s+(\d+)', text)
    if m:
        divisor, quotient = map(int, m.groups())
        return _zad3_v215_ans(raw_text, divisor * quotient, 'v246 generalized adversarial: unknown dividend')
    m = re.search(r'какое число при делении на\s+(\d+)\s+дает\s+(\d+)', text)
    if m:
        divisor, quotient = map(int, m.groups())
        return _zad3_v215_ans(raw_text, divisor * quotient, 'v246 generalized adversarial: unknown dividend')
    m = re.search(r'делимое неизвестно: его разделили на\s+(\d+),\s*получилось\s+(\d+)', text)
    if m:
        divisor, quotient = map(int, m.groups())
        return _zad3_v215_ans(raw_text, divisor * quotient, 'v246 generalized adversarial: unknown dividend')
    m = re.search(r'число поделили на\s+(\d+);\s*частное равно\s+(\d+)', text)
    if m:
        divisor, quotient = map(int, m.groups())
        return _zad3_v215_ans(raw_text, divisor * quotient, 'v246 generalized adversarial: unknown dividend')

    m = re.search(r'(\d+)\s+разделили на неизвестное число и получили\s+(\d+)', text)
    if m:
        dividend, quotient = map(int, m.groups())
        if quotient:
            return _zad3_v215_ans(raw_text, dividend // quotient, 'v246 generalized adversarial: unknown divisor')
    m = re.search(r'на какое число надо разделить\s+(\d+),\s*чтобы получить\s+(\d+)', text)
    if m:
        dividend, quotient = map(int, m.groups())
        if quotient:
            return _zad3_v215_ans(raw_text, dividend // quotient, 'v246 generalized adversarial: unknown divisor')
    m = re.search(r'делитель неизвестен:\s*(\d+)\s+разделили на него и получили\s+(\d+)', text)
    if m:
        dividend, quotient = map(int, m.groups())
        if quotient:
            return _zad3_v215_ans(raw_text, dividend // quotient, 'v246 generalized adversarial: unknown divisor')
    m = re.search(r'(\d+)\s*:\s*неизвестное число\s*=\s*(\d+)', text)
    if m:
        dividend, quotient = map(int, m.groups())
        if quotient:
            return _zad3_v215_ans(raw_text, dividend // quotient, 'v246 generalized adversarial: unknown divisor')

    # Expressions and order of operations.
    m = re.search(r'(?:найди значение выражения:|вычисли без скобок|порядок действий:|посчитай выражение)\s*(\d+)\s*\+\s*(\d+)\s*[·*×]\s*(\d+)', text)
    if m:
        a, b, c = map(int, m.groups())
        return _zad3_v215_ans(raw_text, a + b * c, 'v246 generalized adversarial: multiplication before addition')
    m = re.search(r'(?:посчитай:|найди значение выражения|действие в скобках:|вычисли выражение)\s*\(\s*(\d+)\s*\+\s*(\d+)\s*\)\s*[·*×]\s*(\d+)', text)
    if m:
        a, b, c = map(int, m.groups())
        return _zad3_v215_ans(raw_text, (a + b) * c, 'v246 generalized adversarial: parentheses then multiplication')
    m = re.search(r'(?:посчитай:|найди значение выражения|вычисли выражение)\s*(\d+)\s*-\s*\(\s*(\d+)\s*\+\s*(\d+)\s*\)', text)
    if m:
        a, b, c = map(int, m.groups())
        return _zad3_v215_ans(raw_text, a - (b + c), 'v246 generalized adversarial: subtract parenthesized sum')
    m = re.search(r'из\s+(\d+)\s+вычти сумму чисел\s+(\d+)\s+и\s+(\d+)', text)
    if m:
        a, b, c = map(int, m.groups())
        return _zad3_v215_ans(raw_text, a - (b + c), 'v246 generalized adversarial: subtract sum in words')
    m = re.search(r'(?:найди значение:|вычисли выражение|сначала выполни деление:|посчитай)\s*(\d+)\s*(?::|/)\s*(\d+)\s*\+\s*(\d+)', text)
    if m:
        a, b, c = map(int, m.groups())
        if b:
            return _zad3_v215_ans(raw_text, a // b + c, 'v246 generalized adversarial: division before addition')
    m = re.search(r'на сколько значение выражения\s+(\d+)\s*\+\s*(\d+)\s+больше значения выражения\s+(\d+)\s*\+\s*(\d+)', text)
    if m:
        a, b, c, d = map(int, m.groups())
        return _zad3_v215_ans(raw_text, (a + b) - (c + d), 'v246 generalized adversarial: difference between expression values')
    m = re.search(r'найди разность значений выражений\s+(\d+)\s*\+\s*(\d+)\s+и\s+(\d+)\s*\+\s*(\d+)', text)
    if m:
        a, b, c, d = map(int, m.groups())
        return _zad3_v215_ans(raw_text, (a + b) - (c + d), 'v246 generalized adversarial: expression value difference')
    m = re.search(r'первое выражение:\s*(\d+)\s*\+\s*(\d+),\s*второе:\s*(\d+)\s*\+\s*(\d+).*?на сколько первое значение больше второго', text)
    if m:
        a, b, c, d = map(int, m.groups())
        return _zad3_v215_ans(raw_text, (a + b) - (c + d), 'v246 generalized adversarial: expression value difference')
    m = re.search(r'сравни суммы\s+(\d+)\s*\+\s*(\d+)\s+и\s+(\d+)\s*\+\s*(\d+):\s*какова разница', text)
    if m:
        a, b, c, d = map(int, m.groups())
