# --- v253 release hardening: live user input normalization ---
# General input cleanup for real-user wrappers and omitted terminal punctuation.
# This does not store exact tasks or answers; it only normalizes the submitted
# single task before existing generalized handlers process it.
_PRE_V253_LIVE_INPUT_NORMALIZATION_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION = build_open_source_curriculum_explanation


def _v253_normalize_live_user_task(raw_text: str) -> str:
    text = str(raw_text or '')
    text = text.replace('\r\n', '\n').replace('\r', '\n')
    text = re.sub(r'\s+([?.!,;])', r'\1', text)
    text = re.sub(r'[«»“”"]', '', text).strip()
    prefix_patterns = (
        r'^\s*(?:пожалуйста,?\s*)?(?:реши(?:те)?|помоги(?:те)?\s+решить)\s+(?:задачу|пример|задание|уравнение)\s*[:.!?\-–—]*\s*',
        r'^\s*(?:пожалуйста,?\s*)?(?:реши(?:те)?|помоги(?:те)?\s+решить)\s*[:.!?\-–—]+\s*',
        r'^\s*(?:найди(?:те)?\s+ответ|ответь(?:те)?(?:\s+кратко)?)\s*[:.!?\-–—]+\s*',
        r'^\s*математика\s*,?\s*\d\s*класс\s*[.:\-–—]?\s*',
        r'^\s*(?:задача|задание|пример|уравнение)\s*(?:№\s*)?\d+\s*[.)\]:;\-–—]*\s*',
        r'^\s*№\s*\d+\s*[.)\]:;\-–—]*\s*',
    )
    for _ in range(4):
        before = text
        for pattern in prefix_patterns:
            text = re.sub(pattern, '', text, count=1, flags=re.IGNORECASE)
        text = text.strip()
        if text == before:
            break
    text = re.sub(
        r'\s*(?:ответ\s+(?:запиши(?:те)?|напиши(?:те)?)\s+числом|запиши(?:те)?\s+ответ\s+числом|напиши(?:те)?\s+ответ\s+числом)\s*[.!?]*\s*$',
        '', text, count=1, flags=re.IGNORECASE,
    ).strip()
    text = re.sub(r'\s+', ' ', text).strip()
    if text and not re.search(r'[.!?]\s*$', text):
        tail = re.split(r'[.!?]\s*', text.lower().replace('ё', 'е'))[-1]
        question_cues = (
            'сколько', 'какой', 'какая', 'какое', 'какие', 'каким', 'какую',
            'на сколько', 'во сколько', 'с какой', 'чему равн', 'что получится',
            'какой результат', 'какое расстояние', 'какая скорость', 'скольких',
        )
        text += '?' if any(cue in tail for cue in question_cues) else '.'
    return text


def build_open_source_curriculum_explanation(raw_text: str) -> Optional[str]:
    cleaned = _v253_normalize_live_user_task(raw_text)
    return _PRE_V253_LIVE_INPUT_NORMALIZATION_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION(cleaned)

# --- v253 release hardening patch: preserve division-colon spacing ---
# Reapply the live-input normalization without treating ':' as terminal
# punctuation, because grade-school division often uses spaced colon notation.
_PRE_V253_COLON_SAFE_INPUT_NORMALIZATION_BASE = _PRE_V253_LIVE_INPUT_NORMALIZATION_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION


def _v253_normalize_live_user_task_colon_safe(raw_text: str) -> str:
    text = str(raw_text or '')
    text = text.replace('\r\n', '\n').replace('\r', '\n')
    text = re.sub(r'\s+([?.!,;])', r'\1', text)
    text = re.sub(r'[«»“”"]', '', text).strip()
    prefix_patterns = (
        r'^\s*(?:пожалуйста,?\s*)?(?:реши(?:те)?|помоги(?:те)?\s+решить)\s+(?:задачу|пример|задание|уравнение)\s*[:.!?\-–—]*\s*',
        r'^\s*(?:пожалуйста,?\s*)?(?:реши(?:те)?|помоги(?:те)?\s+решить)\s*[:.!?\-–—]+\s*',
        r'^\s*(?:найди(?:те)?\s+ответ|ответь(?:те)?(?:\s+кратко)?)\s*[:.!?\-–—]+\s*',
        r'^\s*математика\s*,?\s*\d\s*класс\s*[.:\-–—]?\s*',
        r'^\s*(?:задача|задание|пример|уравнение)\s*(?:№\s*)?\d+\s*[.)\]:;\-–—]*\s*',
        r'^\s*№\s*\d+\s*[.)\]:;\-–—]*\s*',
    )
    for _ in range(4):
        before = text
        for pattern in prefix_patterns:
            text = re.sub(pattern, '', text, count=1, flags=re.IGNORECASE)
        text = text.strip()
        if text == before:
            break
    text = re.sub(
        r'\s*(?:ответ\s+(?:запиши(?:те)?|напиши(?:те)?)\s+числом|запиши(?:те)?\s+ответ\s+числом|напиши(?:те)?\s+ответ\s+числом)\s*[.!?]*\s*$',
        '', text, count=1, flags=re.IGNORECASE,
    ).strip()
    text = re.sub(r'[ \t\f\v]+', ' ', text).strip()
    if text and not re.search(r'[.!?]\s*$', text):
        tail = re.split(r'[.!?]\s*', text.lower().replace('ё', 'е'))[-1]
        question_cues = (
            'сколько', 'какой', 'какая', 'какое', 'какие', 'каким', 'какую',
            'на сколько', 'во сколько', 'с какой', 'чему равн', 'что получится',
            'какой результат', 'какое расстояние', 'какая скорость', 'скольких',
        )
        text += '?' if any(cue in tail for cue in question_cues) else '.'
    return text


def build_open_source_curriculum_explanation(raw_text: str) -> Optional[str]:
    cleaned = _v253_normalize_live_user_task_colon_safe(raw_text)
    return _PRE_V253_COLON_SAFE_INPUT_NORMALIZATION_BASE(cleaned)

# --- v253b: math/unit notation normalization extension ---
_PRE_V253B_NOTATION_NORMALIZATION_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION = build_open_source_curriculum_explanation


def _v253b_has_notation_noise(raw_text: str) -> bool:
    text = str(raw_text or '')
    return bool(re.search(r'[×·хХ]|\.\.|\b(?:руб|коп|см|дм|кг|г)\.|\d{1,2}\s+:\s+\d{2}|выражение\s+:', text, flags=re.IGNORECASE))


def _v253b_base_notation_normalize(raw_text: str) -> str:
    text = str(raw_text or '')
    text = re.sub(r'\.{2,}', '.', text)
    text = text.replace('×', '*').replace('·', '*')
    text = re.sub(r'(?<![A-Za-zА-Яа-яЁё])х(?![A-Za-zА-Яа-яЁё])', 'x', text, flags=re.IGNORECASE)
    text = re.sub(r'\b(\d{1,2})\s+:\s+(\d{2})\b', r'\1:\2', text)
    text = re.sub(r'(?i)(выражение)\s+:\s+', r'\1: ', text)
    return text


def _v253b_unit_variant(text: str) -> str:
    candidate = re.sub(r'\.{2,}', '.', text)
    if re.search(r'\bкоп\.', candidate, flags=re.IGNORECASE) or re.search(r'\bруб\.\s+\d+\s+коп', candidate, flags=re.IGNORECASE):
        candidate = re.sub(r'\b(руб|коп)\.(?=\s|,|$)', r'\1', candidate, flags=re.IGNORECASE)
    candidate = re.sub(r'\b(кг|г)\.(?=\s+(?:\d|сколько|в|на|и|,|$))', r'\1', candidate, flags=re.IGNORECASE)
    candidate = re.sub(r'\bсм\.(?=\s+(?:и|не|сколько|на|в)|,)', 'см', candidate, flags=re.IGNORECASE)
    candidate = re.sub(r'\bдм\.(?=\s+\d)', 'дм', candidate, flags=re.IGNORECASE)
    return candidate


def _v253b_aggressive_unit_variant(text: str) -> str:
    return re.sub(r'\b(руб|коп|см|дм|кг|г)\.(?=\s|,|$)', r'\1', re.sub(r'\.{2,}', '.', text), flags=re.IGNORECASE)


def _v253b_candidates(raw_text: str) -> list[str]:
    base = _v253b_base_notation_normalize(raw_text)
    vals = [base, _v253b_unit_variant(base), _v253b_aggressive_unit_variant(base), str(raw_text or '')]
    out = []
    for item in vals:
        if item not in out:
            out.append(item)
    return out


def _v253b_broad_misfire(result: str) -> bool:
    lower = str(result or '').lower()
    return ('сначала находим норму на одну группу' in lower) or bool(re.search(r'ответ:\s*0\.\d+', lower))


def build_open_source_curriculum_explanation(raw_text: str) -> Optional[str]:
    if not _v253b_has_notation_noise(raw_text):
        return _PRE_V253B_NOTATION_NORMALIZATION_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION(raw_text)
    first_result: Optional[str] = None
    for candidate in _v253b_candidates(raw_text):
        result = _PRE_V253B_NOTATION_NORMALIZATION_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION(candidate)
        if not result:
            continue
        if first_result is None:
            first_result = result
        if not _v253b_broad_misfire(result):
            return result
    return first_result

# --- v253 release hardening patch: do not strip unit-fraction prefixes ---
# A leading "3-я часть" is a mathematical phrase, not a task label.  Keep
# bare number+hyphen tokens while still stripping labels like "Задание 3.".
_PRE_V253_FINAL_LIVE_INPUT_BASE = _PRE_V253_COLON_SAFE_INPUT_NORMALIZATION_BASE


def _v253_normalize_live_user_task_final(raw_text: str) -> str:
    text = str(raw_text or '')
    text = text.replace('\r\n', '\n').replace('\r', '\n')
    text = re.sub(r'\s+([?.!,;])', r'\1', text)
