# --- v255g release-hardening: dictated check-expression difference guard ---
_PRE_V255G_CHECK_EXPRESSION_DIFFERENCE_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION = build_open_source_curriculum_explanation


def _v255g_check_expression_difference_payload(raw_text: str) -> Optional[str]:
    text = _v255d_voice_candidate(raw_text)
    m = re.search(
        r'ученик\s+вычислил\s*([0-9+\-*/:().\s]+?)\s+и\s+получил\s+(-?\d+)\b.*?на\s+сколько\s+отлича\w*\s+результат\s+ученика\s+от\s+верн',
        text,
        flags=re.IGNORECASE,
    )
    if not m:
        return None
    expr, student = m.group(1), int(m.group(2))
    value = _safe_eval_primary_arithmetic(expr)
    if value is None or getattr(value, 'denominator', 1) != 1:
        return None
    diff = abs(int(value) - student)
    return _zad3_v215_ans(raw_text, diff, 'v255 generalized spoken check-expression difference guard')


def build_open_source_curriculum_explanation(raw_text: str) -> Optional[str]:
    checked = _v255g_check_expression_difference_payload(raw_text)
