# --- v255i release-hardening: dictated unknown comparison guard ---
_PRE_V255I_UNKNOWN_COMPARISON_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION = build_open_source_curriculum_explanation


def _v255i_unknown_comparison_payload(raw_text: str) -> Optional[str]:
    text = _v255d_voice_candidate(raw_text)
    m = re.search(r'число\s+(-?\d+)\s+на\s+(\d+)\s+(меньше|больше)\s+неизвестн\w*.*?чему\s+равн\w*\s+неизвестн', text, flags=re.IGNORECASE)
    if m:
        value, diff, relation = int(m.group(1)), int(m.group(2)), m.group(3).lower()
        answer = value + diff if relation.startswith('меньше') else value - diff
        return _zad3_v215_ans(raw_text, answer, 'v255 generalized unknown comparison guard')
    m = re.search(r'неизвестн\w*\s+число\s+на\s+(\d+)\s+(меньше|больше)\s+числа\s+(-?\d+).*?чему\s+равн\w*\s+неизвестн', text, flags=re.IGNORECASE)
    if m:
        diff, relation, value = int(m.group(1)), m.group(2).lower(), int(m.group(3))
        answer = value - diff if relation.startswith('меньше') else value + diff
        return _zad3_v215_ans(raw_text, answer, 'v255 generalized unknown comparison guard')
    return None


def build_open_source_curriculum_explanation(raw_text: str) -> Optional[str]:
    unknown_cmp = _v255i_unknown_comparison_payload(raw_text)
    if unknown_cmp:
        return unknown_cmp
    return _PRE_V255I_UNKNOWN_COMPARISON_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION(raw_text)


