_PRE_V255K_PLACE_VALUE_COMPOSE_BUILD_OPEN_SOURCE_CURRICULUM_EXPLANATION = build_open_source_curriculum_explanation


def _v255k_place_value_compose_payload(raw_text: str) -> Optional[str]:
    text = _v255d_voice_candidate(raw_text)
    m = re.search(
        r'составь\s+число\s+из\s+(\d+)\s*(?:тысяч\w*)?\s*,?\s*(\d+)\s+сот\w*\s*,?\s*(\d+)\s+десят\w*\s+и\s+(\d+)\s+единиц\w*\s*,?\s*затем\s+прибавь\s+(\d+)',
        text,
        flags=re.IGNORECASE,
    )
    if not m:
        return None
    thousands_raw, hundreds, tens, ones, add = map(int, m.groups())
    thousands_value = thousands_raw if thousands_raw >= 1000 else thousands_raw * 1000
    answer = thousands_value + hundreds * 100 + tens * 10 + ones + add
    return _zad3_v215_ans(raw_text, answer, 'v255 generalized dictated place-value composition guard')


