    m = re.search(r'(?P<thing>занятие|урок|тренировка|экскурсия)\s+начал[ао]сь\s+в\s+(?P<h1>\d{1,2})[:ч](?P<m1>\d{2})\s+и\s+закончил[ао]сь\s+в\s+(?P<h2>\d{1,2})[:ч](?P<m2>\d{2}).{0,80}?сколько\s+минут\s+длил[ао]сь\s+(?P=thing)', lower)
